-- Poems batch 22
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('4ee9fe31-acd1-4464-95b0-d5acf9de17b9','不出','白居易','唐','唐诗','tang','','[]','簷前新葉覆殘花，席上餘桮對早茶。',32,'全唐诗/poet.tang.23000.json','["簷前新葉覆殘花，席上餘桮對早茶。", "好是老身銷日處，誰能騎馬傍人家。"]'),
('94e24f31-18de-49fa-97f1-cb5cdc0560e9','惜落花','白居易','唐','唐诗','tang','','[]','夜來風雨急，無復舊花林。',48,'全唐诗/poet.tang.23000.json','["夜來風雨急，無復舊花林。", "枝上三分落，園中二寸深。", "日斜啼鳥思，春盡老人心。", "莫怪添桮飲，情多酒不禁。"]'),
('545723e9-3bab-484c-a54c-70a95c51b8a3','老病','白居易','唐','唐诗','tang','','[]','晝聽笙歌夜醉眠，若非月下即花前。',32,'全唐诗/poet.tang.23000.json','["晝聽笙歌夜醉眠，若非月下即花前。", "如今老病須知分，不負春來二十年。"]'),
('1544581f-5ec2-41b8-af81-83ddfe3b1f8d','憶晦叔','白居易','唐','唐诗','tang','','[]','遊山弄水攜詩卷，看月尋花把酒桮。',32,'全唐诗/poet.tang.23000.json','["遊山弄水攜詩卷，看月尋花把酒桮。", "六事盡思君作伴，幾時歸到洛陽來。"]'),
('6d0a663a-582a-44c5-8389-b1471d377b3c','送徐州高僕射赴鎮','白居易','唐','唐诗','tang','','[]','大紅斾引碧幢旌，新拜將軍指點行。',64,'全唐诗/poet.tang.23000.json','["大紅斾引碧幢旌，新拜將軍指點行。", "戰將易求何足貴，書生難得始堪榮。", "離筵歌舞花叢散，候騎刀槍雪隊迎。", "應笑蹉跎白頭尹，風塵唯管洛陽城。"]'),
('f3b33dd6-2b36-45ae-9938-268229e7ead2','琴酒','白居易','唐','唐诗','tang','','[]','耳根得聽琴初暢，心地忘機酒半酣。',32,'全唐诗/poet.tang.23000.json','["耳根得聽琴初暢，心地忘機酒半酣。", "若使啓期兼解醉，應言四樂不言三。"]'),
('a985da00-109a-4637-9572-d9586e4ab8e8','聽幽蘭','白居易','唐','唐诗','tang','','[]','琴中古曲是幽蘭，爲我慇懃更弄看。',32,'全唐诗/poet.tang.23000.json','["琴中古曲是幽蘭，爲我慇懃更弄看。", "欲得身心俱靜好，自彈不及聽人彈。"]'),
('44a5dc80-55aa-4d6b-9c62-25fea11a1dc9','六年秋重題白蓮','白居易','唐','唐诗','tang','','[]','素房含露玉冠鮮，紺葉搖風鈿扇圓。',64,'全唐诗/poet.tang.23000.json','["素房含露玉冠鮮，紺葉搖風鈿扇圓。", "本是吳州供進藕，今爲伊水寄生蓮。", "移根到此三千里，結子經今六七年。", "不獨池中花故舊，兼乘舊日採花船。"]'),
('9279ca45-262c-4d33-bb5c-894d1e394a23','元相公挽歌詞三首 一','白居易','唐','唐诗','tang','','[]','銘旌官重威儀盛，騎吹聲繁鹵簿長。',32,'全唐诗/poet.tang.23000.json','["銘旌官重威儀盛，騎吹聲繁鹵簿長。", "後魏帝孫唐宰相，六年七月葬咸陽。"]'),
('3aeae636-0c10-4f56-bfde-7117b3aeb972','元相公挽歌詞三首 二','白居易','唐','唐诗','tang','','[]','墓門已閉笳簫去，唯有夫人哭不休。',32,'全唐诗/poet.tang.23000.json','["墓門已閉笳簫去，唯有夫人哭不休。", "蒼蒼露草咸陽壠，此是千秋第一秋。"]'),
('7671d638-703a-41d4-b478-4fa8fdac62b1','元相公挽歌詞三首 三','白居易','唐','唐诗','tang','','[]','送葬萬人皆慘澹，反虞駟馬亦悲鳴。',32,'全唐诗/poet.tang.23000.json','["送葬萬人皆慘澹，反虞駟馬亦悲鳴。", "琴書劒珮誰收拾，三歲遺孤新學行。"]'),
('5b8a84ee-47b7-4e37-a47c-2ea383d69a99','臥聽法曲霓裳','白居易','唐','唐诗','tang','','[]','金磬玉笙調已久，牙牀角枕睡常遲。',64,'全唐诗/poet.tang.23000.json','["金磬玉笙調已久，牙牀角枕睡常遲。", "朦朧閑夢初成後，宛轉柔聲入破時。", "樂可理心應不謬，酒能陶性信無疑。", "起嘗殘酌聽餘曲，斜背銀缸半下帷。"]'),
('2df82fbf-916d-437d-9c85-e00951cc349d','結之','白居易','唐','唐诗','tang','','[]','歡愛今何在，悲啼亦是空。',24,'全唐诗/poet.tang.23000.json','["歡愛今何在，悲啼亦是空。", "同爲一夜夢，共過十年中。"]'),
('91e64ba6-5d47-42f8-9deb-7a63a68a0425','五鳳樓晚望','白居易','唐','唐诗','tang','','[]','晴陽晚照濕煙銷，五鳳樓高天泬寥。',64,'全唐诗/poet.tang.23000.json','["晴陽晚照濕煙銷，五鳳樓高天泬寥。", "野綠全經朝雨洗，林紅半被暮雲燒。", "龍門翠黛眉相對，伊水黃金線一條。", "自入秋來風景好，就中最好是今朝。"]'),
('300dcb91-a371-4441-87dd-e60a6efd877a','寄劉蘇州','白居易','唐','唐诗','tang','','[]','去年八月哭微之，今年八月哭敦詩。',64,'全唐诗/poet.tang.23000.json','["去年八月哭微之，今年八月哭敦詩。", "何堪老淚交流日，多是秋風搖落時。", "泣罷幾迴深自念，情來一倍苦相思。", "同年同病同心事，除却蘇州更是誰。"]'),
('1a16eb0f-af60-4dd0-8823-b71ae52c6c18','送客','白居易','唐','唐诗','tang','','[]','病上籃輿相送來，衰容秋思兩悠哉。',32,'全唐诗/poet.tang.23000.json','["病上籃輿相送來，衰容秋思兩悠哉。", "涼風褭褭吹槐子，却請行人勸一桮。"]'),
('0aa0a689-f740-4d41-b2a5-7b488711796f','秋思','白居易','唐','唐诗','tang','','[]','夕照紅於燒，晴空碧勝藍。',48,'全唐诗/poet.tang.23000.json','["夕照紅於燒，晴空碧勝藍。", "獸形雲不一，弓勢月初三。", "雁思來天北，砧愁滿水南。", "蕭條秋氣味，未老已深諳。"]'),
('da5d0377-2e65-4451-b965-1e63dca82383','酬夢得秋夕不寐見寄','白居易','唐','唐诗','tang','','[]','碧簟絳紗帳，夜涼風景清。',48,'全唐诗/poet.tang.23000.json','["碧簟絳紗帳，夜涼風景清。", "病聞和藥氣，渴聽碾茶聲。", "露竹偷燈影，煙松護月明。", "何言千里隔，秋思一時生。"]'),
('4ab72d60-7944-4ef1-b6a9-328c896251c6','題周家歌者','白居易','唐','唐诗','tang','','[]','清緊如敲玉，深圓似轉簧。',24,'全唐诗/poet.tang.23000.json','["清緊如敲玉，深圓似轉簧。", "一聲腸一斷，能有幾多腸。"]'),
('c9e483fd-a0d3-49be-976e-27faad14176b','憶夢得','白居易','唐','唐诗','tang','','[]','齒髮各蹉跎，疎慵與病和。',48,'全唐诗/poet.tang.23000.json','["齒髮各蹉跎，疎慵與病和。", "愛花心在否，見酒興如何。", "年長風情少，官高俗慮多。", "幾時紅燭下，聞唱竹枝歌。"]'),
('da56c3f9-586e-431d-9d4b-28303d311a96','贈同座','白居易','唐','唐诗','tang','','[]','春黛雙蛾嫩，秋蓬兩鬢侵。',48,'全唐诗/poet.tang.23000.json','["春黛雙蛾嫩，秋蓬兩鬢侵。", "謀歡身太晚，恨老意彌深。", "薄解燈前舞，尤能酒後吟。", "花叢便不入，猶自未甘心。"]'),
('b08d742c-7d0a-4d94-96d5-f48dde14bd55','失婢','白居易','唐','唐诗','tang','','[]','宅院小牆庳，坊門帖牓遲。',48,'全唐诗/poet.tang.23000.json','["宅院小牆庳，坊門帖牓遲。", "舊恩慚自薄，前事悔難追。", "籠鳥無常主，風花不戀枝。", "今宵在何處，唯有月明知。"]'),
('1acea810-d596-43a5-9ecd-9bce21934e6e','夜招晦叔','白居易','唐','唐诗','tang','','[]','庭草留霜池結冰，黃昏鐘絕凍雲凝。',64,'全唐诗/poet.tang.23000.json','["庭草留霜池結冰，黃昏鐘絕凍雲凝。", "碧氈帳上正飄雪，紅火爐前初炷燈。", "高調秦箏一兩弄，小花蠻榼二三升。", "爲君更奏湘神曲，夜就儂來能不能。"]'),
('31d1a842-3ff2-467c-9c3c-7976abc05124','戲答皇甫監','白居易','唐','唐诗','tang','','[]','寒宵勸酒君須飲，君是孤眠七十身。',32,'全唐诗/poet.tang.23000.json','["寒宵勸酒君須飲，君是孤眠七十身。", "莫道非人身不煖，十分一醆煖於人。"]'),
('21d7f4c3-7561-4896-8b20-4e89b2a11e20','和楊師臯傷小姬英英','白居易','唐','唐诗','tang','','[]','自從嬌騃一相依，共見楊花七度飛。',64,'全唐诗/poet.tang.23000.json','["自從嬌騃一相依，共見楊花七度飛。", "玳瑁牀空收枕席，琵琶弦斷倚屏幃。", "人間有夢何曾入，泉下無家豈是歸。", "墳上少啼留取淚，明年寒食更沾衣。"]'),
('104b0aa6-35d3-41f8-9961-a66fd899631c','池邊即事','白居易','唐','唐诗','tang','','[]','氈帳胡琴出塞曲，蘭塘越櫂弄潮聲。',32,'全唐诗/poet.tang.23000.json','["氈帳胡琴出塞曲，蘭塘越櫂弄潮聲。", "何言此處同風月，薊北江南萬里情。"]'),
('15030c88-7a2f-4850-9f3d-eb1c763080c7','聞樂感鄰','白居易','唐','唐诗','tang','','[]','老去親朋零落盡，秋來弦管感傷多。',64,'全唐诗/poet.tang.23000.json','["老去親朋零落盡，秋來弦管感傷多。", "尚書宅畔悲鄰笛，廷尉門前歎雀羅。", "綠綺窗空分妓女，絳紗帳掩罷笙歌。", "歡娛未足身先去，爭奈書生薄命何。"]'),
('6d6f94fa-23b0-4451-a96f-b8a9fc66bb57','戊申歲暮詠懷三首 一','白居易','唐','唐诗','tang','','[]','窮冬月末兩三日，半百年過六七時。',64,'全唐诗/poet.tang.23000.json','["窮冬月末兩三日，半百年過六七時。", "龍尾趂朝無氣力，牛頭參道有心期。", "榮華外物終須悟，老病傍人豈得知。", "猶被妻兒教漸退，莫求致仕且分司。"]'),
('c7350629-440e-4864-80d4-2a65aa9a154f','戊申歲暮詠懷三首 二','白居易','唐','唐诗','tang','','[]','唯生一女才十二，秪欠三年未六旬。',64,'全唐诗/poet.tang.23000.json','["唯生一女才十二，秪欠三年未六旬。", "婚嫁累輕何怕老，飢寒心慣不憂貧。", "紫泥丹筆皆經手，赤紱金章盡到身。", "更擬踟躕覓何事，不歸嵩洛作閑人。"]'),
('4e01ccfa-881b-4207-828a-97b2349a7e35','戊申歲暮詠懷三首 三','白居易','唐','唐诗','tang','','[]','七年囚閉作籠禽，但願開籠便入林。',64,'全唐诗/poet.tang.23000.json','["七年囚閉作籠禽，但願開籠便入林。", "幸得展張今日翅，不能辜負昔時心。", "人間禍福愚難料，世上風波老不禁。", "萬一差池似前事，又應追悔不抽簪。"]'),
('3531e9e7-a673-42b3-bb4e-882ff7423bdb','贈夢得','白居易','唐','唐诗','tang','','[]','心中萬事不思量，坐倚屏風臥向陽。',64,'全唐诗/poet.tang.23000.json','["心中萬事不思量，坐倚屏風臥向陽。", "漸覺詠詩猶老醜，豈宜憑酒更麄狂。", "頭垂白髮我思退，脚蹋青雲君欲忙。", "只有今春相伴在，花前賸醉兩三場。"]'),
('4c73e5eb-b53c-4bc7-87c8-896fe5e91b50','想東遊五十韻','白居易','唐','唐诗','tang','','[]','海內時無事，江南歲有秋。',288,'全唐诗/poet.tang.23000.json','["海內時無事，江南歲有秋。", "生民皆樂業，地主盡賢侯。", "郊靜銷戎馬，城高逼斗牛。", "平河七百里，沃壤二三州。", "坐有湖山趣，行無風浪憂。", "食寧妨解纜，寢不廢乘流。", "泉石諳天竺，煙霞識虎丘。", "餘芳認蘭澤，遺詠思蘋洲。", "菡萏紅塗粉，菰蒲綠潑油。", "鱗差漁戶舍，綺錯稻田溝。", "紫洞藏仙窟，玄泉貯怪湫。", "精神昂老鶴，姿彩媚潛蚪。", "靜閱天工妙，閑窺物狀幽。", "投竿出比目，擲果下獼猴。", "味苦蓮心小，漿甜蔗節稠。", "橘苞從自結，藕孔是誰鎪。", "逐日移潮信，隨風變櫂謳。", "遞夫交烈火，候吏次鳴騶。", "梵塔形疑踊，閶門勢欲浮。", "客迎攜酒榼，僧待置茶甌。", "小宴閑談笑，初筵雅獻酬。", "稍催朱蠟炬，徐動碧牙籌。", "圓醆飛蓮子，長裾曳石榴。", "柘枝隨畫鼓，調笑從香毬。"]'),
('3b258b9b-2195-47d7-aff6-e0da75bbcc56','病免後喜除賓客','白居易','唐','唐诗','tang','','[]','臥在漳濱滿十旬，起爲商皓伴三人。',32,'全唐诗/poet.tang.23000.json','["臥在漳濱滿十旬，起爲商皓伴三人。", "從今且莫嫌身病，不病何由索得身。"]'),
('0461e544-0911-4944-afcd-cb7ca4f34bf7','長樂亭留別','白居易','唐','唐诗','tang','','[]','灞滻風煙函谷路，曾經幾度別長安。',64,'全唐诗/poet.tang.23000.json','["灞滻風煙函谷路，曾經幾度別長安。", "昔時蹙促爲遷客，今日從容自去官。", "優詔幸分四皓秩，祖筵慚繼二疎歡。", "塵纓世網重重縛，迴顧方知出得難。"]'),
('6b6ff052-46ae-4a57-907a-b28a10352041','陝府王大夫相迎偶贈','白居易','唐','唐诗','tang','','[]','紫微閣老自多情，白首園公豈要迎。',64,'全唐诗/poet.tang.23000.json','["紫微閣老自多情，白首園公豈要迎。", "伴我綠槐陰下歇，向君紅斾影前行。", "綸巾髮少渾欹仄，籃轝肩齊甚穩平。", "但問主人留幾日，分司賓客去無程。"]'),
('e592f003-9497-4ce0-afef-231973017049','別陝州王司馬','白居易','唐','唐诗','tang','','["\u9ec4\u6cb3"]','笙歌惆悵欲爲別，風景闌珊初過春。',32,'全唐诗/poet.tang.23000.json','["笙歌惆悵欲爲別，風景闌珊初過春。", "爭得遣君詩不苦，黃河岸上白頭人。"]'),
('d9911748-ed02-42c8-94e1-08a8968a7708','將至東都先寄令狐留守','白居易','唐','唐诗','tang','','[]','黃鳥無聲葉滿枝，閑吟想到洛城時。',64,'全唐诗/poet.tang.23000.json','["黃鳥無聲葉滿枝，閑吟想到洛城時。", "惜逢金谷三春盡，恨拜銅樓一月遲。", "詩境忽來還自得，醉鄉潛去與誰期。", "東都添箇狂賓客，先報壺觴風月知。"]'),
('da3ccf2c-9071-4540-9c06-485ee08ba64a','荅崔十八見寄','白居易','唐','唐诗','tang','','[]','明朝欲見琴尊伴，洗拭金桮拂玉徽。',64,'全唐诗/poet.tang.23000.json','["明朝欲見琴尊伴，洗拭金桮拂玉徽。", "君乞曹州刺史替，我拋刑部侍郎歸。", "倚瘡老馬收蹄立，避箭高鴻盡翅飛。", "豈料洛陽風月夜，故人垂老得相依。"]'),
('a0aa5c86-09f7-4217-a6cf-4908288e3530','贈皇甫賓客','白居易','唐','唐诗','tang','','[]','輕衣穩馬槐陰路，漸近東來漸少塵。',64,'全唐诗/poet.tang.23000.json','["輕衣穩馬槐陰路，漸近東來漸少塵。", "耳鬧久憎聞俗事，眼明初喜見閑人。", "昔曾對作承華相，今復連爲博望賓。", "始信淡交宜久遠，與君轉老轉相親。"]'),
('4d24a24c-c4c4-498f-a45b-d345a7fee8a7','歸履道宅','白居易','唐','唐诗','tang','','[]','驛吏引藤轝，家童開竹扉。',48,'全唐诗/poet.tang.23000.json','["驛吏引藤轝，家童開竹扉。", "往時多暫住，今日是長歸。", "眼下有衣食，耳邊無是非。", "不論貧與富，飲水亦應肥。"]'),
('3a3ad978-2075-452d-89cc-60ed2cecc697','問江南物','白居易','唐','唐诗','tang','','[]','歸來未及問生涯，先問江南物在耶。',64,'全唐诗/poet.tang.23000.json','["歸來未及問生涯，先問江南物在耶。", "引手摩挲青石笋，迴頭點檢白蓮花。", "蘇州舫故龍頭闇，王尹橋傾雁齒斜。", "別有夜深惆悵事，月明雙鶴在裴家。"]'),
('81329510-177f-4290-9f45-91f2e2a2bae3','蕭庶子相過','白居易','唐','唐诗','tang','','[]','半日停車馬，何人在白家。',24,'全唐诗/poet.tang.23000.json','["半日停車馬，何人在白家。", "慇懃蕭庶子，愛酒不嫌茶。"]'),
('8da06a0b-654a-4ea8-ad5f-42be99b0f4f1','荅尉遲少尹問所須','白居易','唐','唐诗','tang','','[]','乍到頻勞問所須，所須非玉亦非珠。',32,'全唐诗/poet.tang.23000.json','["乍到頻勞問所須，所須非玉亦非珠。", "愛君水閣宜閑詠，每有詩成許去無。"]'),
('129b8890-021e-4eb2-96d3-84b9ef07b83d','詠閑','白居易','唐','唐诗','tang','','[]','但有閑銷日，都無事繫懷。',48,'全唐诗/poet.tang.23000.json','["但有閑銷日，都無事繫懷。", "朝眠因客起，午飯伴僧齋。", "樹合陰交戶，池分水夾階。", "就中今夜好，風月似江淮。"]'),
('0f515370-afa3-4d8c-831e-553fbc31be5d','同崔十八寄元浙東王陝州','白居易','唐','唐诗','tang','','[]','未能同隱雲林下，且復相招祿仕間。',64,'全唐诗/poet.tang.23000.json','["未能同隱雲林下，且復相招祿仕間。", "隨月有錢勝賣藥，終年無事抵歸山。", "鏡湖水遠何由汎，棠樹枝高不易攀。", "惆悵八科殘四在，兩人榮鬧兩人閑。"]'),
('94dea6d7-8593-4d27-b958-cd7cf0c1687a','荅蘇庶子月夜聞家僮奏樂見贈','白居易','唐','唐诗','tang','','[]','牆西明月水東亭，一曲霓裳按小伶。',32,'全唐诗/poet.tang.23000.json','["牆西明月水東亭，一曲霓裳按小伶。", "不敢邀君無別意，弦生管澀未堪聽。"]'),
('6520433b-3513-4a9b-85e9-d9adaf5ed311','偶吟','白居易','唐','唐诗','tang','','[]','里巷多通水，林園盡不扃。',48,'全唐诗/poet.tang.23000.json','["里巷多通水，林園盡不扃。", "松身爲外戶，池面是中庭。", "元氏詩三帙，陳家酒一瓶。", "醉來狂發詠，鄰女暎籬聽。"]'),
('27abe2fc-5749-470b-9ba7-b371abcd7066','白蓮池汎舟','白居易','唐','唐诗','tang','','[]','白藕新花照水開，紅窗小舫信風迴。',32,'全唐诗/poet.tang.23000.json','["白藕新花照水開，紅窗小舫信風迴。", "誰教一片江南興，逐我慇懃萬里來。"]'),
('75f3c55f-6f0c-4ef8-8644-0473187aa8fa','池上即事','白居易','唐','唐诗','tang','','[]','行尋甃石引新泉，坐看修橋補釣船。',64,'全唐诗/poet.tang.23000.json','["行尋甃石引新泉，坐看修橋補釣船。", "綠竹挂衣涼處歇，清風展簟困時眠。", "身閑當貴真天爵，官散無憂即地仙。", "林下水邊無厭日，便堪終老豈論年。"]'),
('cee43204-82fd-45d5-9e52-71c9a570f265','酬裴相公見寄二絕 一','白居易','唐','唐诗','tang','','[]','習靜心方泰，勞生事漸稀。',24,'全唐诗/poet.tang.23000.json','["習靜心方泰，勞生事漸稀。", "可憐安穩地，捨此欲何歸。"]'),
('bc0f5796-8f9a-47ad-93d5-27206ae38c3a','酬裴相公見寄二絕 二','白居易','唐','唐诗','tang','','[]','一雙垂翅鶴，數首解嘲文。',24,'全唐诗/poet.tang.23000.json','["一雙垂翅鶴，數首解嘲文。", "總是迂閑物，爭堪伴相君。"]'),
('0848de11-6e78-4a69-a20d-8f503e320d31','荅夢得聞蟬見寄','白居易','唐','唐诗','tang','','[]','開緘思浩然，獨詠晚風前。',48,'全唐诗/poet.tang.23000.json','["開緘思浩然，獨詠晚風前。", "人貌非前日，蟬聲似去年。", "槐花新雨後，柳影欲秋天。", "聽罷無他計，相思又一篇。"]'),
('56ce8a48-d698-4ff1-a5d1-70dbe2c3a7c9','令狐尚書許過弊居先贈長句','白居易','唐','唐诗','tang','','[]','不矜軒冕愛林泉，許到池頭一醉眠。',64,'全唐诗/poet.tang.23000.json','["不矜軒冕愛林泉，許到池頭一醉眠。", "已遣平治行藥逕，兼教掃拂釣魚船。", "應將筆硯隨詩主，定有笙歌伴酒仙。", "祗候高情無別物，蒼苔石笋白花蓮。"]'),
('057e4259-0862-4bbf-ac19-f2e91720ce49','自題','白居易','唐','唐诗','tang','','[]','老宜官冷靜，貧賴俸優饒。',48,'全唐诗/poet.tang.23000.json','["老宜官冷靜，貧賴俸優饒。", "熱月無堆案，寒天不趂朝。", "傍看應寂寞，自覺甚逍遙。", "徒對盈尊酒，兼無愁可銷。"]'),
('0024073c-14e3-4d76-822e-b905d3b6f6d7','荅崔十八','白居易','唐','唐诗','tang','','[]','勞將白叟比黃公，今古由來事不同。',32,'全唐诗/poet.tang.23000.json','["勞將白叟比黃公，今古由來事不同。", "我有商山君未見，清泉白石在胸中。"]'),
('625fd0b6-33da-4b00-b6d6-e03c2f1ab2ac','偶詠','白居易','唐','唐诗','tang','','[]','禦熱蕉衣健，扶羸竹杖輕。',48,'全唐诗/poet.tang.23000.json','["禦熱蕉衣健，扶羸竹杖輕。", "誦經凭檻立，散藥繞廊行。", "暝槿無風落，秋蟲欲雨鳴。", "身閑當將息，病亦有心情。"]'),
('a2efcf64-19cb-4834-88d5-d2481d4e18ff','荅蘇六','白居易','唐','唐诗','tang','','[]','但喜暑隨三伏去，不知秋送二毛來。',32,'全唐诗/poet.tang.23000.json','["但喜暑隨三伏去，不知秋送二毛來。", "更無別計相寬慰，故遣陽關勸一桮。"]'),
('8bd83315-5205-4a7c-a12a-51589232880e','秋遊','白居易','唐','唐诗','tang','','[]','下馬閑行伊水頭，涼風清景勝春遊。',32,'全唐诗/poet.tang.23000.json','["下馬閑行伊水頭，涼風清景勝春遊。", "何事古今詩句裏，不多說著洛陽秋。"]'),
('0bc83f62-9ca6-426c-8086-ce2cc97b54c3','偶作','白居易','唐','唐诗','tang','','[]','張翰一桮酒，榮期三樂歌。',48,'全唐诗/poet.tang.23000.json','["張翰一桮酒，榮期三樂歌。", "聰明傷混沌，煩惱汚頭陁。", "簟冷秋生早，堦閑日上多。", "近來門更靜，無雀可張羅。"]'),
('4ab7fb31-90ad-4737-b871-48e00fcd152f','遊平原贈晦叔','白居易','唐','唐诗','tang','','[]','照水容雖老，登山力未衰。',48,'全唐诗/poet.tang.23000.json','["照水容雖老，登山力未衰。", "欲眠先命酒，暫歇亦吟詩。", "且喜身無縛，終慙鬢有絲。", "迴頭語閑伴，閑校十年遲。"]'),
('941995d2-23b6-461a-a742-151fbefda506','不出門','白居易','唐','唐诗','tang','','[]','不出門來又數旬，將何銷日與誰親。',64,'全唐诗/poet.tang.23000.json','["不出門來又數旬，將何銷日與誰親。", "鶴籠開處見君子，書卷展時逢古人。", "自靜其心延壽命，無求於物長精神。", "能行便是真修道，何必降魔調伏身。"]'),
('959e7ad3-110a-48c4-bb5c-ee40e9628914','歎鶴病','白居易','唐','唐诗','tang','','[]','右翅低垂左脛傷，可憐風貌甚昂藏。',32,'全唐诗/poet.tang.23000.json','["右翅低垂左脛傷，可憐風貌甚昂藏。", "亦知白日青天好，未要高飛且養瘡。"]'),
('1099630e-cb16-494b-a990-eef0794ae50b','臨都驛送崔十八','白居易','唐','唐诗','tang','','[]','勿言臨都五六里，扶病出城相送來。',48,'全唐诗/poet.tang.23000.json','["勿言臨都五六里，扶病出城相送來。", "莫道長安一步地，馬頭西去幾時迴。", "與君後會知何處，爲我今朝盡一桮。"]'),
('e042ea2d-0c5c-4f50-8bc3-e2eecd4549c6','對鏡','白居易','唐','唐诗','tang','','[]','三分鬢髮二分絲，曉鏡秋容相對時。',64,'全唐诗/poet.tang.23000.json','["三分鬢髮二分絲，曉鏡秋容相對時。", "去作忙官應太老，退爲閑叟未全遲。", "靜中得味何須道，穩處安身更莫疑。", "若使至今黃綺在，聞吾此語亦分司。"]'),
('170c4529-da68-4758-9dca-14a7ae904979','勸酒十四首 何處難忘酒七首 一','白居易','唐','唐诗','tang','','[]','何處難忘酒，長安喜氣新。',48,'全唐诗/poet.tang.23000.json','["何處難忘酒，長安喜氣新。", "初登高第後，乍作好官人。", "省壁明張牓，朝衣穩稱身。", "此時無一醆，爭奈帝城春。"]'),
('5675bc63-ae80-4966-8014-2d9b91b10f29','勸酒十四首 何處難忘酒七首 二','白居易','唐','唐诗','tang','','[]','何處難忘酒，天涯話舊情。',48,'全唐诗/poet.tang.23000.json','["何處難忘酒，天涯話舊情。", "青雲俱不達，白髮遞相驚。", "二十年前別，三千里外行。", "此時無一醆，何以敘平生。"]'),
('f3b74db1-b72b-4f63-a7e7-0d942b62a43c','勸酒十四首 何處難忘酒七首 三','白居易','唐','唐诗','tang','','[]','何處難忘酒，朱門羨少年。',48,'全唐诗/poet.tang.23000.json','["何處難忘酒，朱門羨少年。", "春分花發後，寒食月明前。", "小院迴羅綺，深房理管弦。", "此時無一醆，爭過豔陽天。"]'),
('126e6a7e-f649-40ef-af70-a94af44a0569','勸酒十四首 何處難忘酒七首 四','白居易','唐','唐诗','tang','','[]','何處難忘酒，霜庭老病翁。',48,'全唐诗/poet.tang.23000.json','["何處難忘酒，霜庭老病翁。", "闇聲啼蟋蟀，乾葉落梧桐。", "鬢爲愁先白，顏因醉暫紅。", "此時無一醆，何計奈秋風。"]'),
('ec2cdd28-69a2-4f37-9561-0d02ed1aca7b','勸酒十四首 何處難忘酒七首 五','白居易','唐','唐诗','tang','','[]','何處難忘酒，軍功第一高。',48,'全唐诗/poet.tang.23000.json','["何處難忘酒，軍功第一高。", "還鄉隨露布，半路授旌旄。", "玉柱剝葱手，金章爛椹袍。", "此時無一醆，何以騁雄豪。"]'),
('b27063ff-16bc-4333-847e-d5b30ace29ab','勸酒十四首 何處難忘酒七首 六','白居易','唐','唐诗','tang','','[]','何處難忘酒，青門送別多。',48,'全唐诗/poet.tang.23000.json','["何處難忘酒，青門送別多。", "歛襟收涕淚，簇馬聽笙歌。", "煙樹灞陵岸，風塵長樂坡。", "此時無一醆，爭奈去留何。"]'),
('0164b588-486c-4f96-b1c1-fe2165b2a1e2','勸酒十四首 何處難忘酒七首 七','白居易','唐','唐诗','tang','','[]','何處難忘酒，逐臣歸故園。',48,'全唐诗/poet.tang.23000.json','["何處難忘酒，逐臣歸故園。", "赦書逢驛騎，賀客出都門。", "半面瘴煙色，滿衫鄉淚痕。", "此時無一醆，何物可招魂。"]'),
('331ec948-26e6-4ad3-bf97-5aac5a8f6661','勸酒十四首 不如來飲酒七首 一','白居易','唐','唐诗','tang','','[]','莫隱深山去，君應到自嫌。',48,'全唐诗/poet.tang.23000.json','["莫隱深山去，君應到自嫌。", "齒傷朝水冷，貌苦夜霜嚴。", "漁去風生浦，樵歸雪滿巖。", "不如來飲酒，相對醉厭厭。"]'),
('430b85e6-224e-4c26-b82c-6228acda7bc4','勸酒十四首 不如來飲酒七首 二','白居易','唐','唐诗','tang','','[]','莫作農夫去，君應見自愁。',48,'全唐诗/poet.tang.23000.json','["莫作農夫去，君應見自愁。", "迎春犂瘦地，趂晚餧羸牛。", "數被官加稅，稀逢歲有秋。", "不如來飲酒，相伴醉悠悠。"]'),
('a4e70600-7be6-4037-8992-940a7773517e','勸酒十四首 不如來飲酒七首 三','白居易','唐','唐诗','tang','','[]','莫作商人去，恓惶君未諳。',48,'全唐诗/poet.tang.23000.json','["莫作商人去，恓惶君未諳。", "雪霜行塞北，風水宿江南。", "藏鏹百千萬，沈舟十二三。", "不如來飲酒，仰面醉酣酣。"]'),
('b4161c70-be10-4148-b6c0-79be92bec1c7','勸酒十四首 不如來飲酒七首 四','白居易','唐','唐诗','tang','','[]','莫事長征去，辛勤難具論。',48,'全唐诗/poet.tang.23000.json','["莫事長征去，辛勤難具論。", "何曾畫麟閣，祗是老轅門。", "蟣蝨衣中物，刀槍面上痕。", "不如來飲酒，合眼醉昏昏。"]'),
('65eaed8e-1714-42a7-93be-017eea369da0','勸酒十四首 不如來飲酒七首 五','白居易','唐','唐诗','tang','','[]','莫學長生去，仙方悞殺君。',48,'全唐诗/poet.tang.23000.json','["莫學長生去，仙方悞殺君。", "那將薤上露，擬待鶴邊雲。", "矻矻皆燒藥，纍纍盡作墳。", "不如來飲酒，閑坐醉醺醺。"]'),
('7f8f6ca8-92c4-438f-a645-3aac916af9a2','勸酒十四首 不如來飲酒七首 六','白居易','唐','唐诗','tang','','[]','莫上青雲去，青雲足愛憎。',48,'全唐诗/poet.tang.23000.json','["莫上青雲去，青雲足愛憎。", "自賢誇智慧，相糺鬬功能。", "魚爛緣吞餌，蛾燋爲撲燈。", "不如來飲酒，任性醉騰騰。"]'),
('d1d1a647-63de-4e4b-8026-bfe6bf5d8d19','勸酒十四首 不如來飲酒七首 七','白居易','唐','唐诗','tang','','[]','莫入紅塵去，令人心力勞。',48,'全唐诗/poet.tang.23000.json','["莫入紅塵去，令人心力勞。", "相爭兩蝸角，所得一牛毛。", "且滅嗔中火，休磨笑裏刀。", "不如來飲酒，穩臥醉陶陶。"]'),
('e23518e0-65d1-4890-81b1-5b557eb78555','和令狐相公寄劉郎中兼見示長句','白居易','唐','唐诗','tang','','[]','日月天衢仰面看，尚淹池鳳滯臺鸞。',64,'全唐诗/poet.tang.23000.json','["日月天衢仰面看，尚淹池鳳滯臺鸞。", "碧幢千里空移鎮，赤筆三年未轉官。", "別後縱吟終少興，病來雖飲不多歡。", "酒軍詩敵如相遇，臨老猶能一據鞍。"]'),
('b436b45f-f872-4455-b8da-3d99fd4012c6','即事','白居易','唐','唐诗','tang','','[]','見月連宵坐，聞風盡日眠。',48,'全唐诗/poet.tang.23000.json','["見月連宵坐，聞風盡日眠。", "室香羅藥氣，籠煖焙茶煙。", "鶴啄新晴地，雞棲薄暮天。", "自看淘酒米，倚杖小池前。"]'),
('abedde78-4e7b-4445-a43f-faa2f2b13bd3','期宿客不至','白居易','唐','唐诗','tang','','[]','風飄雨灑簾帷故，竹暎松遮燈火深。',32,'全唐诗/poet.tang.23000.json','["風飄雨灑簾帷故，竹暎松遮燈火深。", "宿客不來嫌冷落，一尊酒對一張琴。"]'),
('99800513-46d2-4f7c-84b2-be96f8206138','問移竹','白居易','唐','唐诗','tang','','[]','問君移竹意如何，慎勿排行但間窠。',32,'全唐诗/poet.tang.23000.json','["問君移竹意如何，慎勿排行但間窠。", "多種少栽皆有意，大都少校不如多。"]'),
('29611f25-d27c-4485-920f-d9ab1cfc8a18','重陽席上賦白菊','白居易','唐','唐诗','tang','','["\u91cd\u9633\u8282", "\u83ca\u82b1"]','滿園花菊鬱金黃，中有孤叢色似霜。',32,'全唐诗/poet.tang.23000.json','["滿園花菊鬱金黃，中有孤叢色似霜。", "還似今朝歌酒席，白頭翁入少年場。"]'),
('bcee09cf-8460-4b79-bd54-23b0c82c33eb','偶吟二首 一','白居易','唐','唐诗','tang','','[]','眼下有衣兼有食，心中無喜亦無憂。',64,'全唐诗/poet.tang.23000.json','["眼下有衣兼有食，心中無喜亦無憂。", "正如身後有何事，應向人間無所求。", "靜念道經深閉目，閑迎禪客小低頭。", "猶殘少許雲泉興，一歲龍門數度遊。"]'),
('535fef96-ff6b-44f3-b0a4-ecdef79f5331','偶吟二首 二','白居易','唐','唐诗','tang','','[]','晴教曬藥泥茶竈，閑看科松洗竹林。',64,'全唐诗/poet.tang.23000.json','["晴教曬藥泥茶竈，閑看科松洗竹林。", "活計縱貧長淨潔，池亭雖小頗幽深。", "廚香炊黍調和酒，窗暖安弦拂拭琴。", "老去生涯祗如此，更無餘事可勞心。"]'),
('7caa199c-ae4d-4abd-ac07-6b3e3e80f50e','何處春先到','白居易','唐','唐诗','tang','','[]','何處春先到，橋東水北亭。',48,'全唐诗/poet.tang.23000.json','["何處春先到，橋東水北亭。", "凍花開未得，冷酒酌難醒。", "就日移輕榻，遮風展小屏。", "不勞人勸醉，鶯語漸丁寧。"]'),
('0674f13a-ed30-4516-b15a-ee5fdd1c7b8a','勉閑遊','白居易','唐','唐诗','tang','','[]','天時人事常多故，一歲春能幾處遊。',64,'全唐诗/poet.tang.23000.json','["天時人事常多故，一歲春能幾處遊。", "不是塵埃便風雨，若非疾病即悲憂。", "貧窮心苦多無興，富貴身忙不自由。", "唯有分司官恰好，閑遊雖老未能休。"]'),
('ab89f06a-c738-43c3-aa4c-c29cda738f04','寄兩銀榼與裴侍郎因題兩絕句 一','白居易','唐','唐诗','tang','','[]','貧無好物堪爲信，雙榼雖輕意不輕。',32,'全唐诗/poet.tang.23000.json','["貧無好物堪爲信，雙榼雖輕意不輕。", "願奉謝公池上酌，丹心綠酒一時傾。"]'),
('dbe580e6-2934-4e80-8410-116c7213b174','寄兩銀榼與裴侍郎因題兩絕句 二','白居易','唐','唐诗','tang','','[]','慣和麴糵堪盛否，重用鹽梅試洗看。',32,'全唐诗/poet.tang.23000.json','["慣和麴糵堪盛否，重用鹽梅試洗看。", "小器不知容幾許，襄陽米賤酒升寬。"]'),
('9c63ccc1-2995-4dc6-a80c-1b6a1241c3e0','小橋柳','白居易','唐','唐诗','tang','','[]','細水涓涓似淚流，日西惆悵小橋頭。',32,'全唐诗/poet.tang.23000.json','["細水涓涓似淚流，日西惆悵小橋頭。", "衰楊葉盡空枝在，猶被霜風吹不休。"]'),
('f33fa93c-572e-4d82-b6b0-f18e4632982c','哭微之二首 一','白居易','唐','唐诗','tang','','[]','八月涼風吹白幕，寢門廊下哭微之。',32,'全唐诗/poet.tang.23000.json','["八月涼風吹白幕，寢門廊下哭微之。", "妻孥朋友來相弔，唯道皇天無所知。"]'),
('5643776d-56eb-4c72-ae22-49a11d1fc0e0','哭微之二首 二','白居易','唐','唐诗','tang','','[]','文章卓犖生無敵，風骨英靈歿有神。',32,'全唐诗/poet.tang.23000.json','["文章卓犖生無敵，風骨英靈歿有神。", "哭送咸陽北原上，可能隨例作灰塵。"]'),
('be1b8708-5201-48d3-a7de-9aebf9ff583b','馬上晚吟','白居易','唐','唐诗','tang','','[]','人少街荒已寂寥，風多塵起重蕭條。',64,'全唐诗/poet.tang.23000.json','["人少街荒已寂寥，風多塵起重蕭條。", "上陽落葉飄宮樹，中渡流澌擁渭橋。", "出早冒寒衣挍薄，歸遲侵黑酒全消。", "如今不是閑行日，日短天陰坊曲遙。"]'),
('6f07d66a-91a2-427a-a43d-d4940d963e7a','醉中重留夢得','白居易','唐','唐诗','tang','','[]','劉郎劉郎莫先起，蘇臺蘇臺隔雲水。',32,'全唐诗/poet.tang.23000.json','["劉郎劉郎莫先起，蘇臺蘇臺隔雲水。", "酒醆來從一百分，馬頭去便三千里。"]'),
('0427c764-1d52-46ed-babb-d641183b7c23','雪夜喜李郎中見訪兼酬所贈','白居易','唐','唐诗','tang','','[]','可憐今夜鵝毛雪，引得高情鶴氅人。',64,'全唐诗/poet.tang.23000.json','["可憐今夜鵝毛雪，引得高情鶴氅人。", "紅蠟燭前明似晝，青氈帳裏暖如春。", "十分滿醆黃金液，一尺中庭白玉塵。", "對此欲留君便宿，詩情酒分合相親。"]'),
('91d4bed5-1ea1-4a13-bded-1e035363d903','任老','白居易','唐','唐诗','tang','','[]','不愁陌上春光盡，亦任庭前日影斜。',32,'全唐诗/poet.tang.23000.json','["不愁陌上春光盡，亦任庭前日影斜。", "面黑眼昏頭雪白，老應無可更增加。"]'),
('ed1aa7ed-fe99-47af-8398-86e280de9470','勸歡','白居易','唐','唐诗','tang','','[]','火急歡娛慎勿遲，眼看老病悔難追。',32,'全唐诗/poet.tang.23000.json','["火急歡娛慎勿遲，眼看老病悔難追。", "尊前花下歌筵裏，會有求來不得時。"]'),
('17d53913-cc9a-441e-869e-b47a6c8e6664','荅王尚書問履道池舊橋','白居易','唐','唐诗','tang','','[]','虹梁雁齒隨年換，素板朱欄逐日修。',64,'全唐诗/poet.tang.23000.json','["虹梁雁齒隨年換，素板朱欄逐日修。", "但恨尚書能久別，莫忘州守不頻遊。", "重移舊柱開中眼，亂種新花擁兩頭。", "李郭小船何足問，待君乘過濟川舟。"]'),
('a57665af-c94d-4271-98d1-a9035bbbc5f4','晚歸府','白居易','唐','唐诗','tang','','[]','晚從履道來歸府，街路雖長尹不嫌。',32,'全唐诗/poet.tang.23000.json','["晚從履道來歸府，街路雖長尹不嫌。", "馬上涼於牀上坐，綠槐風透紫蕉衫。"]'),
('23358244-82d2-45a4-b12b-c6675502abb5','從龍潭寺至少林寺題贈同遊者','白居易','唐','唐诗','tang','','[]','山屐田衣六七賢，搴芳蹋翠弄潺湲。',64,'全唐诗/poet.tang.23000.json','["山屐田衣六七賢，搴芳蹋翠弄潺湲。", "九龍潭月落桮酒，三品松風飄管弦。", "強健且宜遊勝地，清涼不覺過炎天。", "始知駕鶴乘雲外，別有逍遙地上仙。"]'),
('27b49d16-df1b-4df1-8671-cd6c4bcece95','夜從法王寺下歸嶽寺','白居易','唐','唐诗','tang','','[]','雙剎夾虛空，緣雲一徑通。',48,'全唐诗/poet.tang.23000.json','["雙剎夾虛空，緣雲一徑通。", "似從忉利下，如過劒門中。", "燈火光初合，笙歌曲未終。", "可憐獅子座，舁出淨名翁。"]'),
('5cefade4-ae6e-495e-ba2b-db2a162c7544','宿龍潭寺','白居易','唐','唐诗','tang','','[]','夜上九潭誰是伴，雲隨飛蓋月隨桮。',32,'全唐诗/poet.tang.23000.json','["夜上九潭誰是伴，雲隨飛蓋月隨桮。", "明年尚作三川守，此地兼將歌舞來。"]'),
('f993a332-d674-421b-b8c5-5a7df6792ac4','嵩陽觀夜奏霓裳','白居易','唐','唐诗','tang','','[]','開元遺曲自淒涼，況近秋天調是商。',64,'全唐诗/poet.tang.23000.json','["開元遺曲自淒涼，況近秋天調是商。", "愛者誰人唯白尹，奏時何處在嵩陽。", "迴臨山月聲彌怨，散入松風韻更長。", "子晉少姨聞定怪，人間亦便有霓裳。"]'),
('fd511e6f-8ebc-499f-a9ed-1216b34b3dc5','過元家履信宅','白居易','唐','唐诗','tang','','[]','雞犬喪家分散後，林園失主寂寥時。',64,'全唐诗/poet.tang.23000.json','["雞犬喪家分散後，林園失主寂寥時。", "落花不語空辭樹，流水無情自入池。", "風蕩醼船初破漏，雨淋歌閣欲傾欹。", "前庭後院傷心事，唯是春風秋月知。"]'),
('620190f9-ce46-4ac0-979a-2926f377fb5a','和杜錄事題紅葉','白居易','唐','唐诗','tang','','[]','寒山十月旦，霜葉一時新。',48,'全唐诗/poet.tang.23000.json','["寒山十月旦，霜葉一時新。", "似燒非因火，如花不待春。", "連行排絳帳，亂落剪紅巾。", "解駐籃轝看，風前唯兩人。"]'),
('a29f76e5-7ede-43dc-a9fe-052e756be427','題崔常侍濟上別墅','白居易','唐','唐诗','tang','','[]','求榮爭寵任紛紛，脫棄金貂祗有君。',64,'全唐诗/poet.tang.23000.json','["求榮爭寵任紛紛，脫棄金貂祗有君。", "散員疏去未爲貴，小邑陶休何足云。", "山色好當晴後見，泉聲宜向醉中聞。", "主人憶爾爾知否，拋却青雲歸白雲。"]'),
('9b730d38-b7d0-48c0-a16a-a41b9c2685e8','過溫尚書舊莊','白居易','唐','唐诗','tang','','[]','白石清泉拋濟口，碧幢紅斾照河陽。',32,'全唐诗/poet.tang.23000.json','["白石清泉拋濟口，碧幢紅斾照河陽。", "邨人都不知時事，猶自呼爲處士莊。"]'),
('9b04eb77-5a74-46a5-bbf9-24a5cca7dd90','天壇峰下贈杜錄事','白居易','唐','唐诗','tang','','[]','年顏氣力漸衰殘，王屋中峰欲上難。',64,'全唐诗/poet.tang.23000.json','["年顏氣力漸衰殘，王屋中峰欲上難。", "頂上將探小有洞，喉中須嚥大還丹。", "河車九轉宜精鍊，火候三年在好看。", "他日藥成分一粒，與君先去掃天壇。"]'),
('04deb13e-52ad-4525-973a-0de929cc384c','贈僧五首 鉢塔院如大師','白居易','唐','唐诗','tang','','[]','百千萬劫菩提種，八十三年功德林。',64,'全唐诗/poet.tang.23000.json','["百千萬劫菩提種，八十三年功德林。", "若不秉持僧行苦，將何報答佛恩深。", "慈悲不瞬諸天眼，清淨無塵幾地心。", "每歲八關蒙九授，慇懃一戒重千金。"]'),
('4def9d24-051a-4e09-b119-55316b644f04','贈僧五首 神照上人','白居易','唐','唐诗','tang','','[]','心如定水隨形應，口似懸河逐病治。',32,'全唐诗/poet.tang.23000.json','["心如定水隨形應，口似懸河逐病治。", "曾向衆中先禮拜，西方去日莫相遺。"]'),
('e42689be-67b4-4431-8587-19f93f98c2af','贈僧五首 自遠禪師','白居易','唐','唐诗','tang','','[]','自出家來長自在，緣身一衲一繩牀。',32,'全唐诗/poet.tang.23000.json','["自出家來長自在，緣身一衲一繩牀。", "令人見即心無事，每一相逢是道場。"]'),
('8dd4151e-a99b-408e-9d87-a19e2667081a','贈僧五首 宗實上人','白居易','唐','唐诗','tang','','[]','榮華恩愛棄成唾，戒定真如和作香。',32,'全唐诗/poet.tang.23000.json','["榮華恩愛棄成唾，戒定真如和作香。", "今古雖殊同一法，瞿曇拋却轉輪王。"]'),
('66ec2417-f842-4c8b-a8be-84fa0f9e874f','贈僧五首 清閑上人','白居易','唐','唐诗','tang','','[]','梓潼眷屬何年別，長壽壇場近日開。',32,'全唐诗/poet.tang.23000.json','["梓潼眷屬何年別，長壽壇場近日開。", "應是蜀人皆度了，法輪移向洛中來。"]'),
('cfcc1e2a-aa1f-4ffb-a4a6-5c56897ccb2c','彈秋思','白居易','唐','唐诗','tang','','[]','信意閑彈秋思時，調清聲直韻疎遲。',32,'全唐诗/poet.tang.23000.json','["信意閑彈秋思時，調清聲直韻疎遲。", "近來漸喜無人聽，琴格高低心自知。"]'),
('dcfe87e1-db7b-482e-92d8-83dda9223c1a','自詠','白居易','唐','唐诗','tang','','[]','隨宜飲食聊充腹，取次衣裘亦煖身。',64,'全唐诗/poet.tang.23000.json','["隨宜飲食聊充腹，取次衣裘亦煖身。", "未必得年非瘦薄，無妨長福是單貧。", "老龜豈羨犧牲飽，蟠木寧爭桃李春。", "隨分自安心自斷，是非何用問閑人。"]'),
('1dd35a15-7789-487f-8fb7-8037519cbb4a','分司初到洛中偶題六韻兼戲呈馮尹','白居易','唐','唐诗','tang','','[]','相府念多病，春宮容不才。',72,'全唐诗/poet.tang.23000.json','["相府念多病，春宮容不才。", "官銜依口得，俸料逐身來。", "白首林園在，紅塵車馬迴。", "招呼新客侶，掃掠舊池臺。", "小舫宜攜樂，新荷好蓋桮。", "不知金谷主，早晚賀筵開。"]'),
('63ab766f-09f5-417f-8f36-53068bad7b47','春風','白居易','唐','唐诗','tang','','["\u6625\u5929", "\u82b1", "\u5199\u82b1"]','春風先發苑中梅，櫻杏桃梨次第開。',32,'全唐诗/poet.tang.23000.json','["春風先發苑中梅，櫻杏桃梨次第開。", "薺花榆莢深邨裏，亦道春風爲我來。"]'),
('e02d8087-7962-4f39-9529-bbe3f7a427bd','洛陽春','白居易','唐','唐诗','tang','','[]','洛陽陌上春長在，惜別今來二十年。',32,'全唐诗/poet.tang.23000.json','["洛陽陌上春長在，惜別今來二十年。", "唯覓少年心不得，其餘萬事盡依然。"]'),
('dc28335d-1c50-4b11-9ce3-9d4b0bfa90c2','恨去年','白居易','唐','唐诗','tang','','[]','老去唯耽酒，春來不著家。',24,'全唐诗/poet.tang.23000.json','["老去唯耽酒，春來不著家。", "去年來校晚，不見洛陽花。"]'),
('1dac9096-03e2-4fad-a9d5-d5247588d772','早出晚歸','白居易','唐','唐诗','tang','','[]','早起或因攜酒出，晚歸多是看花迴。',32,'全唐诗/poet.tang.23000.json','["早起或因攜酒出，晚歸多是看花迴。", "若拋風景長閑坐，自問東京作底來。"]'),
('95bf6c8f-60f1-47e0-b1d5-c0d01b9a0c21','魏王堤','白居易','唐','唐诗','tang','','["\u6625\u5929", "\u5199\u666f"]','花寒嬾發鳥慵啼，信馬閑行到日西。',32,'全唐诗/poet.tang.23000.json','["花寒嬾發鳥慵啼，信馬閑行到日西。", "何處未春先有思，柳條無力魏王堤。"]'),
('a75592c2-f753-4bf0-80fe-46d26aaa0e79','嘗黃醅新酎憶微之','白居易','唐','唐诗','tang','','[]','世間好物黃醅酒，天下閑人白侍郎。',64,'全唐诗/poet.tang.23000.json','["世間好物黃醅酒，天下閑人白侍郎。", "愛向卯時謀洽樂，亦曾酉日放粗狂。", "醉來枕麴貧如富，身後堆金有若亡。", "元九計程殊未到，甕頭一醆共誰嘗。"]'),
('adfb7769-d8cd-4a37-8cc7-6825dc6fb4db','勸行樂','白居易','唐','唐诗','tang','','[]','少年信美何曾久，春日雖遲不再中。',32,'全唐诗/poet.tang.23000.json','["少年信美何曾久，春日雖遲不再中。", "歡笑勝愁歌勝哭，請君莫道等頭空。"]'),
('41b9065d-fd8b-4ab0-b4e6-157ac997972a','老慵','白居易','唐','唐诗','tang','','[]','豈是交親向我疎，老慵自愛閉門居。',32,'全唐诗/poet.tang.23000.json','["豈是交親向我疎，老慵自愛閉門居。", "近來漸喜知聞斷，免惱嵇康索報書。"]'),
('35e48220-8b62-4a31-bc8e-6f47f48ad039','酬別微之','白居易','唐','唐诗','tang','','[]','[灃]頭峽口錢唐岸，三別都經二十年。',98,'全唐诗/poet.tang.23000.json','["[灃]頭峽口錢唐岸，三別都經二十年。", "且喜筋骸俱健在，勿嫌鬚鬢各皤然。", "君歸北闕朝天帝，我住東京作地仙。", "博望自來非棄置，承明重入莫拘牽。", "醉收桮杓停燈語，寒展衾裯對枕眠。", "猶被分司官繫絆，送君不得過甘泉。"]'),
('a37dedb1-2c20-42c5-ba34-0ce1f7115b2a','予與微之老而無子發於言歎著在詩篇今年冬各有一子戲作二什一以相賀一以自嘲 一','白居易','唐','唐诗','tang','','[]','常憂到老都無子，何況新生又是兒。',64,'全唐诗/poet.tang.23000.json','["常憂到老都無子，何況新生又是兒。", "陰德自然宜有慶，皇天可得道無知。", "一園水竹今爲主，百卷文章更付誰。", "莫慮鵷鶵無浴處，即應重入鳳皇池。"]'),
('4ef28ff3-b8c8-4b9d-8d5b-7d9688419a27','予與微之老而無子發於言歎著在詩篇今年冬各有一子戲作二什一以相賀一以自嘲 二','白居易','唐','唐诗','tang','','[]','五十八翁方有後，靜思堪喜亦堪嗟。',64,'全唐诗/poet.tang.23000.json','["五十八翁方有後，靜思堪喜亦堪嗟。", "一珠甚小還慚蚌，八子雖多不羨鴉。", "秋月晚生丹桂實，春風新長紫蘭芽。", "持桮祝願無他語，慎勿頑愚似汝爺。"]'),
('6a1ca837-d486-4601-bb34-8a7b4d8cdd5c','自問','白居易','唐','唐诗','tang','','[]','年來私自問，何故不歸京。',48,'全唐诗/poet.tang.23000.json','["年來私自問，何故不歸京。", "佩玉腰無力，看花眼不明。", "老慵難發遣，春病易滋生。", "賴有彈琴女，時時聽一聲。"]'),
('24ce74cc-5141-4312-a1f9-04686bd90c94','晚桃花','白居易','唐','唐诗','tang','','["\u548f\u7269", "\u6292\u60c5", "\u601c\u60dc", "\u548f\u7269\u8bd7", "\u6843\u82b1"]','一樹紅桃亞拂池，竹遮松蔭晚開時。',64,'全唐诗/poet.tang.23000.json','["一樹紅桃亞拂池，竹遮松蔭晚開時。", "非因斜日無由見，不是閑人豈得知。", "寒地生材遺挍易，貧家養女嫁常遲。", "春深欲落誰憐惜，白侍郎來折一枝。"]'),
('728b4fb6-68d0-489a-817d-4881ef033379','夜調琴憶崔少卿','白居易','唐','唐诗','tang','','[]','今夜調琴忽有情，欲彈惆悵憶崔卿。',32,'全唐诗/poet.tang.23000.json','["今夜調琴忽有情，欲彈惆悵憶崔卿。", "何人解愛中徽上，秋思頭邊八九聲。"]'),
('bc01555d-9800-4f45-bd7f-e25fb62876d1','阿崔','白居易','唐','唐诗','tang','','[]','謝病臥東都，羸然一老夫。',144,'全唐诗/poet.tang.23000.json','["謝病臥東都，羸然一老夫。", "孤單同伯道，遲暮過商瞿。", "豈料鬢成雪，方看掌弄珠。", "已衰寧望有，雖晚亦勝無。", "蘭入前春夢，桑懸昨日弧。", "里閭多慶賀，親戚共歡娛。", "膩剃新胎髮，香綳小繡襦。", "玉芽開手爪，酥顆點肌膚。", "弓冶將傳汝，琴書勿墜吾。", "未能知壽夭，何暇慮賢愚。", "乳氣初離殼，啼聲漸變雛。", "何時能反哺，供養白頭烏。"]'),
('94b0f3e4-5bc9-4b87-ac5c-f309cef8f759','贈鄰里往還','白居易','唐','唐诗','tang','','[]','問予何故獨安然，免被飢寒婚嫁牽。',64,'全唐诗/poet.tang.23000.json','["問予何故獨安然，免被飢寒婚嫁牽。", "骨肉都盧無十口，糧儲依約有三年。", "但能斗藪人間事，便是逍遙地上仙。", "唯恐往還相厭賤，南家飲酒北家眠。"]'),
('75562208-45df-4293-b663-acac33e31611','王子晉廟','白居易','唐','唐诗','tang','','[]','子晉廟前山月明，人聞往往夜吹笙。',32,'全唐诗/poet.tang.23000.json','["子晉廟前山月明，人聞往往夜吹笙。", "鸞吟鳳唱聽無拍，多似霓裳散序聲。"]'),
('9014fd06-8969-4fb7-8a05-d823bd668d70','晚起','白居易','唐','唐诗','tang','','[]','起晚憐春暖，歸遲愛月明。',48,'全唐诗/poet.tang.23000.json','["起晚憐春暖，歸遲愛月明。", "放慵長飽睡，聞健且閑行。", "北闕停朝簿，西方入社名。", "唯吟一句偈，無念是無生。"]'),
('9a9ce1f9-46fa-4871-83ed-007e95f1f744','酬皇甫賓客','白居易','唐','唐诗','tang','','[]','玄晏家風黃綺身，深居高臥養精神。',64,'全唐诗/poet.tang.23000.json','["玄晏家風黃綺身，深居高臥養精神。", "性慵無病常稱病，心足雖貧不道貧。", "竹院君閑銷永日，花亭我醉送殘春。", "自嫌詩酒猶多興，若比先生是俗人。"]'),
('dc1d2a40-cef1-422c-8371-011ced271c57','池上贈韋山人','白居易','唐','唐诗','tang','','[]','新竹夾平流，新荷拂小舟。',48,'全唐诗/poet.tang.23000.json','["新竹夾平流，新荷拂小舟。", "衆皆嫌好拙，誰肯伴閑遊。", "客爲忙多去，僧因飯暫留。", "獨憐韋處士，盡日共悠悠。"]'),
('02334a47-6844-426c-a42c-bd513c558e5a','無夢','白居易','唐','唐诗','tang','','[]','老眼花前闇，春衣雨後寒。',48,'全唐诗/poet.tang.23000.json','["老眼花前闇，春衣雨後寒。", "舊詩多忘却，新酒且嘗看。", "拙定於身穩，慵應趂伴難。", "漸銷名利想，無夢到長安。"]'),
('3c2c7c44-7a0a-4a09-9d88-1290404d41a2','對小潭寄遠上人','白居易','唐','唐诗','tang','','[]','小潭澄見底，閑客坐開襟。',48,'全唐诗/poet.tang.23000.json','["小潭澄見底，閑客坐開襟。", "借問不流水，何如無念心。", "彼惟清且淺，此乃寂而深。", "是義誰能荅，明朝問道林。"]'),
('a372afdb-2ab8-4ef9-8e01-11acfdb99149','閑吟二首 一','白居易','唐','唐诗','tang','','[]','留司老賓客，春盡興如何。',48,'全唐诗/poet.tang.23000.json','["留司老賓客，春盡興如何。", "官寺行香少，僧房寄宿多。", "閑傾一醆酒，醉聽兩聲歌。", "憶得陶潛語，羲皇無以過。"]'),
('8e01fe77-9a43-4823-9fdb-7a6069fd7acd','閑吟二首 二','白居易','唐','唐诗','tang','','[]','閑遊來早晚，已得一周年。',48,'全唐诗/poet.tang.23000.json','["閑遊來早晚，已得一周年。", "嵩洛供雲水，朝廷乞俸錢。", "長歌時獨酌，飽食後安眠。", "聞道山榴發，明朝向玉泉。"]'),
('cdaee7f6-98a8-4b91-9daf-348758f7dcad','獨遊玉泉寺','白居易','唐','唐诗','tang','','[]','雲樹玉泉寺，肩舁半日程。',48,'全唐诗/poet.tang.23000.json','["雲樹玉泉寺，肩舁半日程。", "更無人作伴，祗共酒同行。", "新葉千萬影，殘鶯三兩聲。", "閑遊竟未足，春盡有餘情。"]'),
('4bd37ab6-5677-49a1-9e8c-4fd4d7ec697b','晚出尋人不遇','白居易','唐','唐诗','tang','','[]','籃轝不乘乘晚涼，相尋不遇亦無妨。',32,'全唐诗/poet.tang.23000.json','["籃轝不乘乘晚涼，相尋不遇亦無妨。", "輕衣穩馬槐陰下，自要閑行一兩坊。"]'),
('9eed0454-c8dc-4d6b-89be-ce2a56a36414','苦熱','白居易','唐','唐诗','tang','','[]','頭痛汗盈巾，連宵復達晨。',48,'全唐诗/poet.tang.23000.json','["頭痛汗盈巾，連宵復達晨。", "不堪逢苦熱，猶賴是閑人。", "朝客應煩倦，農夫更苦辛。", "始慙當此日，得作自由身。"]'),
('968ae6c2-3e54-41fb-83a6-12bb479fff36','銷暑','白居易','唐','唐诗','tang','','[]','何以銷煩暑，端居一院中。',48,'全唐诗/poet.tang.23000.json','["何以銷煩暑，端居一院中。", "眼前無長物，窗下有清風。", "熱散由心靜，涼生爲室空。", "此時身自得，難更與人同。"]'),
('a37e35be-7eb2-4ee0-921c-a02055ae4251','行香歸','白居易','唐','唐诗','tang','','[]','出作行香客，歸如坐夏僧。',48,'全唐诗/poet.tang.23000.json','["出作行香客，歸如坐夏僧。", "牀前雙草屨，簷下一紗燈。", "珮委腰無力，冠欹髮不勝。", "鸞臺龍尾道，合盡少年登。"]'),
('52b01d69-c9ed-43eb-ba7a-71c0a3d60fa5','同王十七庶子李六員外鄭二侍御同年四人遊龍門有感而作','白居易','唐','唐诗','tang','','[]','一曲悲歌酒一尊，同年零落幾人存。',64,'全唐诗/poet.tang.23000.json','["一曲悲歌酒一尊，同年零落幾人存。", "世如閱水應堪歎，名是浮雲豈足論。", "各從仕祿休明代，共感平生知己恩。", "今日與君重上處，龍門不是舊龍門。"]'),
('38f98359-792c-4502-b493-1c916b62e85b','池上小宴問程秀才','白居易','唐','唐诗','tang','','[]','洛下林園好自知，江南景物闇相隨。',64,'全唐诗/poet.tang.23000.json','["洛下林園好自知，江南景物闇相隨。", "淨淘紅粒罯香飯，薄切紫鱗烹水葵。", "雨滴篷聲青雀舫，浪搖花影白蓮池。", "停杯一問蘇州客，何似吳松江上時。"]'),
('21fa156d-3f6d-49c0-9a6e-9db39f8bf166','橋亭卯飲','白居易','唐','唐诗','tang','','[]','卯時偶飲齋時臥，林下高橋橋上亭。',64,'全唐诗/poet.tang.23000.json','["卯時偶飲齋時臥，林下高橋橋上亭。", "松影過窗眠始覺，竹風吹面醉初醒。", "就荷葉上包魚鮓，當石渠中浸酒缾。", "生計悠悠身兀兀，甘從妻喚作劉伶。"]'),
('25e11040-1dc3-4a6c-936b-5ad1b0b17ace','舟中夜坐','白居易','唐','唐诗','tang','','[]','潭邊霽後多清景，橋下涼來足好風。',32,'全唐诗/poet.tang.23000.json','["潭邊霽後多清景，橋下涼來足好風。", "秋鶴一雙船一隻，夜深相伴月明中。"]'),
('2df6bde2-1979-41b9-9bc0-cae37434bfd6','戲和微之荅竇七行軍之作','白居易','唐','唐诗','tang','','[]','旌鉞從櫜鞬，賓僚禮數全。',72,'全唐诗/poet.tang.23000.json','["旌鉞從櫜鞬，賓僚禮數全。", "夔龍來要地，鵷鷺下遼天。", "赭汗騎驕馬，青娥舞醉仙。", "合成江上作，散到洛中傳。", "陋巷能無酒，貧池亦有船。", "春裝秋未寄，謾道有閑錢。"]'),
('fa6f8fd6-9461-49e6-bbbf-69094f42595f','閑忙','白居易','唐','唐诗','tang','','[]','奔走朝行內，棲遲林墅間。',48,'全唐诗/poet.tang.23000.json','["奔走朝行內，棲遲林墅間。", "多因病後退，少及健時還。", "斑白霜侵鬢，蒼黃日下山。", "閑忙俱過日，忙挍不如閑。"]'),
('e99d734c-7070-4a97-bc7b-40dd3c3fec18','西風','白居易','唐','唐诗','tang','','[]','西風來幾日，一葉已先飛。',48,'全唐诗/poet.tang.23000.json','["西風來幾日，一葉已先飛。", "新霽乘輕屐，初涼換熟衣。", "淺渠銷慢水，疎竹漏斜暉。", "薄暮青苔巷，家僮引鶴歸。"]'),
('cc51fd9a-5ede-4965-870a-f84c91e91f86','題西亭','白居易','唐','唐诗','tang','','[]','多見朱門富貴人，林園未畢即無身。',32,'全唐诗/poet.tang.23000.json','["多見朱門富貴人，林園未畢即無身。", "我今幸作西亭主，已見池塘五度春。"]'),
('d61ecb7d-60b0-4fc3-b570-c0a8189e8fa5','觀游魚','白居易','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u666f"]','繞池閑步看魚游，正值兒童弄釣舟。',32,'全唐诗/poet.tang.23000.json','["繞池閑步看魚游，正值兒童弄釣舟。", "一種愛魚心各異，我來施食爾垂鉤。"]'),
('f98b254c-9b18-4b26-9a27-e02684b086e5','看採蓮','白居易','唐','唐诗','tang','','[]','小桃閑上小蓮船，半採紅蓮半白蓮。',32,'全唐诗/poet.tang.23000.json','["小桃閑上小蓮船，半採紅蓮半白蓮。", "不似江南惡風浪，芙蓉池在臥牀前。"]'),
('0fe43c29-9ba8-4e50-9a81-1551890a8cbf','看採菱','白居易','唐','唐诗','tang','','[]','菱池如鏡淨無波，白點花稀青角多。',32,'全唐诗/poet.tang.23000.json','["菱池如鏡淨無波，白點花稀青角多。", "時唱一聲新水調，謾人道是採菱歌。"]'),
('ff38d6b1-e797-4077-a203-4893b551703a','夭老','白居易','唐','唐诗','tang','','[]','早世身如風裏燭，暮年髮似鏡中絲。',32,'全唐诗/poet.tang.23000.json','["早世身如風裏燭，暮年髮似鏡中絲。", "誰人斷得人間事，少夭堪傷老又悲。"]'),
('ea4c9d4d-e062-42b3-8316-80ebfce176aa','秋池','白居易','唐','唐诗','tang','','[]','洗浪清風透水霜，水邊閑坐一繩牀。',32,'全唐诗/poet.tang.23000.json','["洗浪清風透水霜，水邊閑坐一繩牀。", "眼塵心垢見皆盡，不是秋池是道場。"]'),
('b4c5505a-88ad-49b8-9d62-2e3632d194b3','登天宮閣','白居易','唐','唐诗','tang','','[]','午時乘興出，薄暮未能還。',48,'全唐诗/poet.tang.23000.json','["午時乘興出，薄暮未能還。", "高上煙中閣，平看雪後山。", "委形羣動裏，任性一生間。", "洛下多閑客，其中我最閑。"]'),
('2ea5b1d9-d366-4e8e-a105-5305e0ce9146','新雪二首 一','白居易','唐','唐诗','tang','','[]','不思北省煙霄地，不憶南宮風月天。',32,'全唐诗/poet.tang.23000.json','["不思北省煙霄地，不憶南宮風月天。", "唯憶靜恭楊閣老，小園新雪煖爐前。"]'),
('6746e7c3-b779-46fe-b639-023356abaa55','新雪二首 二','白居易','唐','唐诗','tang','','[]','不思朱雀街東鼓，不憶青龍寺後鐘。',32,'全唐诗/poet.tang.23000.json','["不思朱雀街東鼓，不憶青龍寺後鐘。", "唯憶夜深新雪後，新昌臺上七株松。"]'),
('2b17cdfb-d181-4937-8492-18c6526bcaf0','日高臥','白居易','唐','唐诗','tang','','[]','怕寒放嬾日高臥，臨老誰言牽率身。',64,'全唐诗/poet.tang.23000.json','["怕寒放嬾日高臥，臨老誰言牽率身。", "夾幕繞房深似洞，重裀襯枕煖於春。", "小青衣動桃根起，嫩綠醅浮竹葉新。", "未裹頭前傾一醆，何如衝雪趂朝人。"]'),
('141a584c-e120-41bd-aada-7742004a9258','和微之任校書郎日過三鄉','白居易','唐','唐诗','tang','','[]','三鄉過日君年幾，今日君年五十餘。',32,'全唐诗/poet.tang.23000.json','["三鄉過日君年幾，今日君年五十餘。", "不獨年催身亦變，校書郎變作尚書。"]'),
('9de77138-1aed-487a-91a4-d8d58c49fb60','和微之十七與君別及隴月花枝之詠','白居易','唐','唐诗','tang','','[]','別時十七今頭白，惱亂君心三十年。',32,'全唐诗/poet.tang.23000.json','["別時十七今頭白，惱亂君心三十年。", "垂老休吟花月句，恐君更結後身緣。"]'),
('0b04ebb1-cc81-4c1c-a57e-0aa2afbd2f96','和微之歎槿花','白居易','唐','唐诗','tang','','[]','朝榮殊可惜，暮落實堪嗟。',24,'全唐诗/poet.tang.23000.json','["朝榮殊可惜，暮落實堪嗟。", "若向花中比，猶應勝眼花。"]'),
('72508a9c-b467-4052-ab2b-84e0019c857f','思往喜今','白居易','唐','唐诗','tang','','[]','憶除司馬向江州，及此凡經十五秋。',64,'全唐诗/poet.tang.23000.json','["憶除司馬向江州，及此凡經十五秋。", "雖在簪裾從俗累，半尋山水是閑遊。", "謫居終帶鄉關思，領郡猶分邦國憂。", "爭似如今作賓客，都無一念到心頭。"]'),
('c206fa0c-f6f0-47b2-ae41-360791f5961d','題平泉薛家雪堆莊','白居易','唐','唐诗','tang','','[]','怪石千年應自結，靈泉一帶是誰開。',64,'全唐诗/poet.tang.23000.json','["怪石千年應自結，靈泉一帶是誰開。", "蹙爲宛轉青蛇項，噴作玲瓏白雪堆。", "赤日旱天長看雨，玄陰臘月亦聞雷。", "所嗟地去都門遠，不得肩舁每日來。"]'),
('ecde3098-58c3-422e-92b1-6d78255b5995','和微之道保生三日','白居易','唐','唐诗','tang','','[]','相看鬢似絲，始作弄璋詩。',72,'全唐诗/poet.tang.23000.json','["相看鬢似絲，始作弄璋詩。", "且有承家望，誰論得力時。", "莫興三日歎，猶勝七年遲。", "我未能忘喜，君應不合悲。", "嘉名稱道保，乞姓號崔兒。", "但恐持相竝，蒹葭瓊樹枝。"]'),
('dfe8691c-d2eb-4e25-b6ac-094d525c155c','哭皇甫七郎中','白居易','唐','唐诗','tang','','[]','志業過玄晏，詞華似禰衡。',48,'全唐诗/poet.tang.23000.json','["志業過玄晏，詞華似禰衡。", "多才非福祿，薄命是聰明。", "不得人間壽，還留身後名。", "涉江文一首，便可敵公卿。"]'),
('5cd6dd1f-bf4d-4a82-aeac-0459d9e87f95','晚起','白居易','唐','唐诗','tang','','[]','爛熳朝眠後，頻伸晚起時。',72,'全唐诗/poet.tang.23000.json','["爛熳朝眠後，頻伸晚起時。", "煖爐生火早，寒鏡裹頭遲。", "融雪煎香茗，調酥煮乳糜。", "慵饞還自哂，快活亦誰知。", "酒性溫無毒，琴聲淡不悲。", "榮公三樂外，仍弄小男兒。"]'),
('8a207a4a-2fdf-46e9-8c3d-f831b9e623fb','疑夢二首 一','白居易','唐','唐诗','tang','','[]','莫驚寵辱虛憂喜，莫計恩讐浪苦辛。',32,'全唐诗/poet.tang.23000.json','["莫驚寵辱虛憂喜，莫計恩讐浪苦辛。", "黃帝孔丘無處問，安知不是夢中身。"]'),
('cf439ecc-7724-4703-a4da-777573f02643','疑夢二首 二','白居易','唐','唐诗','tang','','[]','鹿疑鄭相終難辨，蝶化莊生詎可知。',32,'全唐诗/poet.tang.23000.json','["鹿疑鄭相終難辨，蝶化莊生詎可知。", "假使如今不是夢，能長於夢幾多時。"]'),
('919df5a8-f380-4a15-97d1-8ea586a6ee5b','夜宴惜別','白居易','唐','唐诗','tang','','[]','笙歌旖旎曲終頭，轉作離聲滿坐愁。',64,'全唐诗/poet.tang.23000.json','["笙歌旖旎曲終頭，轉作離聲滿坐愁。", "箏怨朱弦從此斷，燭啼紅淚爲誰流。", "夜長似歲歡宜盡，醉未如泥飲莫休。", "何況雞鳴即須別，門前風雨冷脩脩。"]'),
('5b898c89-82a2-46d9-acb3-2d2577552423','歸來二周歲','白居易','唐','唐诗','tang','','[]','歸來二周歲，二歲似須臾。',48,'全唐诗/poet.tang.23000.json','["歸來二周歲，二歲似須臾。", "池藕重生葉，林鴉再引雛。", "時豐實倉廩，春暖葺庖廚。", "更作三年計，三年身健無。"]'),
('05111aeb-2fcd-48fc-8d0c-a6dd4c7274b6','吾土','白居易','唐','唐诗','tang','','[]','身心安處爲吾土，豈限長安與洛陽。',64,'全唐诗/poet.tang.23000.json','["身心安處爲吾土，豈限長安與洛陽。", "水竹花前謀活計，琴詩酒裏到家鄉。", "榮先生老何妨樂，楚接輿歌未必狂。", "不用將金買莊宅，城東無主是春光。"]'),
('b3eea558-6a63-40c0-afea-19db68f28f2e','題岐王舊山池石壁','白居易','唐','唐诗','tang','','[]','樹深藤老竹迴環，石壁重重錦翠斑。',64,'全唐诗/poet.tang.23000.json','["樹深藤老竹迴環，石壁重重錦翠斑。", "俗客看來猶解愛，忙人到此亦須閑。", "況當霽景涼風後，如在千巖萬壑間。", "黃綺更歸何處去，洛陽城內有商山。"]'),
('2dd2c8a3-117a-4fdf-a8b3-db2fc107d053','病眼花','白居易','唐','唐诗','tang','','[]','頭風目眩乘衰老，祗有增加豈有瘳。',64,'全唐诗/poet.tang.23000.json','["頭風目眩乘衰老，祗有增加豈有瘳。", "花發眼中猶足怪，柳生肘上亦須休。", "大窠羅綺看纔辨，小字文書見便愁。", "必若不能分黑白，却應無悔復無尤。"]'),
('b22643fe-f413-4429-889a-46efafe7eef1','早飲醉中除河南尹敕到','白居易','唐','唐诗','tang','','[]','雪擁衡門水滿池，溫爐卯後煖寒時。',64,'全唐诗/poet.tang.23000.json','["雪擁衡門水滿池，溫爐卯後煖寒時。", "綠醅新酎嘗初醉，黃紙除書到不知。", "厚俸自來誠忝濫，老身欲起尚遲疑。", "應須了却丘中計，女嫁男婚三逕資。"]'),
('9567e00d-04aa-4e56-b3f8-d513d78578cd','除夜','白居易','唐','唐诗','tang','','[]','病眼少眠非守歲，老心多感又臨春。',32,'全唐诗/poet.tang.23000.json','["病眼少眠非守歲，老心多感又臨春。", "火銷燈盡天明後，便是平頭六十人。"]'),
('c1da54ac-493e-4957-8ed3-04312d994a5a','府西池','白居易','唐','唐诗','tang','','[]','柳無氣力枝先動，池有波紋冰盡開。',32,'全唐诗/poet.tang.23000.json','["柳無氣力枝先動，池有波紋冰盡開。", "今日不知誰計會，春風春水一時來。"]'),
('1da16782-2e2c-4d65-8d87-64203d26c2ff','天津橋','白居易','唐','唐诗','tang','','[]','津橋東北斗亭西，到此令人詩思迷。',64,'全唐诗/poet.tang.23000.json','["津橋東北斗亭西，到此令人詩思迷。", "眉月晚生神女浦，臉波春傍窈娘堤。", "柳絲褭褭風繰出，草縷茸茸雨剪齊。", "報道前驅少呼喝，恐驚黃鳥不成啼。"]'),
('448201e3-351a-4d40-a790-0da20438af6a','不准擬二首 一','白居易','唐','唐诗','tang','','[]','籃轝騰騰一老夫，褐裘烏帽白髭鬚。',48,'全唐诗/poet.tang.23000.json','["籃轝騰騰一老夫，褐裘烏帽白髭鬚。", "早衰饒病多蔬食，筋力消磨合有無。", "不准擬身年六十，上山仍未要人扶。"]'),
('d47efd92-0c2c-4867-b8e7-b5cc5aa02325','不准擬二首 二','白居易','唐','唐诗','tang','','[]','憶昔謫居炎瘴地，巴猿引哭虎隨行。',48,'全唐诗/poet.tang.23000.json','["憶昔謫居炎瘴地，巴猿引哭虎隨行。", "多於賈誼長沙苦，小挍潘安白髮生。", "不准擬身年六十，遊春猶自有心情。"]'),
('2139cfca-2633-4d25-929b-84688c377f7d','府中夜賞','白居易','唐','唐诗','tang','','[]','櫻桃廳院春偏好，石井欄堂夜更幽。',64,'全唐诗/poet.tang.23000.json','["櫻桃廳院春偏好，石井欄堂夜更幽。", "白粉牆頭花半出，緋紗燭下水平流。", "閑留賓客嘗新酒，醉領笙歌上小舟。", "舞袖飄颻櫂容與，忽疑身是夢中遊。"]'),
('93d50ae4-64bf-4302-8608-f02de262487c','府西池北新葺水齋即事招賓偶題十六韻','白居易','唐','唐诗','tang','','[]','繚繞府西面，潺湲池北頭。',192,'全唐诗/poet.tang.23000.json','["繚繞府西面，潺湲池北頭。", "鑿開明月峽，決破白蘋洲。", "清淺漪瀾急，夤緣浦嶼幽。", "直衝行徑斷，平入臥齋流。", "石疊青稜玉，波翻白片鷗。", "噴時千點雨，澄處一泓油。", "絕境應難別，同心豈易求。", "少逢人愛翫，多是我淹留。", "夾岸鋪長簟，當軒泊小舟。", "枕前看鶴浴，牀下見魚遊。", "洞戶斜開扇，疎簾半上鉤。", "紫浮萍泛泛，碧亞竹修修。", "讀罷書仍展，碁終局未收。", "午茶能散睡，卯酒善銷愁。", "簷雨晚初霽，窗風涼欲休。", "誰能伴老尹，時復一閑遊。"]'),
('aa2f2676-f244-4d86-a6f5-ead20f9410f8','哭崔兒','白居易','唐','唐诗','tang','','[]','掌珠一顆兒三歲，鬢雪千莖父六旬。',64,'全唐诗/poet.tang.23000.json','["掌珠一顆兒三歲，鬢雪千莖父六旬。", "豈料汝先爲異物，常憂吾不見成人。", "悲腸自斷非因劒，啼眼加昏不是塵。", "懷抱又空天默默，依前重作鄧攸身。"]'),
('cff2300a-74e5-4813-9775-c17364dfc883','初喪崔兒報微之晦叔','白居易','唐','唐诗','tang','','[]','書報微之晦叔知，欲題崔字淚先垂。',64,'全唐诗/poet.tang.23000.json','["書報微之晦叔知，欲題崔字淚先垂。", "世間此恨偏敦我，天下何人不哭兒。", "蟬老悲鳴拋蛻後，龍眠驚覺失珠時。", "文章十帙官三品，身後傳誰庇蔭誰。"]'),
('90fc8301-75ed-434e-8b23-db82081f55dd','府齋感懷酬夢得','白居易','唐','唐诗','tang','','[]','府伶呼喚爭先到，家醞提攜動輙隨。',64,'全唐诗/poet.tang.23000.json','["府伶呼喚爭先到，家醞提攜動輙隨。", "合是人生開眼日，自當年老歛眉時。", "丹砂鍊作三銖土，玄髮看成一把絲。", "勞寄新詩遠安慰，不聞枯樹再生枝。"]'),
('765f0774-e40c-4aca-b274-d2120353ff0f','齋居','白居易','唐','唐诗','tang','','[]','香火多相對，葷腥久不嘗。',48,'全唐诗/poet.tang.23000.json','["香火多相對，葷腥久不嘗。", "黃耆數匙粥，赤箭一甌湯。", "厚俸將何用，閑居不可忘。", "明年官滿後，擬買雪堆莊。"]'),
('37835093-80d6-4331-9591-d6813541f4f9','與諸道者同遊二室至九龍潭作','白居易','唐','唐诗','tang','','[]','喜逢二室遊仙子，厭作三川守土臣。',64,'全唐诗/poet.tang.23000.json','["喜逢二室遊仙子，厭作三川守土臣。", "舉手摩挲潭上石，開襟斗藪府中塵。", "他日終爲獨往客，今朝未是自由身。", "若言尹是嵩山主，三十六峰應笑人。"]'),
('ac24f165-9fea-4c03-9f12-bfbc8a34e769','履道池上作','白居易','唐','唐诗','tang','','[]','家池動作經旬別，松竹琴魚好在無。',64,'全唐诗/poet.tang.23000.json','["家池動作經旬別，松竹琴魚好在無。", "樹暗小巢藏巧婦，渠荒新葉長慈姑。", "不因車馬時時到，豈覺林園日日蕪。", "猶喜春深公事少，每來花下得踟躕。"]'),
('771f975f-ac98-4eac-92a6-c3e17d830004','六十拜河南尹','白居易','唐','唐诗','tang','','[]','六十河南尹，前途足可知。',72,'全唐诗/poet.tang.23000.json','["六十河南尹，前途足可知。", "老應無處避，病不與人期。", "幸遇芳菲日，猶富強健時。", "萬金何假藉，一醆莫推辭。", "流水光陰急，浮雲富貴遲。", "人間若無酒，盡合鬢成絲。"]'),
('6c8f0f7d-48ca-4579-b0aa-587acf829581','重修府西水亭院','白居易','唐','唐诗','tang','','[]','因下疏爲沼，隨高築作臺。',48,'全唐诗/poet.tang.23000.json','["因下疏爲沼，隨高築作臺。", "龍門分水入，金谷取花栽。", "繞岸行初匝，憑軒立未迴。", "園西有池位，留與後人開。"]'),
('21e7a5f3-ec94-4e05-9db0-66d160541172','與諸公同出城觀稼','白居易','唐','唐诗','tang','','[]','老尹醉醺醺，來隨年少羣。',48,'全唐诗/poet.tang.23000.json','["老尹醉醺醺，來隨年少羣。", "不憂頭似雪，但喜稼如雲。", "歲望千箱積，秋憐五穀分。", "何人知帝力，堯舜正爲君。"]'),
('01c0a4b6-2b04-4cef-9050-c5152317a032','水堂醉臥問杜三十一','白居易','唐','唐诗','tang','','[]','聞君洛下住多年，何處春流最可憐？',64,'全唐诗/poet.tang.23000.json','["聞君洛下住多年，何處春流最可憐？", "爲問魏王堤岸下，何如同德寺門前。", "無妨水色堪閑翫，不得泉聲伴醉眠。", "那似此堂簾幕底，連明連夜碧潺湲。"]'),
('daf6918e-4a73-4458-afe9-b75dcb0d1cdc','歲暮言懷','白居易','唐','唐诗','tang','','[]','職與才相背，心將口自言。',48,'全唐诗/poet.tang.23000.json','["職與才相背，心將口自言。", "磨鉛教切玉，驅鶴遣乘軒。", "只合居巖窟，何因入府門。", "年終若無替，轉恐負君恩。"]'),
('114cf065-47e3-4799-8528-28f7096ac93d','座中戲呈諸少年','白居易','唐','唐诗','tang','','[]','衰容禁得無多酒，秋鬢新添幾許霜。',64,'全唐诗/poet.tang.23000.json','["衰容禁得無多酒，秋鬢新添幾許霜。", "縱有風情應淡薄，假如老健莫誇張。", "興來吟詠從成癖，飲後酣歌少放狂。", "不爲倚官兼挾勢，因何入得少年場。"]'),
('b220732d-1241-4a3d-bebd-062783fe694c','雪後早過天津橋偶呈諸客','白居易','唐','唐诗','tang','','[]','官橋晴雪曉峩峩，老尹行吟獨一過。',64,'全唐诗/poet.tang.23000.json','["官橋晴雪曉峩峩，老尹行吟獨一過。", "紫綬相輝應不惡，白鬚同色復如何。", "悠揚短景凋年急，牢落衰情感事多。", "猶賴洛中饒醉客，時時䛏我喚笙歌。"]'),
('436e57e6-eb41-4a51-9427-f6d4cbe4058e','新製綾襖成感而有詠','白居易','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11"]','水波文襖造新成，綾軟綿勻溫復輕。',112,'全唐诗/poet.tang.23000.json','["水波文襖造新成，綾軟綿勻溫復輕。", "晨興好擁向陽坐，晚出宜披蹋雪行。", "鶴氅毳疎無實事，木棉花冷得虛名。", "宴安往往歡侵夜，臥穩昏昏睡到明。", "百姓多寒無可救，一身獨煖亦何情。", "心中爲念農桑苦，耳裏如聞飢凍聲。", "爭得大裘長萬丈，與君都蓋洛陽城。"]'),
('07c8b2cb-4eee-4d3e-a9dc-1e3c48626beb','早春雪後贈洛陽李長官長水鄭明府二同年','白居易','唐','唐诗','tang','','[]','獻歲晴和風景新，銅駞街郭暖無塵。',64,'全唐诗/poet.tang.23000.json','["獻歲晴和風景新，銅駞街郭暖無塵。", "府庭共賀三川雪，縣道分行百里春。", "朱紱洛陽官位屈，青袍長水俸錢貧。", "有何功德紆金紫，若比同年是幸人。"]'),
('e52a2c34-7aa0-40ac-aa35-deb8a2c9c1ca','醉吟','白居易','唐','唐诗','tang','','[]','醉來忘渴復忘飢，冠帶形骸杳若遺。',64,'全唐诗/poet.tang.23000.json','["醉來忘渴復忘飢，冠帶形骸杳若遺。", "耳底齋鐘初過後，心頭卯酒未消時。", "臨風朗詠從人聽，看雪閑行任馬遲。", "應被衆疑公事慢，承前府尹不吟詩。"]'),
('fa7936b3-0b78-412a-aa44-f0f116126bcd','府酒五絕 變法','白居易','唐','唐诗','tang','','[]','自慚到府來周歲，惠愛威稜一事無。',32,'全唐诗/poet.tang.23000.json','["自慚到府來周歲，惠愛威稜一事無。", "唯是改張官酒法，漸從濁水作醍醐。"]'),
('46fa7935-797f-41c6-86e2-51c7a9726642','府酒五絕 招客','白居易','唐','唐诗','tang','','[]','日午微風且暮寒，春風冷峭雪乾殘。',32,'全唐诗/poet.tang.23000.json','["日午微風且暮寒，春風冷峭雪乾殘。", "碧氈帳下紅爐畔，試爲來嘗一醆看。"]'),
('e940989b-c90d-46bd-852a-da3a0f8f3fd4','府酒五絕 辨味','白居易','唐','唐诗','tang','','[]','甘露太甜非正味，醴泉雖潔不芳馨。',32,'全唐诗/poet.tang.23000.json','["甘露太甜非正味，醴泉雖潔不芳馨。", "桮中此物何人別，柔旨之中有典刑。"]'),
('cfcdedfc-22e7-47ab-ae39-8dab5bc6753d','府酒五絕 自勸','白居易','唐','唐诗','tang','','[]','憶昔羈貧應舉年，脫衣典酒曲江邊。',32,'全唐诗/poet.tang.23000.json','["憶昔羈貧應舉年，脫衣典酒曲江邊。", "十千一斗猶賒飲，何況官供不著錢。"]'),
('e489a148-c3ca-4b64-9f6f-d26a9f69566c','府酒五絕 諭妓','白居易','唐','唐诗','tang','','[]','燭淚夜黏桃葉袖，酒痕春汚石榴裙。',32,'全唐诗/poet.tang.23000.json','["燭淚夜黏桃葉袖，酒痕春汚石榴裙。", "莫辭辛苦供歡宴，老後思量悔煞君。"]'),
('a0dc11c2-231b-49d2-b4c8-32862ad75274','晚歸早出','白居易','唐','唐诗','tang','','[]','筋力年年減，風光日日新。',72,'全唐诗/poet.tang.23000.json','["筋力年年減，風光日日新。", "退衙歸逼夜，拜表出侵晨。", "何處臺無月，誰家池不春。", "莫言無勝地，自是少閑人。", "坐厭推囚案，行嫌引馬塵。", "幾時辭府印，却作自由身。"]'),
('df3aadc2-f1ba-4fd6-b593-b1d36d657cf4','南龍興寺殘雪','白居易','唐','唐诗','tang','','[]','南龍興寺春晴後，緩步徐吟繞四廊。',64,'全唐诗/poet.tang.24000.json','["南龍興寺春晴後，緩步徐吟繞四廊。", "老趂風花應不稱，閑尋松雪正相當。", "吏人引從多乘轝，賓客逢迎少下堂。", "不擬人間更求事，些些疎嬾亦何妨。"]'),
('e92829b3-e22f-4596-b6ca-c571471d5c32','天宮閣早春','白居易','唐','唐诗','tang','','[]','天宮高閣上何頻，每上令人耳目新。',64,'全唐诗/poet.tang.24000.json','["天宮高閣上何頻，每上令人耳目新。", "前日晚登緣看雪，今朝晴望爲迎春。", "林鶯何處吟箏柱，牆柳誰家曬麴塵。", "可惜三川虛作主，風光不屬白頭人。"]'),
('05715733-83b9-44ff-b10e-122f102878a8','履道居三首 一','白居易','唐','唐诗','tang','','[]','莫嫌地窄林亭小，莫厭貧家活計微。',32,'全唐诗/poet.tang.24000.json','["莫嫌地窄林亭小，莫厭貧家活計微。", "大有高門鏁寬宅，主人到老不曾歸。"]'),
('f66a9815-7551-4bbe-a067-acf2560f0523','履道居三首 二','白居易','唐','唐诗','tang','','[]','東里素帷猶未徹，南鄰丹旐又新懸。',32,'全唐诗/poet.tang.24000.json','["東里素帷猶未徹，南鄰丹旐又新懸。", "衡門蝸舍自慙媿，收得身來已五年。"]'),
('329be486-6bde-415e-9533-bea1dc7c66bc','履道居三首 三','白居易','唐','唐诗','tang','','[]','世事平分衆所知，何嘗苦樂不相隨。',32,'全唐诗/poet.tang.24000.json','["世事平分衆所知，何嘗苦樂不相隨。", "唯餘耽酒狂歌客，只有樂時無苦時。"]'),
('cbf1b1a4-0b53-45d0-b4ce-e7014e5c0026','和夢得冬日晨興','白居易','唐','唐诗','tang','','[]','漏傳初五點，雞報第三聲。',51,'全唐诗/poet.tang.24000.json','["漏傳初五點，雞報第三聲。", "帳下從容起，窗間曨{日怱}明。", "照書燈未滅，煖酒火重生。", "理曲弦歌動，先聞唱渭城。"]'),
('77afcb19-f3d0-421d-9e4a-0c44631db095','雪夜對酒招客','白居易','唐','唐诗','tang','','[]','帳小青氈煖，桮香[綠]蟻新。',50,'全唐诗/poet.tang.24000.json','["帳小青氈煖，桮香[綠]蟻新。", "醉憐今夜月，歡憶去年人。", "闇落燈花燼，閑生草座塵。", "慇懃報弦管，明日有嘉賓。"]'),
('d88d3e8f-211f-4173-bdee-f63282139218','贈晦叔憶夢得','白居易','唐','唐诗','tang','','[]','自別崔公四五秋，因何臨老轉風流。',64,'全唐诗/poet.tang.24000.json','["自別崔公四五秋，因何臨老轉風流。", "歸來不說秦中事，歇定唯謀洛下遊。", "酒面浮花應是喜，歌眉歛黛不關愁。", "得君更有無厭意，猶恨尊前欠老劉。"]'),
('167b8471-b49f-4698-a863-a3bb5e40e0de','醉後重贈晦叔','白居易','唐','唐诗','tang','','[]','老伴知君少，歡情向我偏。',72,'全唐诗/poet.tang.24000.json','["老伴知君少，歡情向我偏。", "無論疎與數，相見輙欣然。", "各以詩成癖，俱因酒得仙。", "笑迴青眼語，醉竝白頭眠。", "豈是今投分，多疑宿結緣。", "人間更何事，攜手送衰年。"]'),
('13f9e8ff-c156-477c-88f8-967688841f5a','睡覺','白居易','唐','唐诗','tang','','[]','星河耿耿漏綿綿，月闇燈微欲曙天。',64,'全唐诗/poet.tang.24000.json','["星河耿耿漏綿綿，月闇燈微欲曙天。", "轉枕頻伸書帳下，披裘箕踞火爐前。", "老眠早覺常殘夜，病力先衰不待年。", "五欲已銷諸念息，世間無境可勾牽。"]'),
('28452f5a-2dd2-4d72-9259-8ede9a679eac','詠興五首 解印出公府','白居易','唐','唐诗','tang','','[]','解印出公府，斗藪塵土衣。',108,'全唐诗/poet.tang.24000.json','["解印出公府，斗藪塵土衣。", "百吏放爾散，雙鶴隨我歸。", "歸來履道宅，下馬入柴扉。", "馬嘶返舊櫪，鶴舞還故池。", "雞犬何忻忻，隣里亦依依。", "年顏老去日，生計勝前時。", "有帛禦冬寒，有穀防歲饑。", "飽於東方朔，樂於榮啓期。", "人生且如此，此外吾不知。"]'),
('ad7a8bd3-2015-4327-bb9b-b596a39761a9','詠興五首 出府歸吾廬','白居易','唐','唐诗','tang','','[]','出府歸吾廬，靜然安且逸。',144,'全唐诗/poet.tang.24000.json','["出府歸吾廬，靜然安且逸。", "更無客干謁，時有僧問疾。", "家僮十餘人，櫪馬三四匹。", "慵發經旬臥，興來連日出。", "出遊愛何處，嵩碧伊瑟瑟。", "況有清和天，正當疎散日。", "身閑自爲貴，何必居榮秩。", "心足即非貧，豈唯金滿室。", "吾觀權勢者，苦以身徇物。", "炙手外炎炎，履冰中慄慄。", "朝飢口忘味，夕惕心憂失。", "但有富貴名，而無富貴實。"]'),
('9e4d2669-67e1-4b83-a8b8-b73abf5c240b','詠興五首 池上有小舟','白居易','唐','唐诗','tang','','[]','池上有小舟，舟中有胡牀。',132,'全唐诗/poet.tang.24000.json','["池上有小舟，舟中有胡牀。", "牀前有新酒，獨酌還獨嘗。", "熏若春日氣，皎如秋水光。", "可洗機巧心，可蕩塵垢腸。", "岸曲舟行遲，一曲進一觴。", "未知幾曲醉，醉入無何鄉。", "寅緣潭島間，水竹深青蒼。", "身閑心無事，白日爲我長。", "我若未忘世，雖閑心亦忙。", "世若未忘我，雖退身難藏。", "我今異於是，身世交相忘。"]'),
('88b5bba7-8787-4d28-b407-9a2b825779ef','詠興五首 四月池水滿','白居易','唐','唐诗','tang','','[]','四月池水滿，龜游魚躍出。',96,'全唐诗/poet.tang.24000.json','["四月池水滿，龜游魚躍出。", "吾亦愛吾池，池邊開一室。", "人魚雖異族，其樂歸於一。", "且與爾爲徒，逍遙同過日。", "爾無羨滄海，蒲藻可委質。", "吾亦忘青雲，衡茅足容膝。", "況吾與爾輩，本非蛟龍匹。", "假如雲雨來，祗是池中物。"]'),
('877e656b-5048-482f-8eb2-d65b981889bd','詠興五首 小庭亦有月','白居易','唐','唐诗','tang','','[]','小庭亦有月，小院亦有花。',168,'全唐诗/poet.tang.24000.json','["小庭亦有月，小院亦有花。", "可憐好風景，不解嫌貧家。", "菱角執笙簧，谷兒抹琵琶。", "紅綃信手舞，紫綃隨意歌。", "邨歌與社舞，客哂主人誇。", "但問樂不樂，豈在鐘鼓多。", "客告暮將歸，主稱日未斜。", "請客稍深酌，願見朱顏酡。", "客知主意厚，分數隨口加。", "堂上燭未秉，座中冠已峩。", "左顧短紅袖，右命小青娥。", "長跪謝貴客，蓬門勞見過。", "客散有餘興，醉臥獨吟哦。", "幕天而席地，誰奈劉伶何。"]'),
('beba8b40-7d12-4c06-8fd3-ea906d3a9cfc','秋涼閑臥','白居易','唐','唐诗','tang','','[]','殘暑晝猶長，早涼秋尚嫩。',48,'全唐诗/poet.tang.24000.json','["殘暑晝猶長，早涼秋尚嫩。", "露荷散清香，風竹含疎韻。", "幽閑竟日臥，衰病無人問。", "薄暮宅門前，槐花深一寸。"]'),
('db893f49-35d4-45a2-91a3-dca2b0b03a06','酬思黯相公見過弊居戲贈','白居易','唐','唐诗','tang','','[]','軒蓋光照地，行人爲裴回。',120,'全唐诗/poet.tang.24000.json','["軒蓋光照地，行人爲裴回。", "呼傳君子出，乃是故人來。", "訪我入窮巷，引君登小臺。", "臺前多竹樹，池上無塵埃。", "貧家何所有，新酒三兩桮。", "停杯欵曲語，上馬復遲迴。", "留守不外宿，日斜宮漏催。", "但留金刀贈，未接玉山頹。", "家醞不敢惜，待君來即開。", "邨妓不辭出，恐君囅然咍。"]'),
('dc512cd4-28f4-4dc9-889f-78a62befc7b6','再授賓客分司','白居易','唐','唐诗','tang','','[]','優穩四皓官，清崇三品列。',144,'全唐诗/poet.tang.24000.json','["優穩四皓官，清崇三品列。", "伊予再塵忝，內媿非才哲。", "俸錢七八萬，給受無虛月。", "分命在東司，又不勞朝謁。", "既資閑養疾，亦賴慵藏拙。", "賓友得從容，琴觴恣怡悅。", "乘籃城外去，繫馬花前歇。", "六遊金谷春，五看龍門雪。", "吾若默無語，安知吾快活。", "吾欲更盡言，復恐人豪奪。", "應爲時所笑，苦惜分司闕。", "但問適意無，豈論官冷熱。"]'),
('f568d77f-83f7-412d-bb87-189954bfa074','把酒','白居易','唐','唐诗','tang','','[]','把酒仰問天，古今誰不死。',144,'全唐诗/poet.tang.24000.json','["把酒仰問天，古今誰不死。", "所貴未死間，少憂多歡喜。", "窮通諒在天，憂喜即由己。", "是故達道人，去彼而取此。", "勿言未富貴，久忝居祿仕。", "借問宗族間，幾人拖金紫。", "勿憂漸衰老，且喜加年紀。", "試數班行中，幾人及暮齒。", "朝飱不過飽，五鼎徒爲爾。", "夕寢止求安，一衾而已矣。", "此外皆長物，於我雲相似。", "有子不留金，何況兼無子。"]'),
('8ebc958c-7f4a-45f8-ae67-ecd19494640b','首夏','白居易','唐','唐诗','tang','','[]','林靜蚊未生，池靜蛙未鳴。',120,'全唐诗/poet.tang.24000.json','["林靜蚊未生，池靜蛙未鳴。", "景長天氣好，竟日和且清。", "春禽餘哢在，夏木新陰成。", "兀爾水邊坐，翛然橋上行。", "自問一何適，身閑官不輕。", "料錢隨月用，生計逐日營。", "食飽慙伯夷，酒足媿淵明。", "壽倍顏氏子，富百黔婁生。", "有一即爲樂，況吾四者幷。", "所以私自慰，雖老有心情。"]'),
('be1f2b7d-d935-425f-91bf-b209a9f95465','代鶴','白居易','唐','唐诗','tang','','[]','我本海上鶴，偶逢江南客。',96,'全唐诗/poet.tang.24000.json','["我本海上鶴，偶逢江南客。", "感君一顧恩，同來洛陽陌。", "洛陽寡族類，皎皎唯兩翼。", "貌是天與高，色非日浴白。", "主人誠可戀，其奈軒庭窄。", "飲啄雜雞羣，年深損標格。", "故鄉渺何處，雲水重重隔。", "誰念深籠中，七換摩天翮。"]'),
('e0ee3250-3d9c-4772-bb26-57e9e36849a8','立秋夕有懷夢得','白居易','唐','唐诗','tang','','[]','露簟荻竹清，風扇蒲葵輕。',72,'全唐诗/poet.tang.24000.json','["露簟荻竹清，風扇蒲葵輕。", "一與故人別，再見新蟬鳴。", "是夕涼飆起，閑境入幽情。", "迴燈見棲鶴，隔竹聞吹笙。", "夜茶一兩杓，秋吟三數聲。", "所思渺千里，雲外長洲城。"]'),
('e35481cb-0c73-45aa-9e5d-87c4d22a9352','哭崔常侍晦叔','白居易','唐','唐诗','tang','','[]','頑賤一拳石，精珍百鍊金。',168,'全唐诗/poet.tang.24000.json','["頑賤一拳石，精珍百鍊金。", "名價既相遠，交分何其深。", "中誠一以合，外物不能侵。", "逶迤二十年，與世同浮沈。", "晚有退閑約，白首歸雲林。", "垂老忽相失，悲哉口語心。", "春日嵩高陽，秋夜清洛陰。", "丘園共誰卜，山水共誰尋。", "風月共誰賞，詩篇共誰吟。", "花開共誰看，酒熟共誰斟。", "惠死莊杜口，鍾歿師廢琴。", "道理使之然，從古非獨今。", "吾道自此孤，我情安可任。", "唯將病眼淚，一灑秋風襟。"]'),
('818b0533-8cde-4fdb-9c52-ef4298a7cf45','新秋曉興','白居易','唐','唐诗','tang','','[]','濁暑忽已退，清宵未全長。',96,'全唐诗/poet.tang.24000.json','["濁暑忽已退，清宵未全長。", "晨釭耿殘焰，宿閤凝微香。", "喔喔雞下樹，輝輝日上梁。", "枕低茵席軟，臥穩身入牀。", "睡足景猶早，起初風乍涼。", "展張小屏幛，收拾生衣裳。", "還有惆悵事，遲遲未能忘。", "拂鏡梳白髮，可憐冰照霜。"]'),
('c212364e-7e5d-462a-b68d-6e58d6a261d8','秋日與張賓客舒著作同遊龍門醉中狂歌凡二百三十八字','白居易','唐','唐诗','tang','','[]','秋天高高秋光清，秋風褭褭秋蟲鳴。',272,'全唐诗/poet.tang.24000.json','["秋天高高秋光清，秋風褭褭秋蟲鳴。", "嵩峰餘霞錦綺卷，伊水細浪鱗甲生。", "洛陽閑客知無數，少出遊山多在城。", "商嶺老人自追逐，蓬丘逸士相逢迎。", "南出鼎門十八里，莊店邐迤橋道平。", "不寒不熱好時節，鞍馬穩快衣衫輕。", "竝轡踟躕下西岸，扣舷容與繞中汀。", "開懷曠達無所繫，觸目勝絕不可名。", "荷衰欲黃荇猶綠，魚樂自躍鷗不驚。", "翠藻蔓長孔雀尾，彩船櫓急寒雁聲。", "家醞一壺白玉液，野花數把黃金英。", "晝遊四看西日暮，夜話三及東方明。", "暫停桮觴輟吟詠，我有狂言君試聽。", "丈夫一生有二志，兼濟獨善難得幷。", "不能救療生民病，即須先濯塵土纓。", "況吾頭白眼已闇，終日戚促何所成。", "不如展眉開口笑，龍門醉臥香山行。"]'),
('36ecd311-3b50-4462-bc82-93c7878beba6','履信池櫻桃島上醉後走筆送別舒員外兼寄宗正李卿考功崔郎中','白居易','唐','唐诗','tang','','[]','櫻桃島前春，去春花萬枝。',112,'全唐诗/poet.tang.24000.json','["櫻桃島前春，去春花萬枝。", "忽憶與宗卿閑飲日，又憶與考功狂醉時。", "歲晚無花空有葉，風吹滿地乾重疊。", "蹋葉悲秋復憶春，池邊樹下重殷勤。", "今朝一酌臨寒水，此地三迴別故人。", "櫻桃花，來春千萬朵，來春共誰花下坐。", "不論崔李上青雲，明日舒三亦拋我。"]'),
('d8588f4b-f21f-4712-8c0b-d64a4bc6bc6a','秋池獨汎','白居易','唐','唐诗','tang','','[]','蕭疎秋竹籬，清淺秋風池。',72,'全唐诗/poet.tang.24000.json','["蕭疎秋竹籬，清淺秋風池。", "一隻短舫艇，一張斑鹿皮。", "皮上有野叟，手中持酒巵。", "半酣箕踞坐，自問身爲誰。", "嚴子垂釣日，蘇門長嘯時。", "悠然意自得，意外何人知。"]'),
('8fe800ce-fb7a-4165-b586-13d0f8f2632f','冬日早起閑詠','白居易','唐','唐诗','tang','','[]','水塘耀初旭，風竹飄餘霰。',72,'全唐诗/poet.tang.24000.json','["水塘耀初旭，風竹飄餘霰。", "幽境雖目前，不因閑不見。", "晨起對爐香，道經尋兩卷。", "晚坐拂琴塵，秋思彈一遍。", "此外更無事，開尊時自勸。", "何必東風來，一桮春上面。"]'),
('0117e5d5-c8db-4de8-acba-a7b3040ce44b','歲暮','白居易','唐','唐诗','tang','','[]','慘澹歲云暮，窮陰動經旬。',120,'全唐诗/poet.tang.24000.json','["慘澹歲云暮，窮陰動經旬。", "霜風裂人面，冰雪摧車輪。", "而我當是時，獨不知苦辛。", "晨炊廩有米，夕爨廚有薪。", "夾帽長覆耳，重裘寬裹身。", "加之一桮酒，煦嫗如陽春。", "洛城士與庶，比屋多飢貧。", "何處爐有火，誰家甑無塵。", "如我飽煖者，百人無一人。", "安得不慙媿，放歌聊自陳。"]'),
('0a918c50-8e39-4234-b4ec-b6b25abef385','南池早春有懷','白居易','唐','唐诗','tang','','[]','朝遊北橋上，晚憩南塘畔。',96,'全唐诗/poet.tang.24000.json','["朝遊北橋上，晚憩南塘畔。", "西日雪全銷，東風冰盡泮。", "簁簁魚尾掉，瞥瞥鵝毛換。", "泥煖草芽生，沙虛泉脉散。", "晴芳冒苔島，宿潤侵蒲岸。", "洛下日初長，江南春欲半。", "時光共拋擲，人事堪嗟歎。", "倚櫂忽尋思，去年池上伴。"]'),
('b1844a3d-fdbe-4516-9e0b-1be943cc3f95','古意','白居易','唐','唐诗','tang','','[]','脉脉復脉脉，美人千里隔。',72,'全唐诗/poet.tang.24000.json','["脉脉復脉脉，美人千里隔。", "不見來幾時，瑤草三四碧。", "玉琴聲悄悄，鸞鏡塵幂幂。", "昔爲連理枝，今作分飛翮。", "寄書多不達，加飯終無益。", "心腸不自寬，衣帶何由窄。"]'),
('abdb806a-96be-4349-9dea-9d69424790f0','山遊示小妓','白居易','唐','唐诗','tang','','[]','雙鬟垂未合，三十纔過半。',72,'全唐诗/poet.tang.24000.json','["雙鬟垂未合，三十纔過半。", "本是綺羅人，今爲山水伴。", "春泉共揮弄，好樹同攀翫。", "笑容花底迷，酒思風前亂。", "紅凝舞袖急，黛慘歌聲緩。", "莫唱楊柳枝，無腸與君斷。"]'),
('ab67a2a1-434d-4b14-bde1-cab1c3029c7a','神照禪師同宿','白居易','唐','唐诗','tang','','[]','八年三月晦，山梨花滿枝。',48,'全唐诗/poet.tang.24000.json','["八年三月晦，山梨花滿枝。", "龍門水西寺，夜與遠公期。", "晏坐自相對，密語誰得知。", "前後際斷處，一念不生時。"]'),
('f6be80d0-1ded-4705-a4e5-e07d605f5977','張常侍相訪','白居易','唐','唐诗','tang','','[]','西亭晚寂寞，鶯散柳陰繁。',48,'全唐诗/poet.tang.24000.json','["西亭晚寂寞，鶯散柳陰繁。", "水戶簾不卷，風牀席自翻。", "忽聞車馬客，來訪蓬蒿門。", "況是張常侍，安得不開尊。"]'),
('1026e962-dab6-4aa8-ba24-a97e2588716e','早夏遊宴','白居易','唐','唐诗','tang','','[]','雖慵興猶在，雖老心猶健。',72,'全唐诗/poet.tang.24000.json','["雖慵興猶在，雖老心猶健。", "昨日山水遊，今朝花酒宴。", "山榴豔似火，玉蘂飄如霰。", "榮落逐瞬遷，炎涼隨刻變。", "未收木綿褥，已動蒲葵扇。", "且喜物與人，年年得相見。"]'),
('2d54a9db-1241-4f29-a80c-983c998449ab','感白蓮花','白居易','唐','唐诗','tang','','[]','白白芙蓉花，本生吳江濆。',144,'全唐诗/poet.tang.24000.json','["白白芙蓉花，本生吳江濆。", "不與紅者雜，色類自區分。", "誰移爾至此，姑蘇白使君。", "初來苦顦顇，久乃芳氛氳。", "月月葉換葉，年年根生根。", "陳根與故葉，銷化成泥塵。", "化者日已遠，來者日復新。", "一爲池中物，永別江南春。", "忽想西涼州，中有天寶民。", "埋歿漢父祖，孳生胡子孫。", "已忘鄉土戀，豈念君親恩。", "生人尚復爾，草木何足云。"]'),
('fa149687-f77d-41b6-924e-15ad6cb964d4','詠所樂','白居易','唐','唐诗','tang','','[]','獸樂在山谷，魚樂在陂池。',180,'全唐诗/poet.tang.24000.json','["獸樂在山谷，魚樂在陂池。", "蟲樂在深草，鳥樂在高枝。", "所樂雖不同，同歸適其宜。", "不以彼易此，況論是與非。", "而我何所樂，所樂在分司。", "分司有何樂，樂哉人不知。", "官優有祿料，職散無羈縻。", "嬾與道相近，鈍將閑自隨。", "昨朝拜表迴，今晚行香歸。", "歸來北窗下，解巾脫塵衣。", "冷泉灌我頂，暖水濯四肢。", "體中幸無疾，臥任清風吹。", "心中又無事，坐任白日移。", "或開書一篇，或引酒一巵。", "但得如今日，終身無厭時。"]'),
('02f64524-4ac6-426b-b0a2-3c61f473c49e','思舊','白居易','唐','唐诗','tang','','[]','閑日一思舊，舊遊如目前。',192,'全唐诗/poet.tang.24000.json','["閑日一思舊，舊遊如目前。", "再思今何在，零落歸下泉。", "退之服硫黃，一病訖不痊。", "微之鍊秋石，未老身溘然。", "杜子得丹訣，終日斷腥羶。", "崔君誇藥力，經冬不衣綿。", "或疾或暴夭，悉不過中年。", "唯予不服食，老命反遲延。", "況在少壯時，亦爲嗜慾牽。", "但躭葷與血，不識汞與鉛。", "飢來吞熱物，渴來飲寒泉。", "詩役五藏神，酒汨三丹田。", "隨日合破壞，至今粗完全。", "齒牙未缺落，肢體尚輕便。", "已開第七秩，飽食仍安眠。", "且進桮中物，其餘皆付天。"]'),
('e4ca9f3b-5892-49fb-9c33-7adc9b11240b','寄盧少尹','白居易','唐','唐诗','tang','','[]','老誨心不亂，莊戒形太勞。',168,'全唐诗/poet.tang.24000.json','["老誨心不亂，莊戒形太勞。", "生命既能保，死籍亦可逃。", "嘉肴與旨酒，信是腐腸膏。", "豔聲與麗色，真爲伐性刀。", "補養在積功，如裘集衆毛。", "將欲致千里，可得差一毫。", "顏回何爲者，簟瓢纔自給。", "肥醲不到口，年不登三十。", "張蒼何爲者，染愛浩無際。", "妾媵填後房，竟壽百餘歲。", "蒼壽有何德，回夭有何辜。", "誰謂具聖體，不如肥瓠軀。", "遂使世俗心，多疑仙道書。", "寄問盧先生，此理當何如。"]'),
('a19971b2-76b4-4275-9b1b-ab55ac1c3e57','池上清晨候皇甫郎中','白居易','唐','唐诗','tang','','[]','曉景麗未熱，晨飆鮮且涼。',72,'全唐诗/poet.tang.24000.json','["曉景麗未熱，晨飆鮮且涼。", "池幽綠蘋合，霜潔白蓮香。", "深掃竹間逕，靜拂松下牀。", "玉柄鶴翎扇，銀甖雲母漿。", "屏除無俗物，瞻望唯清光。", "何人擬相訪，嬴女從蕭郎。"]'),
('14c1510d-2c74-4ece-b1a7-03cf5b7e85a7','詠懷','白居易','唐','唐诗','tang','','[]','我知世無幻，了無干世意。',144,'全唐诗/poet.tang.24000.json','["我知世無幻，了無干世意。", "世知我無堪，亦無責我事。", "由茲兩相忘，因得長自遂。", "自遂意何如，閑官在閑地。", "閑地唯東都，東都少名利。", "閑官是賓客，賓客無牽累。", "嵇康日日嬾，畢卓時時醉。", "酒肆夜深歸，僧房日高睡。", "形安不勞苦，神泰無憂畏。", "從官三十年，無如今氣味。", "鴻雖脫羅弋，鶴尚居祿位。", "唯此未忘懷，有時猶內媿。"]'),
('7db29278-1cf2-4870-b69c-ab1985eee7c7','北窗三友','白居易','唐','唐诗','tang','','[]','今日北窗下，自問何所爲。',204,'全唐诗/poet.tang.24000.json','["今日北窗下，自問何所爲。", "欣然得三友，三友者爲誰。", "琴罷輙舉酒，酒罷輙吟詩。", "三友遞相引，循環無已時。", "一彈愜中心，一詠暢四肢。", "猶恐中有間，以酒彌縫之。", "豈獨吾拙好，古人多若斯。", "嗜詩有淵明，嗜琴有啓期。", "嗜酒有伯倫，三人皆吾師。", "或乏儋石儲，或穿帶索衣。", "弦歌復觴詠，樂道知所歸。", "三師去已遠，高風不可追。", "三友游甚熟，無日不相隨。", "左擲白玉巵，右拂黃金徽。", "興酣不疊紙，走筆操狂詞。", "誰能持此詞，爲我謝親知。", "縱未以爲是，豈以我爲非。"]'),
('31911b6a-c2ca-4f33-a552-54825df4f32f','吟四雖','白居易','唐','唐诗','tang','','[]','酒酣後，歌歇時。',96,'全唐诗/poet.tang.24000.json','["酒酣後，歌歇時。", "請君添一酌，聽我吟四雖。", "年雖老，猶少於韋長史。", "命雖薄，猶勝於鄭長水。", "眼雖病，猶明於徐郎中。", "家雖貧，猶富於郭庶子。", "省躬審分何僥倖，值酒逢歌且歡喜。", "忘榮知足委天和，亦應得盡生生理。"]'),
('37bf0606-38ba-4d3b-895c-ecfc497508a3','裴侍中晉公以集賢林亭即事詩三十六韻見贈猥蒙徵和才拙詞繁輙廣爲五百言以伸酬獻','白居易','唐','唐诗','tang','','[]','三江路千里，五湖天一涯。',288,'全唐诗/poet.tang.24000.json','["三江路千里，五湖天一涯。", "何如集賢第，中有平津池。", "池勝主見覺，景新人未知。", "竹森翠琅玕，水深洞琉璃。", "水竹以爲質，質立而文隨。", "文之者何人，公來親指麾。", "疏鑿出人意，結構得地宜。", "靈襟一搜索，勝概無遁遺。", "因下張沼沚，依高築階基。", "嵩峰見數片，伊水分一支。", "南溪修且直，長波碧逶迤。", "北館壯復麗，倒影紅參差。", "東島號晨光，杲曜迎朝曦。", "西嶺名夕陽，杳曖留落暉。", "前有水心亭，動蕩架漣漪。", "後有開闔堂，寒溫變天時。", "幽泉鏡泓澄，怪石山欹危。", "春葩雪漠漠，夏果珠離離。", "主人命方舟，宛在水中坻。", "親賓次第至，酒樂前後施。", "解纜始登汎，山遊仍水嬉。", "沿洄無滯礙，向背窮幽奇。", "瞥過遠橋下，飄旋深澗陲。", "管弦去縹緲，羅綺來霏微。"]'),
('6c8a2a84-33f3-4bfd-b25c-2cc913d0754d','晚歸香山寺因詠所懷','白居易','唐','唐诗','tang','','[]','我年日已老，我身日已閑。',132,'全唐诗/poet.tang.24000.json','["我年日已老，我身日已閑。", "閑出都門望，但見水與山。", "關塞碧巖巖，伊流清潺潺。", "中有古精舍，軒戶無扃關。", "岸草歇可藉，逕蘿行可攀。", "朝隨浮雲出，夕與飛鳥還。", "吾道本迂拙，世途多險艱。", "嘗聞嵇呂輩，尤悔生疎頑。", "巢悟入箕潁，皓知返商巔。", "豈唯樂肥遁，聊復祛憂患。", "吾亦從此去，終老伊嵩間。"]'),
('dcdf269b-58d3-4501-acbd-821b4bde90ac','張常侍池涼夜閑讌贈諸公','白居易','唐','唐诗','tang','','[]','竹橋新月上，水岸涼風至。',84,'全唐诗/poet.tang.24000.json','["竹橋新月上，水岸涼風至。", "對月五六人，管弦三兩事。", "留連池上酌，款曲城外意。", "或嘯或謳吟，誰知此閑味。", "迴看市朝客，矻矻趨名利。", "朝忙少遊宴，夕困多眠睡。", "清涼屬吾徒，相逢勿辭醉。"]'),
('912f9d6c-f2f1-49fc-9361-2d7d4358efc3','和皇甫郎中秋曉同登天宮閣言懷六韻','白居易','唐','唐诗','tang','','[]','碧天忽已高，白日猶未短。',72,'全唐诗/poet.tang.24000.json','["碧天忽已高，白日猶未短。", "玲瓏曉樓閣，清脆秋絲管。", "張翰一桮酣，嵇康終日嬾。", "塵中足憂累，雲外多疎散。", "病木斧斤遺，冥鴻羈緤斷。", "逍遙二三子，永願爲閑伴。"]'),
('7ad746eb-c18f-4c2f-b9af-fc5e77ddd31b','送呂漳州','白居易','唐','唐诗','tang','','[]','今朝一壺酒，言送漳州牧。',72,'全唐诗/poet.tang.24000.json','["今朝一壺酒，言送漳州牧。", "半自要閑遊，愛花憐草綠。", "花前下鞍馬，草上攜絲竹。", "行客飲數桮，主人歌一曲。", "端居惜風景，屢出勞僮僕。", "獨醉似無名，借君作題目。"]'),
('3edc8818-0eff-4805-8868-291aa99eb8f2','短歌曲','白居易','唐','唐诗','tang','','[]','世人求富貴，多爲奉嗜欲。',168,'全唐诗/poet.tang.24000.json','["世人求富貴，多爲奉嗜欲。", "盛衰不自由，得失常相逐。", "問君少年日，苦學將干祿。", "負笈塵中遊，抱書雪前讀。", "布衾不周體，藜茹纔充腹。", "三十登宦途，五十被朝服。", "奴溫新挾纊，馬肥初食粟。", "未敢議歡遊，尚爲名檢束。", "耳目聾闇後，堂上調絲竹。", "牙齒缺落時，盤中堆酒肉。", "彼來此已去，外餘中不足。", "少壯與榮華，相避如寒燠。", "青雲去地遠，白日經天速。", "從古無奈何，短歌聽一曲。"]'),
('8d3d2354-068b-4d4a-9e18-a3139865ee04','詠懷','白居易','唐','唐诗','tang','','[]','高人樂丘園，中人慕官職。',96,'全唐诗/poet.tang.24000.json','["高人樂丘園，中人慕官職。", "一事尚難成，兩途安可得。", "遑遑干世者，多苦時命塞。", "亦有愛閑人，又爲窮餓逼。", "我今幸雙遂，祿仕兼游息。", "未嘗羨榮華，不省勞心力。", "妻孥與婢僕，亦免愁衣食。", "所以吾一家，面無憂喜色。"]'),
('9d03704c-8423-4662-a90e-68290cd40cef','府西亭納涼歸','白居易','唐','唐诗','tang','','[]','避暑府西亭，晚歸有閑思。',96,'全唐诗/poet.tang.24000.json','["避暑府西亭，晚歸有閑思。", "夏淺蟬未多，綠槐陰滿地。", "帶寬衫解領，馬穩人攏轡。", "面上有涼風，眼前無俗事。", "路經府門過，落日照官次。", "牽聯縲紲囚，奔走塵埃吏。", "低眉悄不語，誰復知茲意。", "憶得五年前，晚衙時氣味。"]'),
('6bdb2b7e-568c-46e9-becb-eeff46b500a9','老熱','白居易','唐','唐诗','tang','','[]','一飽百情足，一酣萬事休。',144,'全唐诗/poet.tang.24000.json','["一飽百情足，一酣萬事休。", "何人不衰老，我老心無憂。", "仕者拘職役，農者勞田疇。", "何人不苦熱，我熱身自由。", "臥風北窗下，坐月南池頭。", "腦涼脫烏帽，足熱濯清流。", "慵發晝高枕，興來夜汎舟。", "何乃有餘適，祗緣無過求。", "或問諸親友，樂天是與不。", "亦無別言語，多道天悠悠。", "悠悠君不知，此味深且幽。", "但恐君知後，亦來從我遊。"]'),
('bcffc7f7-f392-48fe-805d-c9cd42b21903','新秋喜涼因寄兵部楊侍郎','白居易','唐','唐诗','tang','','[]','外強火未退，中銳金方戰。',120,'全唐诗/poet.tang.24000.json','["外強火未退，中銳金方戰。", "一夕風雨來，炎涼隨數變。", "徐徐炎景度，稍稍涼飆扇。", "枕簟忽淒清，巾裳亦輕健。", "老夫納秋候，心體殊安便。", "睡足一屈伸，搔首摩挲面。", "褰簾對池竹，幽寂如僧院。", "俯觀游魚羣，仰數浮雲片。", "閑忙各有趣，彼此寧相見。", "昨日聞慕巢，召對延英殿。"]'),
('760442d4-9a7c-4444-9212-d5890154df7d','嬾放二首呈劉夢得吳方之 一','白居易','唐','唐诗','tang','','[]','青衣報平旦，呼我起盥櫛。',48,'全唐诗/poet.tang.24000.json','["青衣報平旦，呼我起盥櫛。", "今早天氣寒，郎君應不出。", "又無賓客至，何以銷閑日。", "已向微陽前，煖酒開詩帙。"]'),
('a4233a6e-b302-496a-a098-e85a032c57d0','嬾放二首呈劉夢得吳方之 二','白居易','唐','唐诗','tang','','[]','朝憐一牀日，暮愛一爐火。',48,'全唐诗/poet.tang.24000.json','["朝憐一牀日，暮愛一爐火。", "牀暖日高眠，爐溫夜深坐。", "雀羅門嬾出，鶴髮頭慵裹。", "除却劉與吳，何人來問我。"]'),
('a516808c-976a-4059-b00c-e06e883cca1c','六十六','白居易','唐','唐诗','tang','','[]','病知心力減，老覺光陰速。',72,'全唐诗/poet.tang.24000.json','["病知心力減，老覺光陰速。", "五十八歸來，今年六十六。", "鬢絲千萬白，池草八九綠。", "童稚盡成人，園林半喬木。", "看山倚高石，引水穿深竹。", "雖有潺湲聲，至今聽未足。"]'),
('da46e373-98bd-4154-afbe-929348469124','三適贈道友','白居易','唐','唐诗','tang','','[]','褐綾袍厚暖，臥蓋行坐披。',84,'全唐诗/poet.tang.24000.json','["褐綾袍厚暖，臥蓋行坐披。", "紫氈履寬穩，蹇步頗相宜。", "足適已忘履，身適已忘衣。", "況我心又適，兼忘是與非。", "三適今爲一，怡怡復熙熙。", "禪那不動處，混沌未鑿時。", "此固不可說，爲君強言之。"]'),
('342d57c0-3644-4efe-8639-19ada687b0fa','洛陽春贈劉李二賓客','白居易','唐','唐诗','tang','','[]','水南冠蓋地，城東桃李園。',96,'全唐诗/poet.tang.24000.json','["水南冠蓋地，城東桃李園。", "雪消洛陽堰，春入永通門。", "淑景方靄靄，遊人稍喧喧。", "年豐酒漿賤，日晏歌吹繁。", "中有老朝客，華髮暎朱軒。", "從容三兩人，藉草開一尊。", "尊前春可惜，身外事勿論。", "明日期何處，杏花遊趙村。"]'),
('4bbe0a31-d4e2-4194-9763-117fb08e1006','寒食','白居易','唐','唐诗','tang','','[]','人老何所樂，樂在歸鄉國。',96,'全唐诗/poet.tang.24000.json','["人老何所樂，樂在歸鄉國。", "我歸故園來，九度逢寒食。", "故園在何處，池館東城側。", "四隣梨花時，二月伊水色。", "豈獨好風土，仍多舊親戚。", "出去恣歡遊，歸來聊燕息。", "有官供祿俸，無事勞心力。", "但恐優穩多，微躬銷不得。"]'),
('254d3b66-8f9d-4f78-a8d2-d777405b339c','和裴令公一日日一年年雜言見贈','白居易','唐','唐诗','tang','','[]','一日日，作老翁。',120,'全唐诗/poet.tang.24000.json','["一日日，作老翁。", "一年年，過春風。", "公心不以貴隔我，我散唯將閑伴公。", "我無才能忝高秩，合是人間閑散物。", "公有功德在生民，何因得作自由身。", "前日魏王潭上宴連夜，今日午橋池頭遊拂晨。", "山客硯前吟待月，野人尊前醉送春。", "不敢與公閑中爭第一，亦應占得第二第三人。"]'),
('07ea26ba-4e27-4a33-bc83-2b41ebfa0ba6','題裴晉公女几山刻石詩後','白居易','唐','唐诗','tang','','[]','何處畫功業，何處題詩篇？',216,'全唐诗/poet.tang.24000.json','["何處畫功業，何處題詩篇？", "麒麟高閣上，女几小山前。", "爾後多少時，四朝二十年。", "賊骨化爲土，賊壘犂爲田。", "一從賊壘平，陳蔡民晏然。", "騾軍成牛戶，鬼火變人煙。", "生子已嫁娶，種桑亦絲緜。", "皆云公之德，欲報無由緣。", "公今在何處，守都鎮三川。", "舊宅留永樂，新居開集賢。", "公今在何官，被衮珥貂蟬。", "戰袍破猶在，髀肉生欲圓。", "襟懷轉蕭灑，氣力彌精堅。", "登山不拄杖，上馬能掉鞭。", "利澤浸入池，福降昇自天。", "昔號天下將，今稱地上仙。", "勿追赤松遊，勿拍洪崖肩。", "商山有遺老，可以奉周旋。"]'),
('c13f70df-ae15-4a3c-ba96-45e817a7c1ab','洛陽有愚叟','白居易','唐','唐诗','tang','','[]','洛陽有愚叟，白黑無分別。',144,'全唐诗/poet.tang.24000.json','["洛陽有愚叟，白黑無分別。", "浪跡雖似狂，謀身亦不拙。", "點檢盤中飯，非精亦非糲。", "點檢身上衣，無餘亦無闕。", "天時方得所，不寒復不熱。", "體氣正調和，不飢仍不渴。", "閑將酒壺出，醉向人家歇。", "野食或烹鮮，寓眠多擁褐。", "抱琴榮啓樂，荷鍤劉伶達。", "放眼看青山，任頭生白髮。", "不知天地內，更得幾年活。", "從此到終身，盡爲閑日月。"]'),
('2373f1dd-9979-4f1d-8189-d2ff4398446d','飽食閑坐','白居易','唐','唐诗','tang','','[]','紅粒陸渾稻，白鱗伊水魴。',204,'全唐诗/poet.tang.24000.json','["紅粒陸渾稻，白鱗伊水魴。", "庖童呼我食，飯熱魚鮮香。", "筯筯適我口，匙匙充我腸。", "八珍與五鼎，無復心思量。", "捫腹起盥漱，下階振衣裳。", "繞庭行數匝，却上簷下牀。", "箕踞擁裘坐，半身在日暘。", "可憐飽暖味，誰肯來同嘗。", "是歲太和八，兵銷時漸康。", "朝廷重經術，草澤搜賢良。", "堯舜求理切，夔龍啓沃忙。", "懷才抱智者，無不走遑遑。", "唯此不才叟，頑慵戀洛陽。", "飽食不出門，閑坐不下堂。", "子弟多寂寞，僮僕少精光。", "衣食雖充給，神意不揚揚。", "爲爾謀則短，爲吾謀甚長。"]'),
('a002d71c-9d9f-4e83-99a4-614a8ec61d13','閑居自題','白居易','唐','唐诗','tang','','[]','門前有流水，牆上多高樹。',96,'全唐诗/poet.tang.24000.json','["門前有流水，牆上多高樹。", "竹逕繞荷池，縈迴百餘步。", "波閑戲魚鼈，風靜下鷗鷺。", "寂無城市喧，渺有江湖趣。", "吾廬在其上，偃臥朝復暮。", "洛下安一居，山中亦慵去。", "時逢過客愛，問是誰家住。", "此是白家翁，閉門終老處。"]'),
('9ca6b8ca-88e5-46b3-aad7-7fdd10f2831c','覽鏡喜老','白居易','唐','唐诗','tang','','[]','今朝覽明鏡，鬚鬢盡成絲。',168,'全唐诗/poet.tang.24000.json','["今朝覽明鏡，鬚鬢盡成絲。", "行年六十四，安得不衰羸。", "親屬惜我老，相顧興歎咨。", "而我獨微笑，此意何人知。", "笑罷仍命酒，掩鏡捋白髭。", "爾輩且安坐，從容聽我詞。", "生若不足戀，老亦何足悲。", "生若苟可戀，老即生多時。", "不老即須夭，不夭即須衰。", "晚衰勝早夭，此理決不疑。", "古人亦有言，浮生七十稀。", "我今欠六歲，多幸或庶幾。", "儻得及此限，何羨榮啓期。", "當喜不當歎，更傾酒一巵。"]'),
('6d9ab9d7-9810-44fa-92cb-eb02ac9d0907','風雪中作','白居易','唐','唐诗','tang','','[]','歲暮風動地，夜寒雪連天。',144,'全唐诗/poet.tang.24000.json','["歲暮風動地，夜寒雪連天。", "老夫何處宿，暖帳溫爐前。", "兩重褐綺衾，一領花茸氈。", "粥熟呼不起，日高安穩眠。", "是時心與身，了無閑事牽。", "以此度風雪，閑居來六年。", "忽思遠遊客，復想早朝士。", "蹋凍侵夜行，凌寒未明起。", "心爲身君父，身爲心臣子。", "不得身自由，皆爲心所使。", "我心既知足，我身自安止。", "方寸語形骸，吾應不負爾。"]'),
('3986ae17-9069-4dcf-84c2-9e706fbf0496','對琴酒','白居易','唐','唐诗','tang','','[]','西窗明且暖，晚坐卷書帷。',96,'全唐诗/poet.tang.24000.json','["西窗明且暖，晚坐卷書帷。", "琴匣拂開後，酒瓶添滿時。", "角尊白螺醆，玉軫黃金徽。", "未及彈與酌，相對已依依。", "泠泠秋泉韻，貯在龍鳳池。", "油油春雲心，一桮可致之。", "自古有琴酒，得此味者稀。", "祗因康與籍，及我三心知。"]'),
('c7baa30a-7c49-4d49-adfd-ed71dbd76b77','雪中晏起偶詠所懷兼呈張常侍韋庶子皇甫郎中','白居易','唐','唐诗','tang','','[]','窮陰蒼蒼雪雰雰，雪深沒脛泥埋輪。',242,'全唐诗/poet.tang.24000.json','["窮陰蒼蒼雪雰雰，雪深沒脛泥埋輪。", "東家典錢歸礙夜，南家貰米出凌晨。", "我獨何者無此弊，複帳重衾暖若春。", "怕寒放嬾不肯動，日高眠足方頻伸。", "瓶中有酒爐有炭，甕中有飯庖有薪。", "奴溫婢飽身晏起，致茲快活良有因。", "上無臯陶伯益廊廟材，的不能匡君輔國活生民。", "下無巢父許由箕潁操，又不能食薇飲水自苦辛。", "君不見南山悠悠多白雲，又不見西京浩浩唯紅塵。", "紅塵鬧熱白雲冷，好於冷熱中間安置身。", "三年徼倖忝洛尹，兩任優穩爲商賓。", "非賢非愚非智慧，不貴不富不賤貧。", "冉冉老去過六十，騰騰閑來經七春。", "不知張韋與皇甫，私喚我作何如人。"]'),
('1eabd342-c1c8-4d47-a9cf-8e8fb3413058','和裴侍中南園靜興見示','白居易','唐','唐诗','tang','','[]','池館清且幽，高懷亦如此。',48,'全唐诗/poet.tang.24000.json','["池館清且幽，高懷亦如此。", "有時簾動風，盡日橋照水。", "靜將鶴爲伴，閑與雲相似。", "何必學留侯，崎嶇覓松子。"]'),
('0a0e7252-0fff-4777-aa23-67c5ec87a213','春寒','白居易','唐','唐诗','tang','','[]','今朝春氣寒，自問何所欲。',79,'全唐诗/poet.tang.24000.json','["今朝春氣寒，自問何所欲。", "酥煖薤白酒，乳和地黃粥。", "豈惟厭饞口，亦可調病腹。", "助酌有枯魚，佐餐兼旨蓄。", "省躬念前哲，醉飽多慚忸。", "君不聞靖節先生尊長空，廣文先生飯不足。"]'),
('b1af3716-bea5-43e8-b7b0-608eea119cd1','菩提寺上方晚望香山寺寄舒員外','白居易','唐','唐诗','tang','','[]','晚登西寶剎，晴望東精舍。',72,'全唐诗/poet.tang.24000.json','["晚登西寶剎，晴望東精舍。", "反照轉樓臺，輝輝似圖畫。", "冰浮水明滅，雪壓松偃亞。", "石閣僧上來，雲汀雁飛下。", "西京鬧於市，東洛閑如社。", "曾憶舊遊無，香山明月夜。"]'),
('c51dbfcc-debd-45b5-b056-f9744e2e3628','二月一日作贈韋七庶子','白居易','唐','唐诗','tang','','[]','園杏紅萼坼，庭蘭紫芽出。',96,'全唐诗/poet.tang.24000.json','["園杏紅萼坼，庭蘭紫芽出。", "不覺春已深，今朝二月一。", "去冬病瘡痏，將養遵醫術。", "今春入道場，清淨依僧律。", "嘗聞聖賢語，所慎齋與疾。", "遂使愛酒人，停桮一百日。", "明朝二月二，疾平齋復畢。", "應須挈一壺，尋花覓韋七。"]'),
('34a00782-6048-4491-b93d-79c716e313fd','犬鳶','白居易','唐','唐诗','tang','','[]','晚來天氣好，散步中門前。',96,'全唐诗/poet.tang.24000.json','["晚來天氣好，散步中門前。", "門前何所有，偶覩犬與鳶。", "鳶飽凌風飛，犬暖向日眠。", "腹舒穩貼地，翅凝高摩天。", "上無羅弋憂，下無羈鎖牽。", "見彼物遂性，我亦心適然。", "心適復何爲，一詠逍遙篇。", "此仍著於適，尚未能忘言。"]'),
('a3897652-efc3-407d-8c77-36e8e40b045e','夢劉二十八因詩問之','白居易','唐','唐诗','tang','','[]','昨夜夢夢得，初覺思踟躕。',108,'全唐诗/poet.tang.24000.json','["昨夜夢夢得，初覺思踟躕。", "忽忘來汝郡，猶疑在吳都。", "吳都三千里，汝郡二百餘。", "非夢亦不見，近與遠何殊。", "尚能齊近遠，焉用論榮枯。", "但問寢與食，近日兩何如。", "病後能吟否，春來曾醉無。", "樓臺與風景，汝又何如蘇。", "相思一相報，勿復慵爲書。"]'),
('b18ae8cf-acfc-4aaf-b0dd-28e0571b1033','閑吟','白居易','唐','唐诗','tang','','[]','貧窮汲汲求衣食，富貴營營役心力。',64,'全唐诗/poet.tang.24000.json','["貧窮汲汲求衣食，富貴營營役心力。", "人生不富即貧窮，光陰易過閑難得。", "我今幸在窮富間，雖在朝廷不入山。", "看雪尋花翫風月，洛陽城裏七年閑。"]'),
('a5199b24-1928-4616-9497-c57f00546218','西行','白居易','唐','唐诗','tang','','[]','衣裘不單薄，車馬不羸弱。',96,'全唐诗/poet.tang.24000.json','["衣裘不單薄，車馬不羸弱。", "藹藹三月天，閑行亦不惡。", "壽安流水館，硤石青山郭。", "官道柳陰陰，行宮花漠漠。", "常聞俗間語，有錢在處樂。", "我雖非富人，亦不苦寂寞。", "家僮解弦管，騎從攜桮杓。", "時向春風前，歇鞍開一酌。"]'),
('aeb84397-00b0-484a-8ea0-a835e83c5fc6','東歸','白居易','唐','唐诗','tang','','[]','翩翩平肩輿，中有醉老夫。',120,'全唐诗/poet.tang.24000.json','["翩翩平肩輿，中有醉老夫。", "膝上展詩卷，竿頭懸酒壺。", "食宿無定程，僕馬多緩驅。", "臨水歇半日，望山傾一盂。", "藉草坐嵬峩，攀花行踟躕。", "風將景共暖，體與心同舒。", "始悟有營者，居家如在途。", "方知無繫者，在道如安居。", "前夕宿三堂，今旦遊申湖。", "殘春三百里，送我歸東都。"]'),
('5e64c470-9d23-43fe-a11b-ddebedd77088','途中作','白居易','唐','唐诗','tang','','[]','早起上肩舁，一杯平旦醉。',48,'全唐诗/poet.tang.24000.json','["早起上肩舁，一杯平旦醉。", "晚憩下肩舁，一覺殘春睡。", "身不經營物，心不思量事。", "但恐綺與里，只如吾氣味。"]'),
('2959e870-0a7b-4c95-a018-6a160ca68ed7','小臺','白居易','唐','唐诗','tang','','[]','新樹低如帳，小臺平似掌。',48,'全唐诗/poet.tang.24000.json','["新樹低如帳，小臺平似掌。", "六尺白藤牀，一莖青竹杖。", "風飄竹皮落，苔印鶴迹上。", "幽境與誰同，閑人自來往。"]'),
('3909f623-a817-420a-9fd9-b6e1f2722909','睡後茶興憶楊同州','白居易','唐','唐诗','tang','','[]','昨晚飲太多，嵬峩連宵醉。',120,'全唐诗/poet.tang.24000.json','["昨晚飲太多，嵬峩連宵醉。", "今朝餐又飽，爛熳移時睡。", "睡足摩挲眼，眼前無一事。", "信脚繞池行，偶然得幽致。", "婆娑綠陰樹，斑駮青苔地。", "此處置繩牀，傍邊洗茶器。", "白瓷甌甚潔，紅爐炭方熾。", "沫下麴塵香，花浮魚眼沸。", "盛來有佳色，嚥罷餘芳氣。", "不見楊慕巢，誰人知此味。"]'),
('d819e29f-810f-487a-9d01-a2d9a8c521fb','題文集櫃','白居易','唐','唐诗','tang','','[]','破柏作書櫃，櫃牢柏復堅。',96,'全唐诗/poet.tang.24000.json','["破柏作書櫃，櫃牢柏復堅。", "收貯誰家集，題云白樂天。", "我生業文字，自幼及老年。", "前後七十卷，小大三千篇。", "誠知終散失，未忍遽棄捐。", "自開自鎖閉，置在書帷前。", "身是鄧伯道，世無王仲宣。", "只應分付女，留與外孫傳。"]'),
('4cb1e6b6-8c7f-4cc7-8a1d-19decda8dcef','旱熱二首 一','白居易','唐','唐诗','tang','','[]','彤雲散不雨，赫日吁可畏。',120,'全唐诗/poet.tang.24000.json','["彤雲散不雨，赫日吁可畏。", "端坐猶揮汗，出門豈容易。", "忽思公府內，青衫折腰吏。", "復想驛路中，紅塵走馬使。", "征夫更辛苦，逐客彌顦顇。", "日入尚趨程，宵分不遑寐。", "安知北窗叟，偃臥風颯至。", "簟拂碧龍鱗，扇搖白鶴翅。", "豈唯身所得，兼示心無事。", "誰言苦熱天，元有清涼地。"]'),
('cde723ea-67c7-4892-b270-2d3ff5dcd116','旱熱二首 二','白居易','唐','唐诗','tang','','[]','勃勃旱塵氣，炎炎赤日光。',108,'全唐诗/poet.tang.24000.json','["勃勃旱塵氣，炎炎赤日光。", "飛禽颭將墜，行人渴欲狂。", "壯者不耐飢，飢火燒其腸。", "肥者不禁熱，喘急汗如漿。", "此時方自悟，老瘦亦何妨。", "肉輕足健逸，髮少頭清涼。", "薄食不飢渴，端居省衣裳。", "數匙粱飯冷，一領綃衫香。", "持此聊過日，焉知畏景長。"]'),
('701772d3-adf6-404a-9839-cb33ba353f3e','偶作二首 一','白居易','唐','唐诗','tang','','[]','戰馬春放歸，農牛冬歇息。',60,'全唐诗/poet.tang.24000.json','["戰馬春放歸，農牛冬歇息。", "何獨徇名人，終身役心力。", "來者殊未已，去者不知還。", "我今悟已晚，六十方退閑。", "猶勝不悟者，老死紅塵間。"]'),
('d9162d1d-7113-468e-8b82-46d6b54f6a5c','偶作二首 二','白居易','唐','唐诗','tang','','[]','名無高與卑，未得多健羨。',60,'全唐诗/poet.tang.24000.json','["名無高與卑，未得多健羨。", "事無小與大，已得多厭賤。", "如此常自苦，反此或自安。", "此理知甚易，此道行甚難。", "勿信人虛語，君當事上看。"]'),
('dc6de2e4-c3e9-45b4-bcee-1082b3ad417b','池上作','白居易','唐','唐诗','tang','','["\u592a\u6e56"]','西溪風生竹森森，南潭萍開水沈沈。',160,'全唐诗/poet.tang.24000.json','["西溪風生竹森森，南潭萍開水沈沈。", "叢翠萬竿湘岸色，空碧一泊松江心。", "浦派縈迴誤遠近，橋島向背迷窺臨。", "澄瀾方丈若萬頃，倒影咫尺如千尋。", "泛然獨遊邈然坐，坐念行心思古今。", "菟裘不聞有泉沼，西河亦恐無雲林。", "豈如白翁退老地，樹高竹密池塘深。", "華亭雙鶴白矯矯，太湖四石青岑岑。", "眼前盡日更無客，膝上此時唯有琴。", "洛陽冠蓋自相索，誰肯來此同抽簪。"]'),
('fa2161b9-1126-4121-96cd-81f8383a3d86','何處堪避暑','白居易','唐','唐诗','tang','','[]','何處堪避暑，林間背日樓。',144,'全唐诗/poet.tang.24000.json','["何處堪避暑，林間背日樓。", "何處好追涼，池上隨風舟。", "日高飢始食，食竟飽還遊。", "遊罷睡一覺，覺來茶一甌。", "眼明見青山，耳醒聞碧流。", "脫襪閑濯足，解巾快掻頭。", "如此來幾時，已過六七秋。", "從心至百骸，無一不自由。", "拙退是其分，榮耀非所求。", "雖被世間笑，終無身外憂。", "此語君莫怪，靜思吾亦愁。", "如何三伏月，楊尹謫虔州。"]'),
('e6067a35-9958-4d63-ac72-fdebc4acce30','詔下','白居易','唐','唐诗','tang','','[]','昨日詔下去罪人，今日詔下得賢臣。',80,'全唐诗/poet.tang.24000.json','["昨日詔下去罪人，今日詔下得賢臣。", "進退者誰非我事，世間寵辱常紛紛。", "我心與世兩相忘，時事雖聞如不聞。", "但喜今年飽飯吃，洛陽禾稼如秋雲。", "更傾一尊歌一曲，不獨忘世兼忘身。"]'),
('64a0141b-7d2d-487e-ac3c-1c74abd64ef2','七月一日作','白居易','唐','唐诗','tang','','[]','七月一日天，秋生履道里。',120,'全唐诗/poet.tang.24000.json','["七月一日天，秋生履道里。", "閑居見清景，高興從此始。", "林間暑雨歇，池上涼風起。", "橋竹碧鮮鮮，岸莎青靡靡。", "蒼然古磐石，清淺平流水。", "何言中門前，便是深山裏。", "雙僮侍坐臥，一杖扶行止。", "飢聞麻粥香，渴覺雲湯美。", "平生所好物，今日多在此。", "此外更何思，市朝心已矣。"]'),
('dbada1f3-2a57-42f1-a90f-5d037090dbf2','開襟','白居易','唐','唐诗','tang','','[]','開襟何處好，竹下池邊地。',48,'全唐诗/poet.tang.24000.json','["開襟何處好，竹下池邊地。", "餘熱體猶煩，早涼風有味。", "黃萎槐蘂結，紅破蓮芳墜。", "無奈每年秋，先來入衰思。"]'),
('a8dd7482-a024-4985-9ee4-aad421636c4f','自賓客遷太子少傅分司','白居易','唐','唐诗','tang','','[]','頭上漸無髮，耳間新有毫。',96,'全唐诗/poet.tang.24000.json','["頭上漸無髮，耳間新有毫。", "形容逐日老，官秩隨年高。", "優饒又加俸，閑穩仍分曹。", "飲食免藜藿，居處非蓬蒿。", "何言家尚貧，銀榼提綠醪。", "勿謂身未貴，金章照紫袍。", "誠合知止足，豈宜更貪饕。", "默默心自問，於國有何勞。"]'),
('7dc4706c-8abe-4c76-a9a8-47e15c1615d5','自在','白居易','唐','唐诗','tang','','[]','杲杲冬日光，明暖真可愛。',120,'全唐诗/poet.tang.24000.json','["杲杲冬日光，明暖真可愛。", "移榻向陽坐，擁裘仍解帶。", "小奴搥我足，小婢搔我背。", "自問我爲誰，胡然獨安泰。", "安泰良有以，與君論梗概。", "心了事未了，飢寒迫於外。", "事了心未了，念慮煎於內。", "我今實多幸，事與心和會。", "內外及中間，了然無一礙。", "所以日陽中，向君言自在。"]'),
('d9714c59-3855-4fdd-872f-e40c815dda84','詠史','白居易','唐','唐诗','tang','','[]','秦磨利刀斬李斯，齊燒沸鼎烹酈其。',64,'全唐诗/poet.tang.24000.json','["秦磨利刀斬李斯，齊燒沸鼎烹酈其。", "可憐黃綺入商洛，閑臥白雲歌紫芝。", "彼爲葅醢机上盡，此爲鸞皇天外飛。", "去者逍遙來者死，乃知禍福非天爲。"]'),
('a24d2277-3595-493f-b361-b6f81cfeac01','因夢有悟','白居易','唐','唐诗','tang','','[]','交友淪歿盡，悠悠勞夢思。',144,'全唐诗/poet.tang.24000.json','["交友淪歿盡，悠悠勞夢思。", "平生所厚者，昨夜夢見之。", "夢中幾許事，枕上無多時。", "欵曲數杯酒，從容一局碁。", "初見韋尚書，金紫何輝輝。", "中遇李侍郎，笑言甚怡怡。", "終爲崔常侍，意色苦依依。", "一夕三改變，夢心不驚疑。", "此事人盡怪，此理誰得知。", "我粗知此理，聞於竺乾師。", "識行妄分別，智隱迷是非。", "若轉識爲智，菩提其庶幾。"]'),
('d34c6cfd-3872-40dc-a4a5-3877cb093c6c','春遊','白居易','唐','唐诗','tang','','[]','上馬臨出門，出門復逡巡。',108,'全唐诗/poet.tang.24000.json','["上馬臨出門，出門復逡巡。", "迴頭問妻子，應怪春遊頻。", "誠知春遊頻，其奈老大身。", "朱顏去復去，白髮新更新。", "請君屈十指，爲我數交親。", "大限年百歲，幾人及七旬。", "我今六十五，走若下坂輪。", "假使得七十，祗有五度春。", "逢春不遊樂，但恐是癡人。"]'),
('2b2f683d-a08b-4c27-bb48-7156ba1b8ad4','題天竺南院贈閑元旻清四上人','白居易','唐','唐诗','tang','','[]','雜芳澗草合，繁綠巖樹新。',72,'全唐诗/poet.tang.24000.json','["雜芳澗草合，繁綠巖樹新。", "山深景候晚，四月有餘春。", "竹寺過微雨，石逕無纖塵。", "白衣一居士，方袍四道人。", "地是佛國土，人非俗交親。", "城中山下別，相送亦殷勤。"]'),
('9e586e12-312b-46e3-ac87-b7ce9d923781','哭師臯','白居易','唐','唐诗','tang','','[]','南康丹旐引魂迴，洛陽籃舁送葬來。',144,'全唐诗/poet.tang.24000.json','["南康丹旐引魂迴，洛陽籃舁送葬來。", "北邙原邊尹村畔，月苦煙愁夜過半。", "妻孥兄弟號一聲，十二人腸一時斷。", "往者何人送者誰，樂天哭別師臯時。", "平生分義向人盡，今日哀冤唯我知。", "我知何益徒垂淚，籃轝迴竿馬迴轡。", "何日重聞掃市歌，誰家收得琵琶伎。", "蕭蕭風樹白楊影，蒼蒼露草青蒿氣。", "更就墳前哭一聲，與君此別終天地。"]'),
('473ee174-d582-419b-9077-0535957c95f6','隱几贈客','白居易','唐','唐诗','tang','','[]','宦情本淡薄，年貌又老醜。',96,'全唐诗/poet.tang.24000.json','["宦情本淡薄，年貌又老醜。", "紫綬與金章，於予亦何有。", "有時獨隱几，荅然無所偶。", "臥枕一卷書，起嘗一杯酒。", "書將引昏睡，酒用扶衰朽。", "客到忽已酣，脫巾坐搔首。", "疎頑倚老病，容恕慚交友。", "忽思莊生言，亦擬鞭其後。"]'),
('14cebb2d-b656-41f4-bf23-40141eccd615','夏日作','白居易','唐','唐诗','tang','','[]','葛衣疎且單，紗帽輕復寬。',132,'全唐诗/poet.tang.24000.json','["葛衣疎且單，紗帽輕復寬。", "一衣與一帽，可以過炎天。", "止於便吾體，何必被羅紈。", "宿雨林笋嫩，晨露園葵鮮。", "烹葵炮嫩笋，可以備朝餐。", "止於適吾口，何必飫腥羶。", "飯訖盥漱已，捫腹方果然。", "婆娑庭前步，安穩窗下眠。", "外養物不費，內歸心不煩。", "不費用難盡，不煩神易安。", "庶幾無夭閼，得以終天年。"]'),
('c44c5684-0db7-4355-88f2-515ac562cfe6','晚涼偶詠','白居易','唐','唐诗','tang','','[]','日下西牆西，風來北窗北。',72,'全唐诗/poet.tang.24000.json','["日下西牆西，風來北窗北。", "中有逐涼人，單牀獨棲息。", "飄蕭過雲雨，搖曳歸飛翼。", "新葉多好陰，初筠有佳色。", "幽深小池館，優穩閑官職。", "不愛勿復論，愛亦不易得。"]'),
('024f6894-58ab-4730-a57a-96a3c9afdbfa','酬牛相公宮城早秋寓言見示兼呈夢得','白居易','唐','唐诗','tang','','[]','七月中氣後，金與火交爭。',72,'全唐诗/poet.tang.24000.json','["七月中氣後，金與火交爭。", "一聞白雪唱，暑退清風生。", "碧樹未搖落，寒蟬始悲鳴。", "夜涼枕簟滑，秋燥衣巾輕。", "疎受老慵出，劉楨疾未平。", "何人伴公醉，新月上宮城。"]'),
('4526ab6a-c723-43bc-b682-4fcd0e60f1fc','小臺晚坐憶夢得','白居易','唐','唐诗','tang','','[]','汲泉灑小臺，臺上無纖埃。',48,'全唐诗/poet.tang.24000.json','["汲泉灑小臺，臺上無纖埃。", "解帶面西坐，輕襟隨風開。", "晚涼閑興動，憶同傾一杯。", "月明候柴戶，藜杖何時來。"]'),
('23947308-550d-40eb-ac10-2226a4957601','種桃歌','白居易','唐','唐诗','tang','','[]','食桃種其核，一年核生芽。',96,'全唐诗/poet.tang.24000.json','["食桃種其核，一年核生芽。", "二年長枝葉，三年桃有花。", "憶昨五六歲，灼灼盛芬華。", "迨茲八九載，有減而無加。", "去春已稀少，今春漸無多。", "明年後年後，芳意當如何。", "命酒樹下飲，停杯拾餘葩。", "因桃忽自感，悲吒成狂歌。"]'),
('45bfc931-b2fa-402e-b3ba-7293f8306c24','狂言示諸姪','白居易','唐','唐诗','tang','','[]','世欺不識字，我忝攻文筆。',168,'全唐诗/poet.tang.24000.json','["世欺不識字，我忝攻文筆。", "世欺不得官，我忝居班秩。", "人老多病苦，我今幸無疾。", "人老多憂累，我今婚嫁畢。", "心安不移轉，身泰無牽率。", "所以十年來，形神閑且逸。", "況當垂老歲，所要無多物。", "一裘煖過冬，一飯飽終日。", "勿言舍宅小，不過寢一室。", "何用鞍馬多，不能騎兩匹。", "如我優幸身，人中十有七。", "如我知足心，人中百無一。", "傍觀愚亦見，當己賢多失。", "不敢論他人，狂言示諸姪。"]'),
('0cd1e68b-d552-4a67-a74a-32c6a666f1d5','偶以拙詩數首寄呈裴少尹侍郎蒙以盛製四篇一時酬和重投長句美而謝之','白居易','唐','唐诗','tang','','[]','投君之文甚荒蕪，數篇價直一束芻。',96,'全唐诗/poet.tang.24000.json','["投君之文甚荒蕪，數篇價直一束芻。", "報我之章何璀璨，纍纍四貫驪龍珠。", "毛詩三百篇後得，文選六十卷中無。", "一麋麗龜絕報賽，五鹿連柱難支梧。", "高興獨因秋日盡，清吟多與好風俱。", "銀鉤金錯兩殊重，宜上屏風張座隅。"]'),
('ce5bcc14-ed93-41d7-b2e7-a3ebc2165066','六年冬暮贈崔常侍晦叔','白居易','唐','唐诗','tang','','[]','鬢毛霜一色，光景水爭流。',48,'全唐诗/poet.tang.24000.json','["鬢毛霜一色，光景水爭流。", "易過唯冬日，難銷是老愁。", "香開綠蟻酒，煖擁褐綾裘。", "已共崔君約，尊前倒即休。"]'),
('41e3f463-1460-4aed-a203-56402ea427ef','戲招諸客','白居易','唐','唐诗','tang','','[]','黃醅綠醑迎冬熟，絳帳紅爐逐夜開。',32,'全唐诗/poet.tang.24000.json','["黃醅綠醑迎冬熟，絳帳紅爐逐夜開。", "誰道洛中多逸客，不將書喚不曾來。"]'),
('74c20329-8f1f-42e4-bfd1-f9834185e483','十二月二十三日作兼呈晦叔','白居易','唐','唐诗','tang','','[]','案頭曆日雖未盡，向後唯殘六七行。',64,'全唐诗/poet.tang.24000.json','["案頭曆日雖未盡，向後唯殘六七行。", "牀下酒瓶雖不滿，猶應醉得兩三場。", "病身不許依年老，拙宦虛教逐日忙。", "聞健偷閑且勤飲，一杯之外莫思量。"]'),
('b645c497-62ad-4f04-ae20-741e0e32b1bf','七年元日對酒五首 一','白居易','唐','唐诗','tang','','[]','慶弔經過嬾，逢迎跪拜遲。',24,'全唐诗/poet.tang.24000.json','["慶弔經過嬾，逢迎跪拜遲。", "不因時節日，豈覺此身羸。"]'),
('c81bdf06-cc57-4e5e-9b1c-b952a27e332e','七年元日對酒五首 二','白居易','唐','唐诗','tang','','[]','衆老憂添歲，余衰喜入春。',24,'全唐诗/poet.tang.24000.json','["衆老憂添歲，余衰喜入春。", "年開第七秩，屈指幾多人。"]'),
('78d6f1d3-6895-43a9-9977-4b61cb053bf0','七年元日對酒五首 三','白居易','唐','唐诗','tang','','[]','三杯藍尾酒，一楪膠牙餳。',24,'全唐诗/poet.tang.24000.json','["三杯藍尾酒，一楪膠牙餳。", "除却崔常侍，無人共我爭。"]'),
('bd30747f-9559-4026-b633-f951c5db5079','七年元日對酒五首 四','白居易','唐','唐诗','tang','','[]','今朝吳與洛，相憶一欣然。',24,'全唐诗/poet.tang.24000.json','["今朝吳與洛，相憶一欣然。", "夢得君知否，俱過本命年。"]'),
('94f6d933-1d67-4b12-a227-6065ba306274','七年元日對酒五首 五','白居易','唐','唐诗','tang','','[]','同歲崔何在，同年杜又無。',24,'全唐诗/poet.tang.24000.json','["同歲崔何在，同年杜又無。", "應無藏避處，只有且歡娛。"]'),
('151724fa-8ac4-4de5-957f-2fecca7a286f','七年春題府廳','白居易','唐','唐诗','tang','','[]','潦倒守三川，因循涉四年。',48,'全唐诗/poet.tang.24000.json','["潦倒守三川，因循涉四年。", "推誠廢鉤距，示耻用蒲鞭。", "以此稱公事，將何銷俸錢。", "雖非好官職，歲久亦妨賢。"]'),
('184cc912-91cc-4b60-a1b6-c01a9906d46f','早春醉吟寄太原令狐相公蘇州劉郎中','白居易','唐','唐诗','tang','','[]','雪夜閑遊多秉燭，花時蹔出亦提壺。',64,'全唐诗/poet.tang.24000.json','["雪夜閑遊多秉燭，花時蹔出亦提壺。", "別來少遇新詩敵，老去難逢舊飲徒。", "大振威名降北虜，勤行惠化活東吳。", "不知歌酒騰騰興，得似河南醉尹無。"]'),
('3cc093e1-e345-4ffe-9721-f49b48891cfa','洛下送牛相公出鎮淮南','白居易','唐','唐诗','tang','','[]','北闕至東京，風光十六程。',72,'全唐诗/poet.tang.24000.json','["北闕至東京，風光十六程。", "坐移丞相閣，春入廣陵城。", "紅斾擁雙節，白鬚無一莖。", "萬人開路看，百吏立班迎。", "閫外君彌重，尊前我亦榮。", "何須身自得，將相是門生。"]'),
('380609ae-9cfc-49bb-857e-de43b33175aa','箏','白居易','唐','唐诗','tang','','[]','雲髻飄蕭綠，花顏旖旎紅。',168,'全唐诗/poet.tang.24000.json','["雲髻飄蕭綠，花顏旖旎紅。", "雙眸剪秋水，十指剝春蔥。", "楚豔爲門閥，秦聲是女工。", "甲明銀玓瓅，柱觸玉玲瓏。", "猨苦啼嫌月，鶯嬌語䛏風。", "移愁來手底，送恨入弦中。", "趙瑟清相似，胡琴鬧不同。", "慢彈迴斷雁，急奏轉飛蓬。", "霜珮鏘還委，冰泉咽復通。", "珠聯千拍碎，刀截一聲終。", "倚麗精神定，矜能意態融。", "歇時情不斷，休去思無窮。", "燈下青春夜，尊前白首翁。", "且聽應得在，老耳未多聾。"]'),
('4e0c217e-fb38-42a2-9b11-ab78b2dec630','洛中春遊呈諸親友','白居易','唐','唐诗','tang','','[]','莫歎年將暮，須憐歲又新。',96,'全唐诗/poet.tang.24000.json','["莫歎年將暮，須憐歲又新。", "府中三遇臘，洛下五逢春。", "春樹花珠顆，春塘水麴塵。", "春娃無氣力，春馬有精神。", "並轡鞭徐動，連盤酒慢巡。", "經過舊鄰里，追逐好交親。", "笑語銷閑日，酣歌送老身。", "一生歡樂事，亦不少於人。"]'),
('b44b76b7-a788-403b-9bf8-9c55491b469d','酬舒三員外見贈長句','白居易','唐','唐诗','tang','','[]','自請假來多少日，五旬光景似須臾。',64,'全唐诗/poet.tang.24000.json','["自請假來多少日，五旬光景似須臾。", "已判到老爲狂客，不分當春作病夫。", "楊柳花飄新白雪，櫻桃子綴小紅珠。", "頭風不敢多多飲，能酌三分相勸無。"]'),
('bb72f1ba-72fc-40c3-8cca-173c96198e07','將歸一絕','白居易','唐','唐诗','tang','','[]','欲去公門返野扉，預思泉竹已依依。',32,'全唐诗/poet.tang.24000.json','["欲去公門返野扉，預思泉竹已依依。", "更憐家醞迎春熟，一甕醍醐待我歸。"]'),
('5f0e6ff3-3c6f-4530-ba60-3259058b43c8','罷府歸舊居','白居易','唐','唐诗','tang','','[]','陋巷乘籃入，朱門挂印迴。',72,'全唐诗/poet.tang.24000.json','["陋巷乘籃入，朱門挂印迴。", "腰間拋組綬，纓上拂塵埃。", "屈曲閑池沼，無非手自開。", "青蒼好竹樹，亦是眼看栽。", "石片擡琴匣，松枝閣酒杯。", "此生終老處，昨日却歸來。"]'),
('921be510-61d6-4d24-bb98-65ed89112664','睡覺偶吟','白居易','唐','唐诗','tang','','[]','官初罷後歸來夜，天欲明前睡覺時。',32,'全唐诗/poet.tang.24000.json','["官初罷後歸來夜，天欲明前睡覺時。", "起坐思量更無事，身心安樂復誰知。"]'),
('3b3c7aea-d799-4134-87eb-3ab9a1a7ea6d','問支琴石','白居易','唐','唐诗','tang','','[]','疑因星隕空中落，歎被泥埋澗底沈。',48,'全唐诗/poet.tang.24000.json','["疑因星隕空中落，歎被泥埋澗底沈。", "天上定應勝地上，支機未必及支琴。", "提攜拂拭知恩否，雖不能言合有心。"]'),
('ace314e9-a760-4216-9e02-888e0c81ba91','自喜','白居易','唐','唐诗','tang','','[]','身慵難勉強，性拙易遲迴。',48,'全唐诗/poet.tang.24000.json','["身慵難勉強，性拙易遲迴。", "布被辰時起，柴門午後開。", "忙驅能者去，閑逐鈍人來。", "自喜誰能會，無才勝有才。"]'),
('425946cb-3dc6-43d5-a5d1-bff11eaacaa0','裴常侍以題薔薇架十八韻見示因廣爲三十韻以和之','白居易','唐','唐诗','tang','','[]','託質依高架，攢花對小堂。',288,'全唐诗/poet.tang.24000.json','["託質依高架，攢花對小堂。", "晚開春去後，獨秀院中央。", "霽景朱明早，芳時白晝長。", "穠因天與色，麗共日爭光。", "剪碧排千萼，研朱染萬房。", "煙條塗石綠，粉蘂撲雌黃。", "根動彤雲涌，枝搖赤羽翔。", "九微燈炫轉，七寶帳熒煌。", "淑氣熏行徑，清陰接步廊。", "照梁迷藻梲，耀壁變雕牆。", "爛若藂然火，殷於葉得霜。", "臙脂含臉笑，蘇合裛衣香。", "浹洽濡晨露，玲瓏漏夕陽。", "合羅排勘纈，醉暈淺深妝。", "乍見疑迴面，遙看誤斷腸。", "風朝舞飛燕，雨夜泣蕭娘。", "桃李慙無語，芝蘭讓不芳。", "山榴何細碎，石竹苦尋常。", "蕙慘偎欄避，蓮羞映浦藏。", "怯教蕉葉戰，妬得柳花狂。", "豈可輕嘲詠，應須痛比方。", "畫幈風自展，繡繖蓋誰張。", "翠錦挑成字，丹砂印著行。", "猩猩凝血點，瑟瑟蹙金匡。"]'),
('dfcb71c9-88c4-4244-aa24-2b40eb4f9f7b','感舊詩卷','白居易','唐','唐诗','tang','','[]','夜深吟罷一長吁，老淚燈前濕白鬚。',32,'全唐诗/poet.tang.24000.json','["夜深吟罷一長吁，老淚燈前濕白鬚。", "二十年前舊詩卷，十人酬和九人無。"]'),
('f0919f4d-7a6b-4328-bf2c-2471fc31d253','酬李二十侍郎','白居易','唐','唐诗','tang','','[]','笋老蘭長花漸稀，衰翁相對惜芳菲。',64,'全唐诗/poet.tang.24000.json','["笋老蘭長花漸稀，衰翁相對惜芳菲。", "殘鶯著雨慵休囀，落絮無風凝不飛。", "行掇木芽供野食，坐牽蘿蔓挂朝衣。", "十年分手今同醉，醉未如泥莫道歸。"]'),
('0d9f48bb-cc2f-44d5-8478-c3d788277ff5','和夢得','白居易','唐','唐诗','tang','','[]','綸閣沈沈無寵命，蘇臺籍籍有能聲。',64,'全唐诗/poet.tang.24000.json','["綸閣沈沈無寵命，蘇臺籍籍有能聲。", "豈唯不得清文力，但恐空傳冗吏名。", "郎署迴翔何水部，江湖留滯謝宣城。", "所嗟非獨君如此，自古才難共命爭。"]'),
('e44ca5fe-3ecb-44db-8fed-134d38042348','贈草堂宗密上人','白居易','唐','唐诗','tang','','[]','吾師道與佛相應，念念無爲法法能。',64,'全唐诗/poet.tang.24000.json','["吾師道與佛相應，念念無爲法法能。", "口藏宣傳十二部，心臺照耀百千燈。", "盡離文字非中道，長住虛空是小乘。", "少有人知菩薩行，世間只是重高僧。"]'),
('f965c4af-8fb5-4179-821b-4aa9f475000e','喜照密閑實四上人見過','白居易','唐','唐诗','tang','','[]','紫袍朝士白髯翁，與俗乖疎與道通。',66,'全唐诗/poet.tang.24000.json','["紫袍朝士白髯翁，與俗乖疎與道通。", "官秩三迴分洛下，交遊一半在僧中。", "臭[帤]世界終須出，香火因緣久願同。", "齋後將何充供養，西軒泉石北窗風。"]'),
('aa3b5db0-1dec-4c14-8f7e-ac7f64c11afa','贈皇甫六張十五李二十三賓客','白居易','唐','唐诗','tang','','[]','昨日三川新罷守，今年四皓盡分司。',64,'全唐诗/poet.tang.24000.json','["昨日三川新罷守，今年四皓盡分司。", "幸陪散秩閑居日，好是登山臨水時。", "家未苦貧常醞酒，身雖衰病尚吟詩。", "龍門泉石香山月，早晚同遊報一期。"]'),
('565dde47-fa94-42ae-bcdc-762c38cc13d7','微之敦詩晦叔相次長逝巋然自傷因成二絕 一','白居易','唐','唐诗','tang','','[]','併失鵷鸞侶，空留麋鹿身。',24,'全唐诗/poet.tang.24000.json','["併失鵷鸞侶，空留麋鹿身。", "只應嵩洛下，長作獨遊人。"]'),
('196cd7ae-bd14-4f25-a614-46b6c536a079','微之敦詩晦叔相次長逝巋然自傷因成二絕 二','白居易','唐','唐诗','tang','','[]','長夜君先去，殘年我幾何。',24,'全唐诗/poet.tang.24000.json','["長夜君先去，殘年我幾何。", "秋風滿衫淚，泉下故人多。"]'),
('002c015a-2991-4ebf-bc33-e0749ab556dc','池上閑詠','白居易','唐','唐诗','tang','','[]','青莎臺上起書樓，綠藻潭中繫釣舟。',64,'全唐诗/poet.tang.24000.json','["青莎臺上起書樓，綠藻潭中繫釣舟。", "日晚愛行深竹裏，月明多上小橋頭。", "蹔嘗新酒還成醉，亦出中門便當遊。", "一部清商聊送老，白鬚蕭颯管弦秋。"]'),
('b927a9a0-9479-4497-849e-966342f62e5c','涼風歎','白居易','唐','唐诗','tang','','[]','昨夜涼風又颯然，螢飄葉墜臥牀前。',32,'全唐诗/poet.tang.24000.json','["昨夜涼風又颯然，螢飄葉墜臥牀前。", "逢秋莫歎須知分，已過潘安三十年。"]'),
('7896c24e-7c04-4e75-9bec-4867baf47de4','和高僕射罷節度讓尚書授少保分司喜遂遊山水之作','白居易','唐','唐诗','tang','','[]','蹔辭八座罷雙旌，便作登山臨水行。',64,'全唐诗/poet.tang.24000.json','["蹔辭八座罷雙旌，便作登山臨水行。", "能以忠貞酬重任，不將富貴礙高情。", "朱門出去簪纓從，絳帳歸來歌吹迎。", "鞍轡鬧裝光滿馬，何人信道是書生。"]'),
('9de06d8f-3fad-4fda-a244-4abd9c7e0225','送考功崔郎中赴闕','白居易','唐','唐诗','tang','','[]','稱意新官又少年，秋涼身健好朝天。',32,'全唐诗/poet.tang.24000.json','["稱意新官又少年，秋涼身健好朝天。", "青雲上了無多路，却要徐驅穩著鞭。"]'),
('96108067-1aa0-48f2-a957-097e98c34c5b','重修香山寺畢題二十二韻以紀之','白居易','唐','唐诗','tang','','[]','闕塞龍門口，祇園鷲嶺頭。',264,'全唐诗/poet.tang.24000.json','["闕塞龍門口，祇園鷲嶺頭。", "曾隨減劫壞，今遇勝緣修。", "再瑩新金剎，重裝舊石樓。", "病僧皆引起，忙客亦淹留。", "四望窮沙界，孤標出贍州。", "地圖鋪洛邑，天柱倚崧丘。", "兩面蒼蒼岸，中心瑟瑟流。", "波翻八灘雪，堰護一潭油。", "臺殿朝彌麗，房廊夜更幽。", "千花高下塔，一葉往來舟。", "岫合雲初吐，林開霧半收。", "靜聞樵子語，遠聽棹郎謳。", "官散殊無事，身閑甚自由。", "吟來攜筆硯，宿去抱衾裯。", "霽月當窗白，涼風滿簟秋。", "煙香封藥竈，泉冷洗茶甌。", "南祖心應學，西方社可投。", "先宜知止足，次要悟浮休。", "覺路隨方樂，迷塗到老愁。", "須除愛名障，莫作戀家囚。", "便合窮年住，何言竟日遊。", "可憐終老地，此是我菟裘。"]'),
('32665393-d2bb-455c-8152-5daf1f7285ff','送楊八給事赴常州','白居易','唐','唐诗','tang','','[]','無嗟別青瑣，且喜擁朱輪。',48,'全唐诗/poet.tang.24000.json','["無嗟別青瑣，且喜擁朱輪。", "五十得三品，百千無一人。", "須勤念黎庶，莫苦憶交親。", "此外無過醉，毗陵何限春。"]'),
('796d2ab3-7d90-4856-b151-49e011156dea','聞歌者唱微之詩','白居易','唐','唐诗','tang','','[]','新詩絕筆聲名歇，舊卷生塵篋笥深。',32,'全唐诗/poet.tang.24000.json','["新詩絕筆聲名歇，舊卷生塵篋笥深。", "時向歌中聞一句，未容傾耳已傷心。"]'),
('73845d0d-3584-4daa-97b9-ca73859ff4f1','醉送李二十常侍赴鎮浙東','白居易','唐','唐诗','tang','','[]','靖安客舍花枝下，共脫青衫典濁醪。',64,'全唐诗/poet.tang.24000.json','["靖安客舍花枝下，共脫青衫典濁醪。", "今日洛橋還醉別，金杯翻汙麒麟袍。", "喧闐夙駕君脂轄，酩酊離筵我藉糟。", "好去商山紫芝伴，珊瑚鞭動馬頭高。"]'),
('e714d456-4d51-490a-ae42-feab7529d259','醉別程秀才','白居易','唐','唐诗','tang','','[]','五度龍門點額迴，却緣多藝復多才。',64,'全唐诗/poet.tang.24000.json','["五度龍門點額迴，却緣多藝復多才。", "貧泥客路黏難出，愁鎖鄉心掣不開。", "何必更遊京國去，不如且入醉鄉來。", "吳弦楚調瀟湘弄，爲我殷勤送一杯。"]'),
('4b603ebd-6ad7-493a-bddd-501ca2344341','自詠','白居易','唐','唐诗','tang','','[]','白衣居士紫芝仙，半醉行歌半坐禪。',64,'全唐诗/poet.tang.24000.json','["白衣居士紫芝仙，半醉行歌半坐禪。", "今日維摩兼飲酒，當時綺季不請錢。", "等閑池上留賓客，隨事燈前有管弦。", "但問此身銷得否，分司氣味不論年。"]'),
('13cc88b7-535c-4b7d-89df-18120ec96632','把酒思閑事二首 一','白居易','唐','唐诗','tang','','[]','把酒思閑事，春愁誰最深。',48,'全唐诗/poet.tang.24000.json','["把酒思閑事，春愁誰最深。", "乞錢羈客面，落第舉人心。", "月下低眉立，燈前抱膝吟。", "憑君勸一醉，勝與萬黃金。"]'),
('1fab3a94-503b-4d35-8b11-8df2107fdedc','把酒思閑事二首 二','白居易','唐','唐诗','tang','','[]','把酒思閑事，春嬌何處多。',48,'全唐诗/poet.tang.24000.json','["把酒思閑事，春嬌何處多。", "試鞍新白馬，弄鏡小青娥。", "掌上初教舞，花前欲按歌。", "憑君勸一醉，勸了問如何。"]'),
('5876ce59-4a0c-42d8-bd90-141ae68cba17','衰荷','白居易','唐','唐诗','tang','','[]','白露凋花花不殘，涼風吹葉葉初乾。',32,'全唐诗/poet.tang.24000.json','["白露凋花花不殘，涼風吹葉葉初乾。", "無人解愛蕭條境，更繞衰藂一匝看。"]'),
('4ce224c4-d210-4663-b43c-2ee1adc87ebb','池上送考功崔郎中兼別房竇二妓','白居易','唐','唐诗','tang','','[]','文昌列宿徵還日，洛浦行雲放散時。',32,'全唐诗/poet.tang.24000.json','["文昌列宿徵還日，洛浦行雲放散時。", "鵷鷺上天花逐水，無因再會白家池。"]'),
('7f3f01b2-a125-4116-b69d-d1b6cb1c06e8','自問','白居易','唐','唐诗','tang','','[]','依仁臺廢悲風晚，履信池荒宿草春。',32,'全唐诗/poet.tang.24000.json','["依仁臺廢悲風晚，履信池荒宿草春。", "自問老身騎馬出，洛陽城裏覓何人。"]'),
('c3aa5fed-7929-4548-9806-8934bf6846d9','送陳許高僕射赴鎮','白居易','唐','唐诗','tang','','[]','敦詩說禮中軍師，重士輕財大丈夫。',64,'全唐诗/poet.tang.24000.json','["敦詩說禮中軍師，重士輕財大丈夫。", "常與師徒同苦樂，不教親故隔榮枯。", "花鈿坐繞黃金印，絲管行隨白玉壺。", "商皓老狂唯愛醉，時時能寄酒錢無。"]'),
('211b87d4-f55d-4a61-b858-e714d07c81af','青氈帳二十韻','白居易','唐','唐诗','tang','','[]','合聚千羊毳，施張百子弮。',240,'全唐诗/poet.tang.24000.json','["合聚千羊毳，施張百子弮。", "骨盤邊柳健，色染塞藍鮮。", "北製因戎剏，南移逐虜遷。", "汰風吹不動，禦雨濕彌堅。", "有頂中央聳，無隅四嚮圓。", "傍通門豁爾，內密氣溫然。", "遠別關山外，初安庭戶前。", "影孤明月夜，價重苦寒年。", "軟煖圍氈毯，鎗摐束管弦。", "最宜霜後地，偏稱雪中天。", "側置低歌座，平鋪小舞筵。", "閑多揭簾入，醉便擁袍眠。", "鐵檠移燈背，銀囊帶火懸。", "深藏曉蘭焰，闇貯宿香煙。", "獸炭休親近，狐裘可棄捐。", "硯溫融凍墨，瓶煖變春泉。", "蕙帳徒招隱，茅庵浪坐禪。", "貧僧應歎羨，寒士定留連。", "賓客於中接，兒孫向後傳。", "王家誇舊物，未及此青氈。"]'),
('7330b304-e43a-4826-9ba7-d045b6507c1f','荅夢得秋日書懷見寄','白居易','唐','唐诗','tang','','[]','幸免非常病，甘當本分衰。',48,'全唐诗/poet.tang.24000.json','["幸免非常病，甘當本分衰。", "眼昏燈最覺，腰瘦帶先知。", "樹葉霜紅日，髭鬚雪白時。", "悲愁緣欲老，老過却無悲。"]'),
('7fb32f2c-572d-4902-a896-4c453e456355','同諸客題于家公主舊宅','白居易','唐','唐诗','tang','','[]','平陽舊宅少人遊，應是遊人到即愁。',64,'全唐诗/poet.tang.24000.json','["平陽舊宅少人遊，應是遊人到即愁。", "布穀鳥啼桃李院，絡絲蟲怨鳳皇樓。", "臺傾滑石猶殘砌，簾斷珍珠不滿鉤。", "聞道至今蕭史在，髭鬚雪白向明州。"]'),
('50f12723-796f-42ad-851b-8fc53963c31b','荅夢得八月十五日夜翫月見寄','白居易','唐','唐诗','tang','','[]','南國碧雲客，東京白首翁。',48,'全唐诗/poet.tang.24000.json','["南國碧雲客，東京白首翁。", "松江初有月，伊水正無風。", "遠思兩鄉斷，清光千里同。", "不知娃館上，何似石樓中。"]'),
('97034772-e5f4-4862-b6d4-95ebc1e27713','初冬早起寄夢得','白居易','唐','唐诗','tang','','[]','起戴烏紗帽，行披白布裘。',48,'全唐诗/poet.tang.24000.json','["起戴烏紗帽，行披白布裘。", "爐溫先煖酒，手冷未梳頭。", "早起煙霜白，初寒鳥雀愁。", "詩成遣誰和，還是寄蘇州。"]'),
('51bb51c6-a88c-45b2-910b-0336ce5e5a44','秋夜聽高調涼州','白居易','唐','唐诗','tang','','[]','樓上金風聲漸緊，月中銀字韻初調。',32,'全唐诗/poet.tang.24000.json','["樓上金風聲漸緊，月中銀字韻初調。", "促張弦柱吹高管，一曲涼州入泬寥。"]'),
('f151ee81-f625-4e49-a426-77038e336425','香山寺二絕 一','白居易','唐','唐诗','tang','','[]','空山寂靜老夫閑，伴鳥隨雲往復還。',32,'全唐诗/poet.tang.24000.json','["空山寂靜老夫閑，伴鳥隨雲往復還。", "家醞滿瓶書滿架，半移生計入香山。"]'),
('d29909c2-b452-4e76-8a47-cd478a322ca4','香山寺二絕 二','白居易','唐','唐诗','tang','','[]','愛風巖上攀松蓋，戀月潭邊坐石稜。',32,'全唐诗/poet.tang.24000.json','["愛風巖上攀松蓋，戀月潭邊坐石稜。", "且共雲泉結緣境，他生當作此山僧。"]'),
('f4acf547-700d-49ce-bcc3-3b3a7037a122','送舒著作重授省郎赴闕','白居易','唐','唐诗','tang','','[]','三歲相依在洛都，遊花宴月飽歡娛。',64,'全唐诗/poet.tang.24000.json','["三歲相依在洛都，遊花宴月飽歡娛。", "惜別笙歌多怨咽，願留軒蓋少踟躕。", "劒磨光彩依前出，鵬舉風雲逐後驅。", "從此求閑應不得，更能重醉白家無。"]'),
('a01070e1-643e-454e-8fe3-6a788d2cfaac','同諸客嘲雪中馬上妓','白居易','唐','唐诗','tang','','[]','珊瑚鞭嚲馬踟躕，引手低蛾索一盂。',64,'全唐诗/poet.tang.24000.json','["珊瑚鞭嚲馬踟躕，引手低蛾索一盂。", "腰爲逆風成弱柳，面因衝冷作凝酥。", "銀箆穩篸烏羅帽，花襜宜乘吒撥駒。", "雪裏君看何所似，王昭君妹寫真圖。"]'),
('7cbc31bb-8c8b-4374-a165-794f4800b86f','喜劉蘇州恩賜金紫遙[想]賀宴以詩慶之','白居易','唐','唐诗','tang','','[]','海內姑蘇太守賢，恩加章綬豈徒然。',64,'全唐诗/poet.tang.24000.json','["海內姑蘇太守賢，恩加章綬豈徒然。", "賀賓喜色欺杯酒，醉妓歡聲遏管弦。", "魚珮葺鱗光照地，鶻銜瑞帶勢衝天。", "莫嫌鬢上些些白，金紫由來稱長年。"]'),
('9e621165-94ad-4db2-94de-ebfb73ece84c','藍田劉明府攜酌相過與皇甫郎中卯時同飲醉後贈之','白居易','唐','唐诗','tang','','[]','臘月九日煖寒客，卯時十分空腹杯。',64,'全唐诗/poet.tang.24000.json','["臘月九日煖寒客，卯時十分空腹杯。", "玄晏舞狂烏帽落，藍田醉倒玉山頹。", "貌偷花色老蹔去，歌蹋柳枝春闇來。", "不爲劉家賢聖物，愁翁笑口大難開。"]'),
('6a22da1e-a3be-49f5-8fe1-0d9b3ae4d4e1','劉蘇州以華亭一鶴遠寄以詩謝之','白居易','唐','唐诗','tang','','[]','老鶴風姿異，衰翁詩思深。',48,'全唐诗/poet.tang.24000.json','["老鶴風姿異，衰翁詩思深。", "素毛如我鬢，丹頂似君心。", "松際雪相映，雞羣塵不侵。", "殷勤遠來意，一隻重千金。"]'),
('dc09fdf3-6031-446a-a27e-30b1ed4d5c47','早春憶蘇州寄夢得','白居易','唐','唐诗','tang','','[]','吳苑四時風景好，就中偏好是春天。',64,'全唐诗/poet.tang.24000.json','["吳苑四時風景好，就中偏好是春天。", "霞光曙後殷於火，水色晴來嫩似煙。", "士女笙歌宜月下，使君金紫稱花前。", "誠知歡樂堪留戀，其奈離鄉已四年。"]'),
('de784111-1c38-412b-b94a-3db3b1f4536f','嘗新酒憶晦叔二首 一','白居易','唐','唐诗','tang','','[]','尊裏看無色，杯中動有光。',24,'全唐诗/poet.tang.24000.json','["尊裏看無色，杯中動有光。", "自君拋我去，此物共誰嘗。"]'),
('81dd517b-fbed-40d1-9302-6535ca10e088','嘗新酒憶晦叔二首 二','白居易','唐','唐诗','tang','','[]','世上強欺弱，人間醉勝醒。',24,'全唐诗/poet.tang.24000.json','["世上強欺弱，人間醉勝醒。", "自君拋我去，此語更誰聽。"]'),
('45539b39-e29f-440c-9737-02bfc5e54ca0','負春','白居易','唐','唐诗','tang','','[]','病來道士教調氣，老去山僧勸坐禪。',32,'全唐诗/poet.tang.24000.json','["病來道士教調氣，老去山僧勸坐禪。", "孤負春風楊柳曲，去年斷酒到今年。"]'),
('c5bddd1f-d034-4116-8f22-1d7a568b18a8','池上閑吟二首 一','白居易','唐','唐诗','tang','','[]','高臥閑行自在身，池邊六見柳條新。',64,'全唐诗/poet.tang.24000.json','["高臥閑行自在身，池邊六見柳條新。", "幸逢堯舜無爲日，得作羲皇向上人。", "四皓再除猶且健，三州罷守未全貧。", "莫愁客到無供給，家醞香濃野菜春。"]'),
('06187b4a-0070-4d0b-bdb0-77145ab0f9f7','池上閑吟二首 二','白居易','唐','唐诗','tang','','[]','非莊非宅非蘭若，竹樹池亭十畝餘。',64,'全唐诗/poet.tang.24000.json','["非莊非宅非蘭若，竹樹池亭十畝餘。", "非道非僧非俗吏，褐裘烏帽閉門居。", "夢遊信意寧殊蝶，心樂身閑便是魚。", "雖未定知生與死，其間勝負兩何如。"]'),
('44ddbb45-11fb-4025-a953-642501430210','早春招張賓客','白居易','唐','唐诗','tang','','[]','久雨初晴天氣新，風煙草樹盡欣欣。',64,'全唐诗/poet.tang.24000.json','["久雨初晴天氣新，風煙草樹盡欣欣。", "雖當冷落衰殘日，還有陽和暖活身。", "池色溶溶藍染水，花光燄燄火燒春。", "商山老伴相收拾，不用隨他年少人。"]'),
('e4e7c726-dbf6-424e-b9cc-a391f9253df8','營閑事','白居易','唐','唐诗','tang','','[]','自笑營閑事，從朝到日斜。',48,'全唐诗/poet.tang.24000.json','["自笑營閑事，從朝到日斜。", "澆畦引泉脉，掃徑避蘭芽。", "暖變牆衣色，晴催木筆花。", "桃根知酒渴，晚送一甌茶。"]'),
('62eb98b5-065c-4cc6-bc2b-0e890b605597','感春','白居易','唐','唐诗','tang','','[]','老思不禁春，風光照眼新。',48,'全唐诗/poet.tang.24000.json','["老思不禁春，風光照眼新。", "花房紅鳥觜，池浪碧魚鱗。", "倚櫂誰爲伴，持杯自問身。", "心情多少在，六十二三人。"]'),
('610ceff4-26bd-4de4-a825-c3ec363646b0','春池上戲贈李郎中','白居易','唐','唐诗','tang','','[]','滿池春水何人愛，唯我迴看指似君。',32,'全唐诗/poet.tang.24000.json','["滿池春水何人愛，唯我迴看指似君。", "直似挼藍新汁色，與君南宅染羅裙。"]'),
('54a19f5c-7a5c-4588-bbd1-9a354bea5771','翫半開花贈皇甫郎中','白居易','唐','唐诗','tang','','[]','勿訝春來晚，無嫌花發遲。',168,'全唐诗/poet.tang.24000.json','["勿訝春來晚，無嫌花發遲。", "人憐全盛日，我愛半開時。", "紫蠟黏爲蔕，紅蘇點作蕤。", "成都新夾纈，梁漢碎臙脂。", "樹杪真珠顆，牆頭小女兒。", "淺深妝駮落，高下火參差。", "蝶戲爭香朵，鶯啼選穩枝。", "好教郎作伴，合共酒相隨。", "醉翫無勝此，狂嘲更讓誰。", "猶殘少年興，不似老人詩。", "西日憑輕照，東風莫殺吹。", "明朝應爛熳，後夜更離披。", "林下遙相憶，尊前闇有期。", "銜杯嚼蘂思，唯我與君知。"]'),
('d88b2b27-bbf9-45fc-94dd-952f28b7332b','池邊','白居易','唐','唐诗','tang','','[]','柳老香絲宛，荷新鈿扇圓。',48,'全唐诗/poet.tang.24000.json','["柳老香絲宛，荷新鈿扇圓。", "殘春深樹裏，斜日小樓前。", "醉遣收杯杓，閑聽理管弦。", "池邊更無事，看補採蓮船。"]'),
('f1932ac3-5151-438b-8e51-c7b638b7578d','家釀新熟每嘗輙醉妻姪等勸令少飲因成長句以諭之','白居易','唐','唐诗','tang','','[]','君應怪我朝朝飲，不說向君君不知。',64,'全唐诗/poet.tang.24000.json','["君應怪我朝朝飲，不說向君君不知。", "身上幸無疼痛處，甕頭正是撇嘗時。", "劉妻勸諫夫休醉，王姪分疎叔不癡。", "六十三翁頭雪白，假如醒黠欲何爲。"]'),
('cde1e7c5-aa1b-45a2-b5a3-7be04b7bd112','送常秀才下第東歸','白居易','唐','唐诗','tang','','[]','東歸多旅恨，西上少知音。',48,'全唐诗/poet.tang.24000.json','["東歸多旅恨，西上少知音。", "寒食看花眼，春風落日心。", "百憂當二月，一醉直千金。", "到處公卿席，無辭酒醆深。"]'),
('cb0b08fe-4d26-4678-ad04-f90d1d3f5d3d','且遊','白居易','唐','唐诗','tang','','[]','手裏一杯滿，心中百事休。',48,'全唐诗/poet.tang.24000.json','["手裏一杯滿，心中百事休。", "春應唯仰醉，老更不禁愁。", "弄水迴船尾，尋花信馬頭。", "眼看筋力減，遊得且須遊。"]'),
('37ddd661-ba74-4582-b457-e4ad52fcad67','題王家莊臨水柳亭','白居易','唐','唐诗','tang','','[]','弱柳緣堤種，虛亭壓水開。',48,'全唐诗/poet.tang.24000.json','["弱柳緣堤種，虛亭壓水開。", "條疑逐風去，波欲上階來。", "翠羽偷魚入，紅腰學舞迴。", "春愁正無緒，爭不盡殘杯。"]'),
('07c4f938-715a-4f1d-85ee-b8dadf2c60cb','題令狐家木蘭花','白居易','唐','唐诗','tang','','[]','膩如玉指塗朱粉，光似金刀剪紫霞。',32,'全唐诗/poet.tang.24000.json','["膩如玉指塗朱粉，光似金刀剪紫霞。", "從此時時春夢裏，應添一樹女郎花。"]'),
('c07c47a6-f2ca-4120-a83e-cf30b1b2fea8','拜表迴閑遊','白居易','唐','唐诗','tang','','[]','玉珮金章紫花綬，紵衫藤帶白綸巾。',80,'全唐诗/poet.tang.24000.json','["玉珮金章紫花綬，紵衫藤帶白綸巾。", "晨興拜表稱朝士，晚出遊山作野人。", "達磨傳心令息念，玄元留意遣同塵。", "八關淨戒齋銷日，一曲狂歌醉送春。", "酒肆法堂方丈室，其間豈是兩般身。"]'),
('177aa578-cc9d-41ac-8cb5-a7a9ec8ccb25','西街渠中種蓮疊石頗有幽致偶題小樓','白居易','唐','唐诗','tang','','[]','朱檻低牆上，清流小閣前。',72,'全唐诗/poet.tang.24000.json','["朱檻低牆上，清流小閣前。", "雇人栽菡萏，買石造潺湲。", "影落江心月，聲移谷口泉。", "閑看捲簾坐，醉聽掩窗眠。", "路笑淘官水，家愁費料錢。", "是非君莫問，一對一翛然。"]'),
('2ca1001f-fdbb-40f3-8338-ded648912642','晚春閑居楊工部寄詩楊常州寄茶同到因以長句荅之','白居易','唐','唐诗','tang','','[]','宿酲寂寞眠初起，春意闌珊日又斜。',64,'全唐诗/poet.tang.24000.json','["宿酲寂寞眠初起，春意闌珊日又斜。", "勸我加餐因早笋，恨人休醉是殘花。", "悶吟工部新來句，渴飲毗陵遠到茶。", "兄弟東西官職冷，門前車馬向誰家。"]'),
('fa1519b2-9672-4180-bb9b-ee784546df6a','玉泉寺南三里澗下多深紅躑躅繁豔殊常感惜題詩以示遊者','白居易','唐','唐诗','tang','','[]','玉泉南澗花奇怪，不似花叢似火堆。',64,'全唐诗/poet.tang.24000.json','["玉泉南澗花奇怪，不似花叢似火堆。", "今日多情唯我到，每年無故爲誰開。", "寧辭辛苦行三里，更與留連飲兩杯。", "猶有一般辜負事，不將歌舞管弦來。"]'),
('3086dd76-b86f-4ecc-8047-b708078596d0','早服雲母散','白居易','唐','唐诗','tang','','[]','曉服雲英漱井華，寥然身若在煙霞。',64,'全唐诗/poet.tang.24000.json','["曉服雲英漱井華，寥然身若在煙霞。", "藥銷日晏三匙飯，酒渴春深一椀茶。", "每夜坐禪觀水月，有時行醉翫風花。", "淨名事理人難解，身不出家心出家。"]'),
('14488040-d6a1-4e2c-b698-f84d179590ad','三月晦日晚聞鳥聲','白居易','唐','唐诗','tang','','[]','晚來林鳥語殷勤，似惜風光說向人。',48,'全唐诗/poet.tang.24000.json','["晚來林鳥語殷勤，似惜風光說向人。", "遣脫破袍勞報煖，催沽美酒敢辭貧。", "聲聲勸醉應須醉，一歲唯殘半日春。"]'),
('b45a7650-d847-4b34-94dc-681030e0e0f1','早夏遊平原迴','白居易','唐','唐诗','tang','','[]','夏早日初長，南風草木香。',48,'全唐诗/poet.tang.24000.json','["夏早日初長，南風草木香。", "肩輿頗平穩，澗路甚清涼。", "紫蕨行看採，青梅旋摘嘗。", "療飢兼解渴，一醆冷雲漿。"]'),
('52bd5ff2-6ac0-49c0-9312-c428f58d2a95','宿天竺寺迴','白居易','唐','唐诗','tang','','[]','野寺經三宿，都城復一還。',48,'全唐诗/poet.tang.24000.json','["野寺經三宿，都城復一還。", "家仍念婚嫁，身尚繫官班。", "蕭灑秋臨水，沈吟晚下山。", "長閑猶未得，逐日且偷閑。"]'),
('9e5a0294-dcd3-4a51-b605-99cae1709a04','侍中晉公欲到東洛先蒙書問期宿龍門思往感今輙獻長句','白居易','唐','唐诗','tang','','[]','昔蒙興化池頭送，今許龍門潭上期。',64,'全唐诗/poet.tang.24000.json','["昔蒙興化池頭送，今許龍門潭上期。", "聚散但慙長見念，榮枯安敢道相思。", "功成名遂來雖久，雲臥山遊去未遲。", "聞說風情筋力在，只如初破蔡州時。"]'),
('1be4afb0-31a4-43b3-8702-68502042b8f6','奉和晉公侍中蒙除留守行及洛師感悅發中斐然成詠之作','白居易','唐','唐诗','tang','','[]','鸞鳳翺翔在寥廓，貂蟬蕭灑出埃塵。',64,'全唐诗/poet.tang.24000.json','["鸞鳳翺翔在寥廓，貂蟬蕭灑出埃塵。", "致成堯舜昇平代，收得夔龍強健身。", "拋擲功名還史冊，分張歡樂與交親。", "商山老皓雖休去，終是留侯門下人。"]'),
('bb1f1e00-a42b-4713-9702-7dacf03860d7','送劉五司馬赴任硤州兼寄崔使君','白居易','唐','唐诗','tang','','[]','位下才高多怨天，劉兄道勝獨恬然。',64,'全唐诗/poet.tang.24000.json','["位下才高多怨天，劉兄道勝獨恬然。", "貧於揚子兩三倍，老過榮公六七年。", "筆硯莫拋留壓案，簞瓢從陋也銷錢。", "郡丞自合當優禮，何況夷陵太守賢。"]'),
('d4e7c27d-8474-4b48-9946-fe4e19cb4379','菩提寺上方晚眺','白居易','唐','唐诗','tang','','[]','樓閣高低樹淺深，山光水色暝沈沈。',64,'全唐诗/poet.tang.24000.json','["樓閣高低樹淺深，山光水色暝沈沈。", "嵩煙半卷青綃幕，伊浪平鋪綠綺衾。", "飛鳥滅時宜極目，遠風來處好開襟。", "誰知不離簪纓內，長得逍遙自在心。"]'),
('42f52081-6d77-4413-b7d7-1d7d7c8e9ad8','楊柳枝詞八首 一','白居易','唐','唐诗','tang','','[]','六么水調家家唱，白雪梅花處處吹。',32,'全唐诗/poet.tang.24000.json','["六么水調家家唱，白雪梅花處處吹。", "古歌舊曲君休聽，聽取新翻楊柳枝。"]'),
('08e1212d-c37a-4011-a548-5595f6aac7ad','楊柳枝詞八首 二','白居易','唐','唐诗','tang','','[]','陶令門前四五樹，亞夫營裏百千條。',32,'全唐诗/poet.tang.24000.json','["陶令門前四五樹，亞夫營裏百千條。", "何似東都正二月，黃金枝映洛陽橋。"]'),
('475610ec-d8d1-44d1-b645-842f2ca5b2db','楊柳枝詞八首 三','白居易','唐','唐诗','tang','','[]','依依褭褭復青青，句引春風無限情。',32,'全唐诗/poet.tang.24000.json','["依依褭褭復青青，句引春風無限情。", "白雪花繁空撲地，綠絲條弱不勝鶯。"]'),
('e76a50a6-101d-489a-aecb-1ced6e20464a','楊柳枝詞八首 四','白居易','唐','唐诗','tang','','[]','紅板江橋青酒旗，館娃宮暖日斜時。',32,'全唐诗/poet.tang.24000.json','["紅板江橋青酒旗，館娃宮暖日斜時。", "可憐雨歇東風定，萬樹千條各自垂。"]'),
('fffe01f0-655e-428e-8ec5-5d5e98ea9156','楊柳枝詞八首 五','白居易','唐','唐诗','tang','','[]','蘇州楊柳任君誇，更有錢唐勝館娃。',32,'全唐诗/poet.tang.24000.json','["蘇州楊柳任君誇，更有錢唐勝館娃。", "若解多情尋小小，綠楊深處是蘇家。"]'),
('88c89108-51a2-4733-9ae8-914231a94c3a','楊柳枝詞八首 六','白居易','唐','唐诗','tang','','[]','蘇家小女舊知名，楊柳風前別有情。',32,'全唐诗/poet.tang.24000.json','["蘇家小女舊知名，楊柳風前別有情。", "剝條盤作銀環樣，卷葉吹爲玉笛聲。"]'),
('1a452cfa-7b61-466c-ac7b-908dfd3f0c8d','楊柳枝詞八首 七','白居易','唐','唐诗','tang','','[]','葉含濃露如啼眼，枝褭輕風似舞腰。',32,'全唐诗/poet.tang.24000.json','["葉含濃露如啼眼，枝褭輕風似舞腰。", "小樹不禁攀折苦，乞君留取兩三條。"]'),
('8b1652de-4048-4d88-b8ed-d91d4ec5ae6a','楊柳枝詞八首 八','白居易','唐','唐诗','tang','','[]','人言柳葉似愁眉，更有愁腸似柳絲。',32,'全唐诗/poet.tang.24000.json','["人言柳葉似愁眉，更有愁腸似柳絲。", "柳絲挽斷腸牽斷，彼此應無續得期。"]'),
('9a5c31af-6696-45f0-90d8-4f3b877a3524','讀老子','白居易','唐','唐诗','tang','','[]','言者不如知者默，此語吾聞於老君。',32,'全唐诗/poet.tang.24000.json','["言者不如知者默，此語吾聞於老君。", "若道老君是知者，緣何自著五千文。"]'),
('d6cadd52-2770-4210-86d3-3c17a3da94db','讀莊子','白居易','唐','唐诗','tang','','[]','莊生齊物同歸一，我道同中有不同。',32,'全唐诗/poet.tang.24000.json','["莊生齊物同歸一，我道同中有不同。", "遂性逍遙雖一致，鶯凰終挍勝蛇蟲。"]'),
('811ac29a-a3fb-420c-b682-8b73a150ae00','讀禪經','白居易','唐','唐诗','tang','','[]','須知諸相皆非相，若住無餘却有餘。',64,'全唐诗/poet.tang.24000.json','["須知諸相皆非相，若住無餘却有餘。", "言下忘言一時了，夢中說夢兩重虛。", "空花豈得兼求果，陽燄如何更覓魚。", "攝動是禪禪是動，不禪不動即如如。"]'),
('e5813234-0a95-457a-b80e-bc8fe0132b1f','感興二首 一','白居易','唐','唐诗','tang','','[]','吉凶禍福有來由，但要深知不要憂。',64,'全唐诗/poet.tang.24000.json','["吉凶禍福有來由，但要深知不要憂。", "只見火光燒潤屋，不聞風浪覆虛舟。", "名爲公器無多取，利是身災合少求。", "雖異匏瓜難不食，大都食足早宜休。"]'),
('79cceb4a-0273-4d5f-a774-01311bd4c67c','感興二首 二','白居易','唐','唐诗','tang','','[]','魚能深入寧憂釣，鳥解高飛豈觸羅。',64,'全唐诗/poet.tang.24000.json','["魚能深入寧憂釣，鳥解高飛豈觸羅。", "熱處先爭炙手去，悔時其奈噬臍何。", "尊前誘得猩猩血，幕上偷安鷰鷰窠。", "我有一言君記取，世間自取苦人多。"]'),
('fdebad6c-77b2-4bf0-8716-9cda25ab05c2','問鶴','白居易','唐','唐诗','tang','','[]','烏鳶爭食雀爭窠，獨立池邊風雪多。',32,'全唐诗/poet.tang.24000.json','["烏鳶爭食雀爭窠，獨立池邊風雪多。", "盡日蹋冰翹一足，不鳴不動意如何。"]'),
('685e910a-3468-4b42-9fca-9e1fe02a1f5f','代鶴荅','白居易','唐','唐诗','tang','','[]','鷹爪攫雞雞肋折，鶻拳蹴雁雁頭垂。',32,'全唐诗/poet.tang.24000.json','["鷹爪攫雞雞肋折，鶻拳蹴雁雁頭垂。", "何如歛翅水邊立，飛上雲松棲穩枝。"]'),
('9df41e23-1cbf-47da-9214-3a9b5a35f2de','閑臥有所思二首 一','白居易','唐','唐诗','tang','','[]','向夕搴簾臥枕琴，微涼入戶起開襟。',64,'全唐诗/poet.tang.24000.json','["向夕搴簾臥枕琴，微涼入戶起開襟。", "偶因明月清風夜，忽想遷臣逐客心。", "何處投荒初恐懼，誰人繞澤正悲吟。", "始知洛下分司坐，一日安閑直萬金。"]'),
('ae6411f5-1a30-4c98-95ba-9c1302f91f54','閑臥有所思二首 二','白居易','唐','唐诗','tang','','[]','權門要路是身災，散地閑居少禍胎。',64,'全唐诗/poet.tang.24000.json','["權門要路是身災，散地閑居少禍胎。", "今日憐君嶺南去，當時笑我洛中來。", "蟲全性命緣無毒，木盡天年爲不才。", "大抵吉凶多自致，李斯一去二疎迴。"]'),
('b0947d7f-1d18-4df1-8401-9c1ad0d99d24','喜閑','白居易','唐','唐诗','tang','','[]','蕭灑伊嵩下，優游黃綺間。',72,'全唐诗/poet.tang.24000.json','["蕭灑伊嵩下，優游黃綺間。", "未曾一日悶，已得六年閑。", "魚鳥爲徒侶，煙霞是往還。", "伴僧禪閉目，迎客笑開顏。", "興發宵遊寺，慵時晝掩關。", "夜來風月好，悔不宿香山。"]'),
('a29b4266-aa15-49fb-a60f-7c91d6b81d2a','詩酒琴人例多薄命予酷好三事雅當此科而所得已多爲幸斯甚偶成狂詠聊寫媿懷','白居易','唐','唐诗','tang','','[]','愛琴愛酒愛詩客，多賤多窮多苦辛。',96,'全唐诗/poet.tang.24000.json','["愛琴愛酒愛詩客，多賤多窮多苦辛。", "中散步兵終不貴，孟郊張籍過於貧。", "一之已歎關於命，三者何堪併在身。", "只合飄零隨草木，誰教凌厲出風塵。", "榮名厚祿二千石，樂飲閑遊三十春。", "何得無厭時咄咄，猶言薄命不如人。"]'),
('b5b03a24-c565-4079-9afa-2f50bc3cf9f5','寄明州于駙馬使君三絕句 一','白居易','唐','唐诗','tang','','[]','有花有酒有笙歌，其奈難逢親故何。',32,'全唐诗/poet.tang.24000.json','["有花有酒有笙歌，其奈難逢親故何。", "近海饒風春足雨，白鬚太守悶時多。"]'),
('aeefe783-e69b-4308-ae21-75d203b1b88e','寄明州于駙馬使君三絕句 二','白居易','唐','唐诗','tang','','[]','平陽音樂隨都尉，留滯三年在浙東。',32,'全唐诗/poet.tang.24000.json','["平陽音樂隨都尉，留滯三年在浙東。", "吳越聲邪無法用，莫教偷入管弦中。"]'),
('fca155db-9375-4cd8-be50-2fe03e735c2c','寄明州于駙馬使君三絕句 三','白居易','唐','唐诗','tang','','[]','何郎小妓歌喉好，嚴老呼爲一串珠。',32,'全唐诗/poet.tang.24000.json','["何郎小妓歌喉好，嚴老呼爲一串珠。", "海味腥鹹損聲氣，聽看猶得斷腸無。"]'),
('f5caec4d-8c93-4287-a962-0f0eb8959b07','閑臥','白居易','唐','唐诗','tang','','[]','薄食當齋戒，散班同隱淪。',48,'全唐诗/poet.tang.24000.json','["薄食當齋戒，散班同隱淪。", "佛容爲弟子，天許作閑人。", "唯置牀臨水，都無物近身。", "清風散髮臥，兼不要紗巾。"]'),
('6feb0593-dbb7-44b8-8d05-8eb033c4e83c','春早秋初因時即事兼寄浙東李侍郎','白居易','唐','唐诗','tang','','[]','春早秋初晝夜長，可憐天氣好年光。',96,'全唐诗/poet.tang.24000.json','["春早秋初晝夜長，可憐天氣好年光。", "和風細動簾帷暖，清露微凝枕簟涼。", "窗下曉眠初減被，池邊晚坐乍移牀。", "閑從蕙草侵堦綠，靜任槐花滿地黃。", "理曲管弦聞後院，熨衣燈火映深房。", "四時新景何人別，遙憶多情李侍郎。"]'),
('19412a2f-f0b9-4ab8-ba03-9427a833eb2c','新秋喜涼','白居易','唐','唐诗','tang','','[]','過得炎蒸月，尤宜老病身。',48,'全唐诗/poet.tang.24000.json','["過得炎蒸月，尤宜老病身。", "衣裳朝不潤，枕簟夜相親。", "樓月纖纖早，波風褭褭新。", "光陰與時節，先感是詩人。"]'),
('a03a42e2-ce4f-4967-aaa5-15268d718a0a','初夏閑吟兼呈韋賓客','白居易','唐','唐诗','tang','','[]','孟夏清和月，東都閑散官。',72,'全唐诗/poet.tang.24000.json','["孟夏清和月，東都閑散官。", "體中無病痛，眼下未飢寒。", "世事聞常悶，交游見即歡。", "杯觴留客切，妓樂取人寬。", "雪鬢隨身老，雲心著處安。", "此中殊有味，試說向君看。"]'),
('f1c1c298-ba3d-46ba-b70e-512dd83f591b','哭崔二十四常侍','白居易','唐','唐诗','tang','','[]','貂冠初別九重門，馬鬣新封四尺墳。',64,'全唐诗/poet.tang.24000.json','["貂冠初別九重門，馬鬣新封四尺墳。", "薤露歌詞非白雪，旌銘官爵是浮雲。", "伯倫每置隨身鍤，元亮先爲自祭文。", "莫道高風無繼者，一千年內有崔君。"]'),
('e441d9a0-276e-435e-bf64-95d16696a10e','奉酬侍中夏中雨後遊城南莊見示八韻','白居易','唐','唐诗','tang','','[]','島樹間林巒，雲收雨氣殘。',96,'全唐诗/poet.tang.24000.json','["島樹間林巒，雲收雨氣殘。", "四山嵐色重，五月水聲寒。", "老鶴兩三隻，新篁千萬竿。", "化成天竺寺，移得子陵灘。", "心覺閑彌貴，身緣健更歡。", "帝將風后待，人作謝公看。", "甪里年雖老，高陽興未闌。", "佳辰不見召，爭免趂杯盤。"]'),
('3338f611-7892-49c6-8377-8ec17424d141','送兖州崔大夫駙馬赴鎮','白居易','唐','唐诗','tang','','[]','戚里誇爲賢駙馬，儒家認作好詩人。',32,'全唐诗/poet.tang.24000.json','["戚里誇爲賢駙馬，儒家認作好詩人。", "魯侯不得辜風景，沂水年年有暮春。"]'),
('65b6b15c-d619-482b-a55d-9a32396277dc','少年問','白居易','唐','唐诗','tang','','[]','少年怪我問如何，何事朝朝醉復歌。',32,'全唐诗/poet.tang.24000.json','["少年怪我問如何，何事朝朝醉復歌。", "號作樂天應不錯，憂愁時少樂時多。"]'),
('b4517dc3-3429-4bc0-8234-31dc271d0f4d','問少年','白居易','唐','唐诗','tang','','[]','千首詩堆青玉案，十分酒寫白金盂。',32,'全唐诗/poet.tang.24000.json','["千首詩堆青玉案，十分酒寫白金盂。", "迴頭却問諸年少，作箇狂夫得了無。"]'),
('b96a1832-961d-48f5-9004-7ea944e8c071','代琵琶弟子謝女師曹供奉寄新調弄譜','白居易','唐','唐诗','tang','','[]','琵琶師在九重城，忽得書來喜且驚。',64,'全唐诗/poet.tang.24000.json','["琵琶師在九重城，忽得書來喜且驚。", "一紙展看非舊譜，四弦翻出是新聲。", "蕤賓掩抑嬌多怨，散水玲瓏峭更清。", "珠顆淚霑金捍撥，紅妝弟子不勝情。"]'),
('c93627bc-9bbd-4f06-8ab1-e579e39b75f5','代林園戲贈','白居易','唐','唐诗','tang','','[]','南院今秋遊宴少，西坊近日往來頻。',32,'全唐诗/poet.tang.24000.json','["南院今秋遊宴少，西坊近日往來頻。", "假如宰相池亭好，作客何如作主人。"]'),
('29f1cf01-40ac-4201-b7dd-0f429a29eb86','戲荅林園','白居易','唐','唐诗','tang','','[]','豈獨西坊來往頻，偷閑處處作遊人。',32,'全唐诗/poet.tang.24000.json','["豈獨西坊來往頻，偷閑處處作遊人。", "衡門雖是棲遲地，不可終朝鏁老身。"]'),
('413b97cc-f71d-4a93-8b36-10ef468ce45c','重戲贈','白居易','唐','唐诗','tang','','[]','集賢池館從他盛，履道林亭勿自輕。',32,'全唐诗/poet.tang.24000.json','["集賢池館從他盛，履道林亭勿自輕。", "往往歸來嫌窄小，年年爲主莫無情。"]'),
('b68bafd6-8cc5-42dd-978a-420b842baf8a','重戲荅','白居易','唐','唐诗','tang','','[]','小水低亭自可親，大池高館不關身。',32,'全唐诗/poet.tang.24000.json','["小水低亭自可親，大池高館不關身。", "林園莫妬裴家好，憎故憐新豈是人。"]'),
('765a8e0b-9798-438c-b806-3396a6c80d33','早秋登天宮寺閣贈諸客','白居易','唐','唐诗','tang','','[]','天宮閣上醉蕭辰，絲管閑聽酒慢巡。',32,'全唐诗/poet.tang.24000.json','["天宮閣上醉蕭辰，絲管閑聽酒慢巡。", "爲向涼風清景道，今朝屬我兩三人。"]'),
('38434da3-f501-498a-a4f7-40767d11a417','曉上天津橋閑望偶逢盧郎中張員外攜酒同傾','白居易','唐','唐诗','tang','','[]','上陽宮裏曉鐘後，天津橋頭殘月前。',64,'全唐诗/poet.tang.24000.json','["上陽宮裏曉鐘後，天津橋頭殘月前。", "空闊境疑非下界，飄颻身似在寥天。", "星河隱映初生日，樓閣蔥蘢半出煙。", "此處相逢傾一醆，始知地上有神仙。"]'),
('eff11311-6798-465d-b2c3-270f8c2bf7ce','八月十五日夜同諸客翫月','白居易','唐','唐诗','tang','','[]','月好共傳唯此夜，境閑皆道是東都。',64,'全唐诗/poet.tang.24000.json','["月好共傳唯此夜，境閑皆道是東都。", "嵩山表裏千重雪，洛水高低兩顆珠。", "清景難逢宜愛惜，白頭相勸強歡娛。", "誠知亦有來年會，保得晴明強健無。"]'),
('ae6d62ff-dd7a-493c-a0a8-63b385f97408','對晚開夜合花贈皇甫郎中','白居易','唐','唐诗','tang','','[]','移晚校一月，花遲過半年。',48,'全唐诗/poet.tang.24000.json','["移晚校一月，花遲過半年。", "紅開杪秋日，翠合欲昏天。", "白露滴未死，涼風吹更鮮。", "後時誰肯顧，唯我與君憐。"]'),
('0f5acfdd-df6d-4aa5-a42b-4fe3d965df3a','醉遊平泉','白居易','唐','唐诗','tang','','[]','狂歌箕踞酒尊前，眼不看人面向天。',32,'全唐诗/poet.tang.24000.json','["狂歌箕踞酒尊前，眼不看人面向天。", "洛客最閑唯有我，一年四度到平泉。"]'),
('cae0f324-167e-4c8f-abf0-8c19e0ff7138','題贈平泉韋徵君拾遺','白居易','唐','唐诗','tang','','[]','箕潁千年後，唯君得古風。',48,'全唐诗/poet.tang.24000.json','["箕潁千年後，唯君得古風。", "位留丹陛上，身入白雲中。", "躁靜心相背，高低跡不同。", "籠雞與梁燕，不信有冥鴻。"]'),
('e2046d37-f9c4-40ed-a327-e10c26f7de43','酬皇甫郎中對新菊花見憶','白居易','唐','唐诗','tang','','[]','愛菊高人吟逸韻，悲秋病客感衰懷。',64,'全唐诗/poet.tang.24000.json','["愛菊高人吟逸韻，悲秋病客感衰懷。", "黃花助興方攜酒，紅葉添愁正滿堦。", "居士葷腥今已斷，仙郎杯杓爲誰排。", "媿君相憶東籬下，擬廢重陽一日齋。"]'),
('917f5f0e-0271-4135-8e6f-9d4b070e51a4','夜宴醉後留獻裴侍中','白居易','唐','唐诗','tang','','[]','九燭臺前十二姝，主人留醉任歡娛。',64,'全唐诗/poet.tang.24000.json','["九燭臺前十二姝，主人留醉任歡娛。", "翩翻舞袖雙飛蝶，宛轉歌聲一索珠。", "坐久欲醒還酩酊，夜深初散又踟躕。", "南山賓客東山妓，此會人間曾有無。"]'),
('6b141253-20f6-4fed-a0e4-7f682b08493c','和韋庶子遠坊赴宴未夜先歸之作兼呈裴員外','白居易','唐','唐诗','tang','','[]','促席留歡日未曛，遠坊歸思已紛紛。',64,'全唐诗/poet.tang.24000.json','["促席留歡日未曛，遠坊歸思已紛紛。", "無妨按轡行乘月，何必逃杯走似雲。", "銀燭忍拋楊柳曲，金鞍潛送石榴裙。", "到時常晚歸時早，笑樂三分校一分。"]'),
('0e7a1a50-bd14-4798-a5e3-91fce0f78b55','集賢池荅侍中問','白居易','唐','唐诗','tang','','[]','主人晚入皇城宿，問客裴回何所須。',32,'全唐诗/poet.tang.24000.json','["主人晚入皇城宿，問客裴回何所須。", "池月幸閑無用處，今宵能借客遊無。"]'),
('aaac8550-c911-445a-90c3-9746fbd61551','楊柳枝二十韻','白居易','唐','唐诗','tang','','[]','小妓攜桃葉，新聲蹋柳枝。',240,'全唐诗/poet.tang.24000.json','["小妓攜桃葉，新聲蹋柳枝。", "妝成剪燭後，醉起拂衫時。", "繡履嬌行緩，花筵笑上遲。", "身輕委迴雪，羅薄透凝脂。", "笙引簧頻煖，箏催柱數移。", "樂童翻怨調，才子與妍詞。", "便想人如樹，先將髮比絲。", "風條搖兩帶，煙葉貼雙眉。", "口動櫻桃破，鬟低翡翠垂。", "枝柔腰嫋娜，荑嫩手葳蕤。", "唳鶴啨呼侶，哀猨夜呌兒。", "玉敲音歷歷，珠貫字纍纍。", "袖爲收聲點，釵因赴節遺。", "重重遍頭別，一一拍心知。", "塞北愁攀折，江南苦別離。", "黃遮金谷岸，綠映杏園池。", "春惜芳華好，秋憐顏色衰。", "取來歌裏唱，勝向笛中吹。", "曲罷那能別，情多不自持。", "纏頭無別物，一首斷腸詩。"]'),
('4cce0fc7-6785-4863-a4f6-e42c4ff4dcad','荅皇甫十郎中秋深酒熟見憶','白居易','唐','唐诗','tang','','[]','煙景冷蒼茫，秋深夜夜霜。',72,'全唐诗/poet.tang.24000.json','["煙景冷蒼茫，秋深夜夜霜。", "爲思池上酌，先覺甕頭香。", "未暇傾巾漉，還應染指嘗。", "醍醐慙氣味，琥珀讓晶光。", "若許陪歌席，須容散道場。", "月終齋戒畢，猶及菊花黃。"]'),
('10041b70-4ba3-4e72-80b5-18902f69bbfe','老去','白居易','唐','唐诗','tang','','[]','老去媿妻兒，冬來有勸詞。',48,'全唐诗/poet.tang.24000.json','["老去媿妻兒，冬來有勸詞。", "煖寒從飲酒，衝冷少吟詩。", "戰勝心還壯，齋勤體校羸。", "由來世間法，損益合相隨。"]'),
('cc2ca4c0-f171-462a-8c54-8c8fbe0e6212','送宗實上人遊江南','白居易','唐','唐诗','tang','','[]','忽辭洛下緣何事，擬向江南住幾時。',32,'全唐诗/poet.tang.24000.json','["忽辭洛下緣何事，擬向江南住幾時。", "每過渡頭應問法，無妨菩薩是船師。"]'),
('3e6fad8f-4c48-46ad-ba13-b714aa6de458','和同州楊侍郎誇柘枝見寄','白居易','唐','唐诗','tang','','[]','細吟馮翊使君詩，憶作餘杭太守時。',32,'全唐诗/poet.tang.24000.json','["細吟馮翊使君詩，憶作餘杭太守時。", "君有一般輸我事，柘枝看校十年遲。"]'),
('c2c80390-e330-46f5-ba9d-7abdd936d2d7','冬初酒熟二首 一','白居易','唐','唐诗','tang','','[]','霜繁脆庭柳，風利剪池荷。',48,'全唐诗/poet.tang.24000.json','["霜繁脆庭柳，風利剪池荷。", "月色曉彌苦，鳥聲寒更多。", "秋懷久寥落，冬計又如何。", "一甕新醅酒，萍浮春水波。"]'),
('02995350-424f-4e4b-ba6d-caa33f31f35e','冬初酒熟二首 二','白居易','唐','唐诗','tang','','[]','酒熟無客來，因成獨酌謠。',48,'全唐诗/poet.tang.24000.json','["酒熟無客來，因成獨酌謠。", "人間老黃綺，地上散松喬。", "忽忽醒還醉，悠悠暮復朝。", "殘年多少在，盡付此中銷。"]'),
('817643e5-6280-4dd3-91fd-b9f3754ba08f','送姚杭州赴任因思舊遊二首 一','白居易','唐','唐诗','tang','','[]','與君細話杭州事，爲我留心莫等閑。',64,'全唐诗/poet.tang.24000.json','["與君細話杭州事，爲我留心莫等閑。", "閭里固宜勤撫恤，樓臺亦要數躋攀。", "笙歌縹緲虛空裏，風月依稀夢想間。", "且喜詩人重管領，遙飛一醆賀江山。"]'),
('c8ebc364-36ae-466d-a19e-b2d0d443cf32','送姚杭州赴任因思舊遊二首 二','白居易','唐','唐诗','tang','','[]','渺渺錢唐路幾千，想君到後事依然。',64,'全唐诗/poet.tang.24000.json','["渺渺錢唐路幾千，想君到後事依然。", "靜逢竺寺猨偷橘，閑看蘇家女採蓮。", "故妓數人憑問詢，新詩兩首倩留傳。", "舍人雖健無多興，老挍當時八九年。"]'),
('0b59cd4b-3572-4072-8777-1c1a47c2c023','寄李相公','白居易','唐','唐诗','tang','','[]','漸老只謀歡，雖貧不要官。',24,'全唐诗/poet.tang.24000.json','["漸老只謀歡，雖貧不要官。", "唯求造化力，試爲駐春看。"]'),
('f03297e4-dd0e-4670-821d-f0ca9b131bf6','冬日平泉路晚歸','白居易','唐','唐诗','tang','','[]','山路難行日易斜，煙村霜樹欲棲鵶。',32,'全唐诗/poet.tang.24000.json','["山路難行日易斜，煙村霜樹欲棲鵶。", "夜歸不到應閑事，熱飲三杯即是家。"]'),
('1618aa3c-ba65-42bf-bf15-f2dc0bd4e3be','利仁北街作','白居易','唐','唐诗','tang','','[]','草色斑斑春雨晴，利仁坊北面西行。',32,'全唐诗/poet.tang.24000.json','["草色斑斑春雨晴，利仁坊北面西行。", "踟躕立馬緣何事，認得張家歌吹聲。"]'),
('de50d4b3-e65f-46d6-95ee-66b91218ba38','洛陽堰閑行','白居易','唐','唐诗','tang','','[]','洛陽堰上新晴日，長夏門前欲暮春。',32,'全唐诗/poet.tang.24000.json','["洛陽堰上新晴日，長夏門前欲暮春。", "遇酒即沽逢樹歇，七年此地作閑人。"]'),
('0f20c58f-34fd-4d11-8077-1dd67371f5f1','過永寧','白居易','唐','唐诗','tang','','[]','村杏野桃繁似雪，行人不醉爲誰開。',32,'全唐诗/poet.tang.24000.json','["村杏野桃繁似雪，行人不醉爲誰開。", "賴逢山縣盧明府，引我花前勸一杯。"]'),
('17236446-0d47-4960-b480-d0102ae38c27','往年稠桑曾喪白馬題詩廳壁今來尚存又復感懷更題絕句','白居易','唐','唐诗','tang','','[]','路傍埋骨蒿草合，壁上題詩塵蘚生。',32,'全唐诗/poet.tang.24000.json','["路傍埋骨蒿草合，壁上題詩塵蘚生。", "馬死七年猶悵望，自知無乃太多情。"]'),
('e8acfd47-6c2f-43f3-becb-7808bf2664fd','羅敷水','白居易','唐','唐诗','tang','','[]','野店東頭花落處，一條流水號羅敷。',32,'全唐诗/poet.tang.24000.json','["野店東頭花落處，一條流水號羅敷。", "芳魂豔骨知何處，春草茫茫墓亦無。"]'),
('9e0c7c1b-c750-45d5-858a-1110af4c9486','路逢青州王大夫赴鎮立馬贈別','白居易','唐','唐诗','tang','','[]','大斾擁金羈，書生得者稀。',48,'全唐诗/poet.tang.24000.json','["大斾擁金羈，書生得者稀。", "何勞問官職，豈不見光輝。", "赫赫人爭看，翩翩馬欲飛。", "不期前歲尹，駐節語依依。"]'),
('86b77fec-16af-43d7-a06b-19bcbcc17d93','和楊同州寒食乾坑會後聞楊工部欲到知予與工部有宿酲','白居易','唐','唐诗','tang','','[]','夜飲歸常晚，朝眠起更遲。',48,'全唐诗/poet.tang.24000.json','["夜飲歸常晚，朝眠起更遲。", "舉頭中酒後，引手索茶時。", "拂枕青長袖，欹簪白接䍦。", "宿酲無興味，先是肺神知。"]'),
('458b9118-24ec-4746-9920-1ad8adc5cb1d','和劉汝州酬侍中見寄長句因書集賢坊勝事戲而問之','白居易','唐','唐诗','tang','','[]','洛川汝海封畿接，履道集賢來往頻。',64,'全唐诗/poet.tang.24000.json','["洛川汝海封畿接，履道集賢來往頻。", "一復時程雖不遠，百餘步地更相親。", "朱門陪宴多投轄，青眼留歡任吐茵。", "聞道郡齋還有酒，花前月下對何人。"]'),
('3b020381-c590-4afd-b04c-460c3144b783','池上二絕 一','白居易','唐','唐诗','tang','','[]','山僧對棊坐，局上竹陰清。',24,'全唐诗/poet.tang.24000.json','["山僧對棊坐，局上竹陰清。", "映竹無人見，時聞下子聲。"]'),
('5bcc5f16-f5f4-4a49-bce5-f26630de8c4d','池上二絕 二','白居易','唐','唐诗','tang','','["\u513f\u7ae5", "\u751f\u6d3b"]','小娃撐小艇，偷採白蓮迴。',24,'全唐诗/poet.tang.24000.json','["小娃撐小艇，偷採白蓮迴。", "不解藏踪跡，浮萍一道開。"]'),
('e36f65b2-4927-4499-830f-233135ce9b5d','白羽扇','白居易','唐','唐诗','tang','','[]','素是自然色，圓因裁製功。',72,'全唐诗/poet.tang.24000.json','["素是自然色，圓因裁製功。", "颯如松起籟，飄似鶴翻空。", "盛夏不銷雪，終年無盡風。", "引秋生手裏，藏月入懷中。", "麈尾斑非疋，蒲葵陋不同。", "何人稱相對，清瘦白鬚翁。"]'),
('3d296a69-3ba9-40b7-8dfa-bff460c114c5','五月齋戒罷宴徹樂聞韋賓客皇甫郎中飲會亦稀又知欲攜酒饌出齋先以長句呈謝','白居易','唐','唐诗','tang','','[]','妓房匣鏡滿紅埃，酒庫封瓶生綠苔。',64,'全唐诗/poet.tang.24000.json','["妓房匣鏡滿紅埃，酒庫封瓶生綠苔。", "居士爾時緣護戒，車公何事亦停杯。", "散齋香火今朝散，開素盤筵後日開。", "隨意往還君莫怪，坐禪僧去飲徒來。"]'),
('81d91d07-a8b2-4bf0-8ee1-3f2abbce7715','閑園獨賞','白居易','唐','唐诗','tang','','[]','午後郊園靜，晴來景物新。',96,'全唐诗/poet.tang.24000.json','["午後郊園靜，晴來景物新。", "雨添山氣色，風借水精神。", "永日若爲度，獨遊何所親。", "仙禽狎君子，芳樹倚佳人。", "蟻鬬王爭肉，蝸移舍逐身。", "蝶雙知伉儷，蜂分見君臣。", "蠢蠕形雖小，逍遙性即均。", "不知鵬與鷃，相去幾微塵。"]'),
('e84630c7-371c-4204-9f1e-4d93c7889f9e','種柳三詠 一','白居易','唐','唐诗','tang','','[]','白頭種松桂，早晚見成林。',36,'全唐诗/poet.tang.24000.json','["白頭種松桂，早晚見成林。", "不及栽楊柳，明年便有陰。", "春風爲催促，副取老人心。"]'),
('62631936-3402-4661-8bca-9b5eceb5ffe4','種柳三詠 二','白居易','唐','唐诗','tang','','[]','從君種楊柳，夾水意如何。',36,'全唐诗/poet.tang.24000.json','["從君種楊柳，夾水意如何。", "準擬三年後，青絲拂綠波。", "仍教小樓上，對唱柳枝歌。"]'),
('b5b8f11c-2ed3-4ad7-b2e0-7040166204e0','種柳三詠 三','白居易','唐','唐诗','tang','','[]','更想五年後，千千條麴塵。',36,'全唐诗/poet.tang.24000.json','["更想五年後，千千條麴塵。", "路傍深映月，樓上闇藏春。", "愁殺閑遊客，聞歌不見人。"]'),
('4121f030-9f08-4f25-bfad-75391bc37196','偶吟','白居易','唐','唐诗','tang','','[]','好官病免曾三度，散地歸休已七年。',64,'全唐诗/poet.tang.24000.json','["好官病免曾三度，散地歸休已七年。", "老自退閑非世棄，貧蒙強健是天憐。", "韋荆南去留春服，王侍中來乞酒錢。", "便得一年生計足，與君美食復甘眠。"]'),
('e3a12b58-7384-49fd-891f-1d9df1828051','池上即事','白居易','唐','唐诗','tang','','[]','移牀避日依松竹，解帶當風挂薜蘿。',64,'全唐诗/poet.tang.24000.json','["移牀避日依松竹，解帶當風挂薜蘿。", "鈿砌池心綠蘋合，粉開花面白蓮多。", "久陰新霽宜絲管，苦熱初涼入綺羅。", "家醞瓶空人客絕，今宵爭奈月明何。"]'),
('7750e8b0-7892-416b-bc70-a2274b9edf6b','南塘暝興','白居易','唐','唐诗','tang','','[]','水色昏猶白，霞光闇漸無。',48,'全唐诗/poet.tang.24000.json','["水色昏猶白，霞光闇漸無。", "風荷搖破扇，波月動連珠。", "蟋蟀啼相應，鴛鴦宿不孤。", "小僮頻報夜，歸步尚踟躕。"]'),
('7a387188-018f-4cc1-8351-88120e851628','小宅','白居易','唐','唐诗','tang','','[]','小宅里閭接，疎籬雞犬通。',48,'全唐诗/poet.tang.24000.json','["小宅里閭接，疎籬雞犬通。", "渠分南巷水，窗借北家風。", "庾信園殊小，陶潛屋不豐。", "何勞問寬窄，寬窄在心中。"]'),
('da143c23-40dd-4b8a-8437-76f31b38060c','諭親友','白居易','唐','唐诗','tang','','[]','適情處處皆安樂，大抵園林勝市朝。',64,'全唐诗/poet.tang.24000.json','["適情處處皆安樂，大抵園林勝市朝。", "煩鬧榮華猶易過，優閑福祿更難銷。", "自憐老大宜疎散，却被交親歎寂寥。", "終日相逢不相見，兩心相去一何遙。"]'),
('65d32d60-871d-4b8d-9c85-1393eb8ef828','龍門送別皇甫澤州赴任韋山人南遊','白居易','唐','唐诗','tang','','[]','隼旟歸洛知何日，鶴駕還嵩莫過春。',32,'全唐诗/poet.tang.24000.json','["隼旟歸洛知何日，鶴駕還嵩莫過春。", "惆悵香山雲水冷，明朝便是獨遊人。"]'),
('f72d578e-203f-4d1a-9203-2e1e81dc7df5','劉蘇州寄釀酒糯米李浙東寄楊柳枝舞衫偶因嘗酒試衫輙成長句寄謝之','白居易','唐','唐诗','tang','','[]','柳枝謾蹋試雙袖，桑落初香嘗一杯。',64,'全唐诗/poet.tang.24000.json','["柳枝謾蹋試雙袖，桑落初香嘗一杯。", "金屑醅濃吳米釀，銀泥衫穩越娃裁。", "舞時已覺愁眉展，醉後仍教笑口開。", "慙媿故人憐寂寞，三千里外寄歡來。"]'),
('fd86f5e0-895f-4267-bf91-d62afe1c801d','詔授同州刺史病不赴任因詠所懷','白居易','唐','唐诗','tang','','[]','同州慵不去，此意復誰知。',96,'全唐诗/poet.tang.24000.json','["同州慵不去，此意復誰知。", "誠愛俸錢厚，其如身力衰。", "可憐病判案，何似醉吟詩。", "勞逸懸相遠，行藏決不疑。", "徒煩人勸諫，只合自尋思。", "白髮來無限，青山去有期。", "野心惟怕鬧，家口莫愁飢。", "賣却新昌宅，聊充送老資。"]'),
('01de01c2-2f5a-4ba3-a6f7-e896c00a3ee3','寄楊六侍郎','白居易','唐','唐诗','tang','','[]','西戶最榮君好去，左馮雖穩我慵來。',32,'全唐诗/poet.tang.24000.json','["西戶最榮君好去，左馮雖穩我慵來。", "秋風一筯鱸魚鱠，張翰搖頭喚不迴。"]'),
('a3351351-5e4a-4297-8b8c-77ca44b43ef9','韋七自太子賓客再除祕書監以長句賀而餞之','白居易','唐','唐诗','tang','','[]','離筵莫愴且同歡，共賀新恩拜舊官。',64,'全唐诗/poet.tang.24000.json','["離筵莫愴且同歡，共賀新恩拜舊官。", "屈就商山伴麋鹿，好歸芸閣狎鵷鸞。", "落星石上蒼苔古，畫鶴廳前白露寒。", "老監姓名應在壁，相思試爲拂塵看。"]'),
('a831a988-8bb2-4882-a0f4-f865e6b3a5f6','酒熟憶皇甫十','白居易','唐','唐诗','tang','','[]','新酒此時熟，故人何日來。',48,'全唐诗/poet.tang.24000.json','["新酒此時熟，故人何日來。", "自從金谷別，不見玉山頹。", "疎索柳花盌，寂寥荷葉杯。", "今冬問氈帳，雪裏爲誰開。"]'),
('11d9e8d1-fff1-4a66-819c-31f81001fa22','九年十一月二十一日感事而作','白居易','唐','唐诗','tang','','[]','禍福茫茫不可期，大都早退似先知。',64,'全唐诗/poet.tang.24000.json','["禍福茫茫不可期，大都早退似先知。", "當君白首同歸日，是我青山獨往時。", "顧索素琴應不暇，憶牽黃犬定難追。", "麒麟作脯龍爲醢，何似泥中曳尾龜。"]'),
('bd786e91-4408-40e9-a198-1d21a4178fe8','即事重題','白居易','唐','唐诗','tang','','[]','重裘暖帽寬氈履，小閣低窗深地爐。',32,'全唐诗/poet.tang.24000.json','["重裘暖帽寬氈履，小閣低窗深地爐。", "身穩心安眠未起，西京朝士得知無。"]'),
('b84e6b34-edd5-43c9-8f48-77855d0b071c','將歸渭村先寄舍弟','白居易','唐','唐诗','tang','','[]','一年年覺此身衰，一日日知前事非。',64,'全唐诗/poet.tang.24000.json','["一年年覺此身衰，一日日知前事非。", "詠月嘲風先要減，登山臨水亦宜稀。", "子平嫁娶貧中畢，元亮田園醉裏歸。", "爲報阿連寒食下，與吾釀酒掃柴扉。"]'),
('faa6013b-5c49-4096-afab-4d9d4358b7a6','看嵩洛有歎','白居易','唐','唐诗','tang','','[]','今日看嵩洛，迴頭歎世間。',48,'全唐诗/poet.tang.24000.json','["今日看嵩洛，迴頭歎世間。", "榮華急如水，憂患大於山。", "見苦方知樂，經忙始愛閑。", "未聞籠裏鳥，飛出肯飛還。"]'),
('ff69fcd3-3ed0-4edb-883c-f0c5bd1e59f8','詠懷','白居易','唐','唐诗','tang','','[]','隨緣逐處便安閑，不入朝廷不住山。',64,'全唐诗/poet.tang.24000.json','["隨緣逐處便安閑，不入朝廷不住山。", "心似虛舟浮水上，身同宿鳥寄林間。", "尚平婚嫁了無累，馮翊符章封却還。", "處分貧家殘活計，匹如身後莫相關。"]'),
('4f2e0fec-11ce-41dd-bec4-62fde7499912','詠老贈夢得','白居易','唐','唐诗','tang','','[]','與君俱老也，自問老何如。',72,'全唐诗/poet.tang.24000.json','["與君俱老也，自問老何如。", "眼澀夜先臥，頭慵朝未梳。", "有時扶杖出，盡日閉門居。", "嬾照新磨鏡，休看小字書。", "情於故人重，迹共少年疎。", "唯是閑談興，相逢尚有餘。"]'),
('18edec5f-06df-4bd0-9291-f3eb09fc93c5','從同州刺史改授太子少傅分司','白居易','唐','唐诗','tang','','[]','承華東署三分務，履道西池七過春。',64,'全唐诗/poet.tang.24000.json','["承華東署三分務，履道西池七過春。", "歌酒優游聊卒歲，園林蕭灑可終身。", "留侯爵秩誠虛貴，疏受生涯未苦貧。", "月俸百千官二品，朝廷雇我作閑人。"]'),
('d9a9bf4b-fba8-424b-b81c-309bcdade7aa','奉和裴令公新成午橋莊綠野堂即事','白居易','唐','唐诗','tang','','[]','舊徑開桃李，新池鑿鳳皇。',120,'全唐诗/poet.tang.24000.json','["舊徑開桃李，新池鑿鳳皇。", "只添丞相閣，不改午橋莊。", "遠處塵埃少，閑中日月長。", "青山爲外屏，綠野是前堂。", "引水多隨勢，栽松不趂行。", "年華玩風景，春事看農桑。", "花妬謝家妓，蘭偷荀令香。", "遊絲飄酒席，瀑布濺琴牀。", "巢許終身穩，蕭曹到老忙。", "千年落公便，進退處中央。"]'),
('8f5b4350-b3a6-488f-a965-62f74b8eac46','自題小草亭','白居易','唐','唐诗','tang','','[]','新結一茅茨，規模儉且卑。',144,'全唐诗/poet.tang.24000.json','["新結一茅茨，規模儉且卑。", "土堦全壘塊，山木半留皮。", "陰合連藤架，藂香近菊籬。", "壁宜藜杖倚，門稱荻簾垂。", "窗裏風清夜，簷間月好時。", "留連嘗酒客，句引坐禪師。", "伴宿雙棲鶴，扶行一侍兒。", "綠醅量醆飲，紅稻約升炊。", "齷齪豪家笑，酸寒富室欺。", "陶廬閑自愛，顏巷陋誰知。", "螻蟻謀深穴，鷦鷯占小枝。", "各隨其分足，焉用有餘爲。"]'),
('91534793-58e2-4007-a6fd-0278574c7afb','自詠','白居易','唐','唐诗','tang','','[]','細故隨緣盡，衰形具體微。',72,'全唐诗/poet.tang.24000.json','["細故隨緣盡，衰形具體微。", "鬬閑僧尚鬧，較瘦鶴猶肥。", "老遣寬裁襪，寒教厚絮衣。", "馬從銜草展，雞任啄籠飛。", "只要天和在，無令物性違。", "自餘君莫問，何是復何非。"]'),
('10215099-eae8-4f49-ab1e-9234041d9ebb','新亭病後獨坐招李侍郎公垂','白居易','唐','唐诗','tang','','[]','新亭未有客，景日獨何爲。',60,'全唐诗/poet.tang.24000.json','["新亭未有客，景日獨何爲。", "趂暖泥茶竈，防寒夾竹籬。", "頭風初定後，眼闇欲明時。", "淺把三分酒，閑題數句詩。", "應須置兩榻，一榻待公垂。"]'),
('a0d4a9b1-1a35-4eb8-8b8b-5b8913ecf9e8','閑臥寄劉同州','白居易','唐','唐诗','tang','','[]','軟褥短屏風，昏昏醉臥翁。',48,'全唐诗/poet.tang.24000.json','["軟褥短屏風，昏昏醉臥翁。", "鼻香茶熟後，腰暖日陽中。", "伴老琴長在，迎春酒不空。", "可憐閑氣味，唯欠與君同。"]'),
('f1532d0e-df2b-47ff-9a54-3a8a6f43840b','殘酌晚餐','白居易','唐','唐诗','tang','','[]','閑傾殘酒後，煖擁小爐時。',48,'全唐诗/poet.tang.24000.json','["閑傾殘酒後，煖擁小爐時。", "舞看新翻曲，歌聽自作詞。", "魚香肥潑火，飯細滑流匙。", "除却慵饞外，其餘盡不知。"]'),
('64a65f36-c17c-4737-8706-fd941ac48535','喜見劉同州夢得','白居易','唐','唐诗','tang','','[]','紫綬白髭鬚，同年二老夫。',48,'全唐诗/poet.tang.24000.json','["紫綬白髭鬚，同年二老夫。", "論心共牢落，見面且歡娛。", "酒好攜來否，詩多記得無。", "應須爲春草，五馬少踟躕。"]'),
('79de982b-0c9e-400c-8c5d-3cb7874a202d','裴令公席上贈別夢得','白居易','唐','唐诗','tang','','[]','年老官高多別離，轉難相見轉相思。',32,'全唐诗/poet.tang.24000.json','["年老官高多別離，轉難相見轉相思。", "雪銷酒盡梁王起，便是鄒枚分散時。"]'),
('0915c42f-c0c2-4af1-bdcd-3f023f4e9929','尋春題諸家園林','白居易','唐','唐诗','tang','','[]','聞健朝朝出，乘春處處尋。',48,'全唐诗/poet.tang.24000.json','["聞健朝朝出，乘春處處尋。", "天供閑日月，人借好園林。", "漸以狂爲態，都無悶到心。", "平生身得所，未省似而今。"]'),
('26029c03-139b-4250-8550-e77d70b14489','又題一絕','白居易','唐','唐诗','tang','','[]','貌隨年老欲何如，興遇春牽尚有餘。',32,'全唐诗/poet.tang.24000.json','["貌隨年老欲何如，興遇春牽尚有餘。", "遙見人家花便入，不論貴賤與親疎。"]'),
('bd37a863-b39c-4cb1-bb44-3aaf15c64680','家園三絕 一','白居易','唐','唐诗','tang','','[]','滄浪峽水子陵灘，路遠江深欲去難。',32,'全唐诗/poet.tang.24000.json','["滄浪峽水子陵灘，路遠江深欲去難。", "何似家池通小院，臥房階下插魚竿。"]'),
('28ab6978-5543-4bfa-967e-8abc75a00bbc','家園三絕 二','白居易','唐','唐诗','tang','','[]','籬下先生時得醉，甕間吏部暫偷閑。',32,'全唐诗/poet.tang.24000.json','["籬下先生時得醉，甕間吏部暫偷閑。", "何如家醞雙魚榼，雪夜花時長在前。"]'),
('7618a91b-a9b6-444d-8575-61fd84f81afe','家園三絕 三','白居易','唐','唐诗','tang','','[]','鴛鴦怕捉竟難親，鸚鵡雖籠不著人。',32,'全唐诗/poet.tang.24000.json','["鴛鴦怕捉竟難親，鸚鵡雖籠不著人。", "何似家禽雙白鶴，閑行一步亦隨身。"]'),
('dc616b8b-4fed-45e2-a8ad-a324bb938038','老來生計','白居易','唐','唐诗','tang','','[]','老來生計君看取，白日遊行夜醉吟。',64,'全唐诗/poet.tang.24000.json','["老來生計君看取，白日遊行夜醉吟。", "陶令有田唯種黍，鄧家無子不留金。", "人間榮耀因緣淺，林下幽閑氣味深。", "煩慮漸消虛白長，一年心勝一年心。"]'),
('8ab8e98e-8c22-4a5a-b903-6b32212b0206','早春題少室東巖','白居易','唐','唐诗','tang','','[]','三十六峰晴，雪銷嵐翠生。',48,'全唐诗/poet.tang.24000.json','["三十六峰晴，雪銷嵐翠生。", "月留三夜宿，春引四山行。", "遠草初含色，寒禽未變聲。", "東巖最高石，唯我有題名。"]'),
('3c132e3f-3b9a-45f8-9149-2c885c72b93f','早春即事','白居易','唐','唐诗','tang','','[]','眼重朝眠足，頭輕宿酒醒。',72,'全唐诗/poet.tang.24000.json','["眼重朝眠足，頭輕宿酒醒。", "陽光滿前戶，雪水半中庭。", "物變隨天氣，春生逐地形。", "北簷梅晚白，東岸柳先青。", "葱壠抽羊角，松巢墮鶴翎。", "老來詩更拙，吟罷少人聽。"]'),
('a4d58623-baf8-4736-a2eb-06b77122e969','歎春風兼贈李二十侍郎二絕 一','白居易','唐','唐诗','tang','','[]','樹根雪盡催花發，池岸冰消放草生。',32,'全唐诗/poet.tang.24000.json','["樹根雪盡催花發，池岸冰消放草生。", "唯有鬚霜依舊白，春風於我獨無情。"]'),
('53d04ab4-500a-4eee-9ca3-973787774f29','歎春風兼贈李二十侍郎二絕 二','白居易','唐','唐诗','tang','','[]','道場齋戒今初畢，酒伴歡娛久不同。',32,'全唐诗/poet.tang.24000.json','["道場齋戒今初畢，酒伴歡娛久不同。", "不把一杯來勸我，無情亦得似春風。"]'),
('1363cce8-7648-4f35-b740-cae029b08558','春來頻與李二賓客郭外同遊因贈長句','白居易','唐','唐诗','tang','','[]','風光引步酒開顏，送老消春嵩洛間。',64,'全唐诗/poet.tang.24000.json','["風光引步酒開顏，送老消春嵩洛間。", "朝蹋落花相伴出，暮隨飛鳥一時還。", "我爲病叟誠宜退，君是才臣豈合閑。", "可惜濟時心力在，放教臨水復登山。"]'),
('5788d6d0-ce3b-4b9d-86be-b18db8680405','二月二日','白居易','唐','唐诗','tang','','[]','二月二日新雨晴，草芽菜甲一時生。',32,'全唐诗/poet.tang.24000.json','["二月二日新雨晴，草芽菜甲一時生。", "輕衫細馬春年少，十字津頭一字行。"]'),
('3315eb0b-1f7b-4ab3-a68e-5d2941c4413d','奉和令公綠野堂種花','白居易','唐','唐诗','tang','','["\u8001\u5e08", "\u8d5e\u7f8e"]','綠野堂開占物華，路人指道令公家。',32,'全唐诗/poet.tang.24000.json','["綠野堂開占物華，路人指道令公家。", "令公桃李滿天下，何用堂前更種花。"]'),
('90461bfa-5f84-49c0-bb30-d3fe60b62ccf','清明日登老君閣望洛城贈韓道士','白居易','唐','唐诗','tang','','[]','風光煙火清明日，歌哭悲歡城市間。',64,'全唐诗/poet.tang.24000.json','["風光煙火清明日，歌哭悲歡城市間。", "何事不隨東洛水，誰家又葬北邙山。", "中橋車馬長無已，下渡舟航亦不閑。", "冢墓纍纍人擾擾，遼東悵望鶴飛還。"]'),
('98f439ef-d136-4aa1-8881-c04dffb03f10','三月三日','白居易','唐','唐诗','tang','','[]','畫堂三月初三日，絮撲窗紗燕拂簷。',64,'全唐诗/poet.tang.24000.json','["畫堂三月初三日，絮撲窗紗燕拂簷。", "蓮子數杯嘗冷酒，柘枝一曲試春衫。", "階臨池面勝看鏡，戶映花藂當下簾。", "指點樓南玩新月，玉鉤素手兩纖纖。"]'),
('49675740-13db-4c61-b7ca-32329eb90265','雨中聽琴者彈別鶴操','白居易','唐','唐诗','tang','','[]','雙鶴分離一何苦，連陰雨夜不堪聞。',32,'全唐诗/poet.tang.24000.json','["雙鶴分離一何苦，連陰雨夜不堪聞。", "莫教遷客孀妻聽，嗟歎悲啼䛏殺君。"]'),
('30529770-c2d9-481b-a121-ad756b2cd30a','酬鄭二司錄與李六郎中寒食日相過同宴見贈','白居易','唐','唐诗','tang','','[]','偶因冷節會嘉賓，況是平生心所親。',64,'全唐诗/poet.tang.24000.json','["偶因冷節會嘉賓，況是平生心所親。", "迎接須衿疏傅老，祗供莫笑阮家貧。", "杯盤狼籍宜侵夜，風景闌珊欲過春。", "相對喜歡還悵望，同年只有此三人。"]'),
('05ffe97c-3c5d-4a48-bbda-0074c7a76cef','喜楊六侍御同宿','白居易','唐','唐诗','tang','','[]','岸幘靜言明月夜，匡牀閑臥落花朝。',64,'全唐诗/poet.tang.24000.json','["岸幘靜言明月夜，匡牀閑臥落花朝。", "二三月裏饒春睡，七八年來不早朝。", "濁水清塵難會合，高鵬低鷃各逍遙。", "眼看又上青雲去，更卜同衾一兩宵。"]'),
('a7380bcd-6773-472a-9f9d-681f18e44002','殘春詠懷贈楊慕巢侍郎','白居易','唐','唐诗','tang','','[]','位逾三品日，年過六旬時。',96,'全唐诗/poet.tang.24000.json','["位逾三品日，年過六旬時。", "不道官班下，其如筋力衰。", "猶憐好風景，轉重舊親知。", "少壯難重得，歡娛且強爲。", "興來池上酌，醉出袖中詩。", "靜話開襟久，閑吟放醆遲。", "落花無限雪，殘鬢幾多絲。", "莫說傷心事，春翁易酒悲。"]'),
('7f6d46b2-3471-4274-bd04-72a04f95ea7c','閑居春盡','白居易','唐','唐诗','tang','','[]','閑泊池舟靜掩扉，老身慵出客來稀。',64,'全唐诗/poet.tang.24000.json','["閑泊池舟靜掩扉，老身慵出客來稀。", "愁應暮雨留教住，春被殘鶯喚遣歸。", "揭甕偷嘗新熟酒，開箱試著舊生衣。", "冬裘夏葛相催促，垂老光陰速似飛。"]'),
('696bdf92-9cff-4fd6-bf94-b45f28aa5032','春盡日天津橋醉吟偶呈李尹侍郎','白居易','唐','唐诗','tang','','[]','宿雨洗天津，無泥未有塵。',72,'全唐诗/poet.tang.24000.json','["宿雨洗天津，無泥未有塵。", "初晴迎早夏，落照送殘春。", "興發詩隨口，狂來酒寄身。", "水邊行嵬峩，橋上立逡巡。", "疎傅心情老，吳公政化新。", "三川徒有主，風景屬閑人。"]'),
('7c2808ce-2e41-4d93-a57d-59e71d35f74d','池上逐涼二首 一','白居易','唐','唐诗','tang','','[]','青苔地上消殘暑，綠樹陰前逐晚涼。',64,'全唐诗/poet.tang.24000.json','["青苔地上消殘暑，綠樹陰前逐晚涼。", "輕屐單衫薄紗帽，淺池平岸庳藤牀。", "簪纓怪我情何薄，泉石諳君味甚長。", "徧問交親爲老計，多言宜靜不宜忙。"]'),
('ca468563-e19a-47ed-bbc3-0bb47188315d','池上逐涼二首 二','白居易','唐','唐诗','tang','','[]','窗間睡足休高枕，水畔閑來上小船。',64,'全唐诗/poet.tang.24000.json','["窗間睡足休高枕，水畔閑來上小船。", "櫂遣禿頭奴子撥，茶教纖手侍兒煎。", "門前便是紅塵地，林外無非赤日天。", "誰信好風清簟上，更無一事但翛然。"]'),
('2c807d44-b9d9-4e39-bf52-faa461b4a4fb','香山避暑二絕 一','白居易','唐','唐诗','tang','','[]','六月灘聲如猛雨，香山樓北暢師房。',32,'全唐诗/poet.tang.24000.json','["六月灘聲如猛雨，香山樓北暢師房。", "夜深起凭闌干立，滿耳潺湲滿面涼。"]'),
('e1f2e3b0-112c-460c-9b71-c975d025af71','香山避暑二絕 二','白居易','唐','唐诗','tang','','[]','紗巾草履竹疎衣，晚下香山蹋翠微。',32,'全唐诗/poet.tang.24000.json','["紗巾草履竹疎衣，晚下香山蹋翠微。", "一路涼風十八里，臥乘籃轝睡中歸。"]'),
('9ec4b3a3-bb95-460e-bab8-d4bd6b607e00','老夫','白居易','唐','唐诗','tang','','[]','七八年來遊洛都，三分遊伴二分無。',64,'全唐诗/poet.tang.24000.json','["七八年來遊洛都，三分遊伴二分無。", "風前月下花園裏，處處唯殘个老夫。", "世事勞心非富貴，人間實事是歡娛。", "誰能逐我來閑坐，時共酣歌傾一壺。"]'),
('0cf9d927-3dd4-4fd3-a330-c71b9b747934','香山下卜居','白居易','唐','唐诗','tang','','[]','老須爲老計，老計在抽簪。',48,'全唐诗/poet.tang.24000.json','["老須爲老計，老計在抽簪。", "山下初投足，人間久息心。", "亂藤遮石壁，絕澗護雲林。", "若要深藏處，無如此處深。"]'),
('4690d143-27fb-422e-9bd9-f071c3d64eaf','無長物','白居易','唐','唐诗','tang','','[]','莫訝家居窄，無嫌活計貧。',48,'全唐诗/poet.tang.24000.json','["莫訝家居窄，無嫌活計貧。", "只緣無長物，始得作閑人。", "青竹單牀簟，烏紗獨幅巾。", "其餘皆稱是，亦足奉吾身。"]'),
('e560bf2f-cb08-4ed3-a71a-424778ea55b8','宿香山寺酬廣陵牛相公見寄','白居易','唐','唐诗','tang','','[]','手札八行詩一篇，無由相見但依然。',64,'全唐诗/poet.tang.24000.json','["手札八行詩一篇，無由相見但依然。", "君匡聖主方行道，我事空王正坐禪。", "支許徒思遊白月，夔龍未放下青天。", "應須且爲蒼生住，猶去懸車十四年。"]'),
('c5dd7f13-2f06-4fcc-a2eb-02cf2d4de23e','以詩代書寄戶部楊侍郎勸買東鄰王家宅','白居易','唐','唐诗','tang','','[]','勸君買取東鄰宅，與我衡門相並開。',64,'全唐诗/poet.tang.24000.json','["勸君買取東鄰宅，與我衡門相並開。", "雲映嵩峰當戶牖，月和伊水入池臺。", "林園亦要聞閑置，筋力應須及健迴。", "莫學因循白賓客，欲年六十始歸來。"]'),
('0cd98c5e-1750-4bb8-a364-d23ed6768481','贈談客','白居易','唐','唐诗','tang','','[]','上客清談何亹亹，幽人閑思自寥寥。',32,'全唐诗/poet.tang.24000.json','["上客清談何亹亹，幽人閑思自寥寥。", "請君休說長安事，膝上風清琴正調。"]'),
('3b51cd92-94e4-4cc0-98f3-5a556228ba44','初入香山院對月','白居易','唐','唐诗','tang','','[]','老住香山初到夜，秋逢白月正圓時。',32,'全唐诗/poet.tang.24000.json','["老住香山初到夜，秋逢白月正圓時。", "從今便是家山月，試問清光知不知。"]'),
('c973d4d6-e2ba-4a05-b6a8-73e79955fd10','題龍門堰西澗','白居易','唐','唐诗','tang','','[]','東岸菊叢西岸柳，柳陰煙合菊花開。',48,'全唐诗/poet.tang.24000.json','["東岸菊叢西岸柳，柳陰煙合菊花開。", "一條秋水琉璃色，闊狹纔容小舫迴。", "除却悠悠白少傅，何人解入此中來。"]'),
('cd3d8e0c-a549-44a9-b55c-4f1c9b9befed','秋霖中奉裴令公見招早出赴會馬上先寄六韻','白居易','唐','唐诗','tang','','[]','雨暗三秋日，泥深一尺時。',72,'全唐诗/poet.tang.24000.json','["雨暗三秋日，泥深一尺時。", "老人平旦出，自問欲何之。", "不是尋醫藥，非干送別離。", "素書傳好語，絳帳赴佳期。", "續借桃花馬，催迎楊柳姬。", "只愁張錄事，罰我怪來遲。"]'),
('09976f6b-ed1e-4b35-9b1a-a3a3cebb9f6f','嘗酒聽歌招客','白居易','唐','唐诗','tang','','[]','一甕香醪新插芻，雙鬟小妓薄能謳。',64,'全唐诗/poet.tang.24000.json','["一甕香醪新插芻，雙鬟小妓薄能謳。", "管弦漸好新教得，羅綺雖貧免外求。", "世上貪忙不覺苦，人間除醉即須愁。", "不知此事君知否，君若知時從我遊。"]'),
('2e1caa8a-5a9f-4ca9-98f0-c4e091a43d0e','八月三日夜作','白居易','唐','唐诗','tang','','[]','露白月微明，天涼景物清。',96,'全唐诗/poet.tang.24000.json','["露白月微明，天涼景物清。", "草頭珠顆冷，樓角玉鉤生。", "氣爽衣裳健，風疎砧杵鳴。", "夜衾香有思，秋簟冷無情。", "夢短眠頻覺，宵長起暫行。", "燭凝臨曉影，蟲怨欲寒聲。", "槿老花先盡，蓮凋子始成。", "四時無了日，何用歎衰榮。"]'),
('d54ddc0d-bcc6-4767-b42f-1961c07efe59','病中贈南鄰覓酒','白居易','唐','唐诗','tang','','[]','頭痛牙疼三日臥，妻看煎藥婢來扶。',32,'全唐诗/poet.tang.24000.json','["頭痛牙疼三日臥，妻看煎藥婢來扶。", "今朝似校擡頭語，先問南鄰有酒無。"]'),
('98feffbf-5801-4d93-bdfa-805b31a9a5b8','曉眠後寄楊戶部','白居易','唐','唐诗','tang','','[]','輭綾腰褥薄緜被，涼冷秋天穩暖身。',32,'全唐诗/poet.tang.24000.json','["輭綾腰褥薄緜被，涼冷秋天穩暖身。", "一覺曉眠殊有味，無因寄與早朝人。"]'),
('d91f5def-2309-41b2-b58c-80443c295fcb','秋雨夜眠','白居易','唐','唐诗','tang','','["\u79cb\u5929", "\u5199\u4eba", "\u6292\u6000", "\u6de1\u6cca"]','涼冷三秋夜，安閑一老翁。',48,'全唐诗/poet.tang.24000.json','["涼冷三秋夜，安閑一老翁。", "臥遲燈滅後，睡美雨聲中。", "灰宿溫瓶火，香添煖被籠。", "曉晴寒未起，霜葉滿階紅。"]'),
('6754d7b4-3ee7-4685-a5d6-f4d4d5b120bc','喜夢得自馮翊歸洛兼呈令公','白居易','唐','唐诗','tang','','[]','上客新從左輔迴，高陽興助洛陽才。',64,'全唐诗/poet.tang.24000.json','["上客新從左輔迴，高陽興助洛陽才。", "已將四海聲名去，又占三春風景來。", "甲子等頭憐共老，文章敵手莫相猜。", "鄒枚未用爭詩酒，且飲梁王賀喜杯。"]'),
('2b063b5f-326b-43b4-aea5-f8a4a926e383','齋戒滿夜戲招夢得','白居易','唐','唐诗','tang','','[]','紗籠燈下道場前，白日持齋夜坐禪。',64,'全唐诗/poet.tang.24000.json','["紗籠燈下道場前，白日持齋夜坐禪。", "無復更思身外事，未能全盡世間緣。", "明朝又擬親杯酒，今夕先聞理管弦。", "方丈若能來問疾，不妨兼有散花天。"]'),
('f27f6e70-92a7-437b-ad15-49bff64bf675','和令公問劉賓客歸來稱意無之作','白居易','唐','唐诗','tang','','[]','水南秋一半，風景未蕭條。',48,'全唐诗/poet.tang.24000.json','["水南秋一半，風景未蕭條。", "皂蓋迴沙苑，藍轝上洛橋。", "閑嘗黃菊酒，醉唱紫芝謠。", "稱意那勞問，請錢不早朝。"]'),
('f8f53f24-6973-4d34-b8b6-5e81a06ae420','酬夢得窮秋夜坐即事見寄','白居易','唐','唐诗','tang','','[]','焰細燈將盡，聲遙漏正長。',48,'全唐诗/poet.tang.24000.json','["焰細燈將盡，聲遙漏正長。", "老人秋向火，小女夜縫裳。", "菊悴籬經雨，萍銷水得霜。", "今冬煖寒酒，先擬共君嘗。"]'),
('dd12c204-a136-437f-910a-1f9a7401d7d8','偶於維揚牛相公處覓得箏箏未到先寄詩來走筆戲荅','白居易','唐','唐诗','tang','','[]','楚匠饒巧思，秦箏多好音。',48,'全唐诗/poet.tang.24000.json','["楚匠饒巧思，秦箏多好音。", "如能惠一面，何啻直雙金。", "玉柱調須品，朱弦染要深。", "會教魔女弄，不動是禪心。"]'),
('c173ced7-76cd-4307-a17f-43dd77459c7e','荅夢得秋庭獨坐見贈','白居易','唐','唐诗','tang','','[]','林梢隱映夕陽殘，庭際蕭疎夜氣寒。',64,'全唐诗/poet.tang.24000.json','["林梢隱映夕陽殘，庭際蕭疎夜氣寒。", "霜草欲枯蟲思急，風枝未定鳥棲難。", "容衰見鏡同惆悵，身健逢杯且喜歡。", "應是天教相煖熱，一時垂老與閑宮。"]'),
('fda608cb-dd18-45d9-8af1-7817e7268e92','長齋月滿攜酒先與夢得對酌醉中同赴令公之宴戲贈夢得','白居易','唐','唐诗','tang','','[]','齋宮前日滿三旬，酒榼今朝一拂塵。',64,'全唐诗/poet.tang.24000.json','["齋宮前日滿三旬，酒榼今朝一拂塵。", "乘興還同訪戴客，解酲仍對姓劉人。", "病心湯沃寒灰活，老面花生朽木春。", "若怕平原怪先醉，知君未慣吐車茵。"]'),
('2de7d9cf-34a7-4d97-a6b4-3ff21fbe75d2','奉酬淮南牛相公思黯見寄二十四韻','白居易','唐','唐诗','tang','','[]','白老忘機客，牛公濟世賢。',288,'全唐诗/poet.tang.24000.json','["白老忘機客，牛公濟世賢。", "鷗棲心戀水，鵬舉翅摩天。", "累就優閑秩，連操造化權。", "貧司甚蕭灑，榮路自喧闐。", "望苑三千日，台階十五年。", "是人皆棄忘，何物不陶甄。", "籃轝遊嵩嶺，油幢鎮海壖。", "竹篙撑釣艇，金甲擁樓船。", "雪夜尋僧舍，春朝列妓筵。", "長齋儼香火，密宴簇花鈿。", "自覺閑勝鬧，遙知醉笑禪。", "是非分未定，會合杳無緣。", "我正思楊府，君應望洛川。", "西來風褭褭，南去雁連連。", "日落龍門外，潮生瓜步前。", "秋同一時盡，月共兩鄉圓。", "舊眷交歡在，新文氣調全。", "慙無白雪曲，難荅碧雲篇。", "金谷詩誰賞，蕪城賦衆傳。", "珠應哂魚目，鉛未伏龍泉。", "遠訊驚魔物，深情寄酒錢。", "霜紈一百疋，玉柱十三弦。", "楚醴來尊裏，秦聲送耳邊。", "何時紅燭下，相對一陶然。"]'),
('89a1db3d-39bb-479e-ad72-3b4bb97ee9f9','吳祕監每有美酒獨酌獨醉但蒙詩報不以飲招輙此戲酬兼呈夢得','白居易','唐','唐诗','tang','','[]','蓬山仙客下煙霄，對酒唯吟獨酌謠。',64,'全唐诗/poet.tang.24000.json','["蓬山仙客下煙霄，對酒唯吟獨酌謠。", "不怕道狂揮玉爵，亦曾乘興解金貂。", "君稱名士誇能飲，我是愚夫肯見招。", "賴有伯倫爲醉伴，何愁不解傲松喬。"]'),
('53a99c15-6da0-4c6b-a361-34489ba4ec48','酬夢得霜夜對月見懷','白居易','唐','唐诗','tang','','[]','淒清冬夜景，搖落長年情。',48,'全唐诗/poet.tang.24000.json','["淒清冬夜景，搖落長年情。", "月帶新霜色，碪和遠雁聲。", "暖憐爐火近，寒覺被衣輕。", "枕上酬佳句，詩成夢不成。"]'),
('9cded7e0-33d9-44d4-a3d6-e6f83d084824','初冬月夜得皇甫澤州手札幷詩數篇因遣報書偶題長句','白居易','唐','唐诗','tang','','[]','清泠玉韻兩三章，落箔銀鉤七八行。',64,'全唐诗/poet.tang.24000.json','["清泠玉韻兩三章，落箔銀鉤七八行。", "心逐報書懸雁足，夢尋來路繞羊腸。", "水南地空多明月，山北天寒足早霜。", "最恨潑醅新熟酒，迎冬不得共君嘗。"]'),
('a849536b-d198-49f0-a04b-b7b90c96018d','雪中酒熟欲攜訪吳監先寄此詩','白居易','唐','唐诗','tang','','[]','新雪對新酒，憶同傾一杯。',48,'全唐诗/poet.tang.24000.json','["新雪對新酒，憶同傾一杯。", "自然須訪戴，不必待延枚。", "陳榻無辭解，袁門莫嬾開。", "笙歌與談笑，隨事自將來。"]'),
('cf31380f-2482-448d-9ffc-250a0fdb0861','酬令公雪中見贈訝不與夢得同相訪','白居易','唐','唐诗','tang','','[]','雪似鵝毛飛散亂，人披鶴氅立裴回。',32,'全唐诗/poet.tang.24000.json','["雪似鵝毛飛散亂，人披鶴氅立裴回。", "鄒生枚叟非無興，唯待梁王召即來。"]'),
('e98f5a29-cb12-43a1-be8a-21f447958a13','題酒甕呈夢得','白居易','唐','唐诗','tang','','[]','若無清酒兩三甕，爭向白鬚千萬莖。',64,'全唐诗/poet.tang.24000.json','["若無清酒兩三甕，爭向白鬚千萬莖。", "麴糵銷愁真得力，光陰催老苦無情。", "凌煙閣上功無分，伏火爐中藥未成。", "更擬共君何處去，且來同作醉先生。"]'),
('f3597bce-26c0-4816-ad39-b2b475acbaf7','迂叟','白居易','唐','唐诗','tang','','[]','一辭魏闕就商賓，散地閑居八九春。',64,'全唐诗/poet.tang.24000.json','["一辭魏闕就商賓，散地閑居八九春。", "初時被目爲迂叟，近日蒙呼作隱人。", "冷暖俗情諳世路，是非閑論任交親。", "應須繩墨機關外，安置疎愚鈍滯身。"]'),
('3a3a626f-e99c-4220-ba9c-f7184c7aad18','洛下閑居寄山南令狐相公','白居易','唐','唐诗','tang','','[]','已收身向園林下，猶寄名於祿仕間。',64,'全唐诗/poet.tang.24000.json','["已收身向園林下，猶寄名於祿仕間。", "不鍛嵇康彌嬾靜，無金疎傅更貧閑。", "支分門內餘生計，謝絕朝中舊往還。", "唯是相君忘未得，時思漢水夢巴山。"]'),
('24648591-4aed-4e69-a011-26958c067a0a','惜春贈李尹','白居易','唐','唐诗','tang','','[]','春色有時盡，公門終日忙。',48,'全唐诗/poet.tang.24000.json','["春色有時盡，公門終日忙。", "兩衙但不闕，一醉亦何妨。", "芳樹花團雪，衰翁鬢撲霜。", "知君倚年少，未苦惜風光。"]'),
('6fc37252-848e-42fd-9c59-773a1a2ca1a9','對酒勸令公開春遊宴','白居易','唐','唐诗','tang','','[]','時泰歲豐無事日，功成名遂自由身。',64,'全唐诗/poet.tang.24000.json','["時泰歲豐無事日，功成名遂自由身。", "前頭更有忘憂日，向上應無快活人。", "自去年來多事故，從今日去少交親。", "宜須數數謀歡會，好作開成第二春。"]'),
('f679b5a3-ba16-4cbc-88ae-9762a0261e81','與夢得偶同到敦詩宅感而題壁','白居易','唐','唐诗','tang','','[]','山東纔副蒼生願，川上俄驚逝水波。',64,'全唐诗/poet.tang.24000.json','["山東纔副蒼生願，川上俄驚逝水波。", "履道淒涼新第宅，宣城零落舊笙歌。", "園荒唯有薪堪採，門冷兼無雀可羅。", "今日相逢偶同到，傷心不是故經過。"]'),
('8dc84e41-c0c6-41f5-a399-58c6b3a95551','楊六尚書新授東川節度使代妻戲賀兄嫂二絕 一','白居易','唐','唐诗','tang','','[]','劉綱與婦共昇仙，弄玉隨夫亦上天。',32,'全唐诗/poet.tang.24000.json','["劉綱與婦共昇仙，弄玉隨夫亦上天。", "何似沙哥領崔嫂，碧油幢引向東川。"]'),
('d2d81f14-86be-4a33-a274-d2640249d826','楊六尚書新授東川節度使代妻戲賀兄嫂二絕 二','白居易','唐','唐诗','tang','','[]','金花銀椀饒君用，罨畫羅衣盡嫂裁。',32,'全唐诗/poet.tang.24000.json','["金花銀椀饒君用，罨畫羅衣盡嫂裁。", "覓得黔婁爲妹壻，可能空寄蜀茶來。"]'),
('e818e044-b74e-449c-bae7-3027fc00d799','閑遊即事','白居易','唐','唐诗','tang','','[]','郊野遊行熟，村園次第過。',72,'全唐诗/poet.tang.24000.json','["郊野遊行熟，村園次第過。", "驀山尋浥澗，蹋水渡伊河。", "寒食青青草，春風瑟瑟波。", "逢人共杯酒，隨馬有笙歌。", "勝事經非少，芳辰過亦多。", "還須自知分，不老擬如何。"]'),
('d19fe25f-6188-47cf-b056-068b222ebf9f','六十六','白居易','唐','唐诗','tang','','[]','七十欠四歲，此生那足論。',72,'全唐诗/poet.tang.24000.json','["七十欠四歲，此生那足論。", "每因悲物故，還且喜身存。", "安得頭長黑，爭教眼不昏。", "交游成拱木，婢僕見曾孫。", "瘦覺腰金重，衰憐鬢雪繁。", "將何理老病，應付與空門。"]'),
('1f716ee9-0091-4f55-b488-9254a9822c20','池上早春即事招夢得','白居易','唐','唐诗','tang','','[]','老更驚年改，閑先覺日長。',96,'全唐诗/poet.tang.24000.json','["老更驚年改，閑先覺日長。", "晴熏榆莢黑，春染柳梢黃。", "雲破山呈色，冰融水放光。", "低平穩船舫，輕暖好衣裳。", "白角三升榼，紅茵六尺牀。", "偶遊難得伴，獨醉不成狂。", "我有中心樂，君無外事忙。", "經過莫慵嬾，相去兩三坊。"]'),
('407ef767-6e67-4104-9f2a-c2377db682f9','因夢得題公垂所寄蠟燭因寄公垂','白居易','唐','唐诗','tang','','[]','照梁初日光相似，出水新蓮豔不如。',32,'全唐诗/poet.tang.24000.json','["照梁初日光相似，出水新蓮豔不如。", "却寄兩條君令取，明年雙引入中書。"]'),
('4cf1bd48-8ce3-4e50-bbbb-e5b0f491c801','令公南莊花柳正盛欲偷一賞先寄二篇 一','白居易','唐','唐诗','tang','','[]','最憶樓花千萬朵，偏憐堤柳兩三株。',32,'全唐诗/poet.tang.24000.json','["最憶樓花千萬朵，偏憐堤柳兩三株。", "擬提社酒攜村妓，擅入朱門莫怪無。"]'),
('d41ce0e5-b035-4626-aefd-dc9e4f8a5d7a','令公南莊花柳正盛欲偷一賞先寄二篇 二','白居易','唐','唐诗','tang','','[]','可惜亭臺閑度日，欲偷風景暫遊春。',32,'全唐诗/poet.tang.24000.json','["可惜亭臺閑度日，欲偷風景暫遊春。", "只愁花裏鶯饒舌，飛入宮城報主人。"]'),
('48bf8656-8ff7-4380-bd51-9756b415c512','春夜宴席上戲贈裴淄川','白居易','唐','唐诗','tang','','[]','九十不衰真地仙，六旬猶健亦天憐。',64,'全唐诗/poet.tang.24000.json','["九十不衰真地仙，六旬猶健亦天憐。", "今年相遇鶯花月，此夜同歡歌酒筵。", "四座齊聲和絲竹，兩家隨分鬬金鈿。", "留君到曉無他意，圖向君前作少年。"]'),
('a6c94e80-a5eb-4519-89ab-d3b6a142330c','贈夢得','白居易','唐','唐诗','tang','','[]','年顏老少與君同，眼未全昏耳未聾。',64,'全唐诗/poet.tang.24000.json','["年顏老少與君同，眼未全昏耳未聾。", "放醉臥爲春日伴，趂歡行入少年叢。", "尋花借馬煩川守，弄水偷船惱令公。", "聞道洛城人盡怪，呼爲劉白二狂翁。"]'),
('f8956f39-ab8c-4c5c-8057-39daad4b2d97','晚春欲攜酒尋沈四著作先以六韻寄之','白居易','唐','唐诗','tang','','[]','病容衰慘澹，芳景晚蹉跎。',72,'全唐诗/poet.tang.24000.json','["病容衰慘澹，芳景晚蹉跎。", "無計留春得，爭能奈老何。", "篇章慵報荅，杯讌喜經過。", "顧我酒狂久，負君詩債多。", "敢辭攜綠蟻，只願見青娥。", "最憶陽關唱，真珠一串歌。"]'),
('618258f5-94bc-441f-abfb-858611aca56e','三月三日祓禊洛濱','白居易','唐','唐诗','tang','','[]','三月草萋萋，黃鶯歇又啼。',144,'全唐诗/poet.tang.24000.json','["三月草萋萋，黃鶯歇又啼。", "柳橋晴有絮，沙路潤無泥。", "禊事修初半，遊人到欲齊。", "金鈿耀桃李，絲管駭鳧鷖。", "轉岸迴船尾，臨流簇馬蹄。", "鬧翻揚子渡，蹋破魏王堤。", "妓接謝公宴，詩陪荀令題。", "舟同李膺泛，醴爲穆生攜。", "水引春心蕩，花牽醉眼迷。", "塵街從鼓動，煙樹任鴉棲。", "舞急紅腰軟，歌遲翠黛低。", "夜歸何用燭，新月鳳樓西。"]'),
('bd0a494f-a2e5-4b77-b828-ccaf9595e52e','同夢得暮春寄賀東西川二楊尚書','白居易','唐','唐诗','tang','','[]','龍節對持真可愛，雁行相接更堪誇。',64,'全唐诗/poet.tang.24000.json','["龍節對持真可愛，雁行相接更堪誇。", "兩川風景同三月，千里江山屬一家。", "魯衛定知連氣色，潘楊亦覺有光華。", "應憐洛下分司伴，冷宴閑遊老看花。"]'),
('23d29c51-acf8-4d60-a761-c24675021791','喜小樓西新柳抽條','白居易','唐','唐诗','tang','','[]','一行弱柳前年種，數尺柔條今日新。',64,'全唐诗/poet.tang.24000.json','["一行弱柳前年種，數尺柔條今日新。", "漸欲拂他騎馬客，未多遮得上樓人。", "須教碧玉羞眉黛，莫與紅桃作麴塵。", "爲報金堤千萬樹，饒伊未敢苦爭春。"]'),
('3c3fc9e6-aac2-4497-a3f5-76f0a803478c','晚春酒醒尋夢得','白居易','唐','唐诗','tang','','[]','料合同惆悵，花殘酒亦殘。',48,'全唐诗/poet.tang.24000.json','["料合同惆悵，花殘酒亦殘。", "醉心忘老易，醒眼別春難。", "獨出雖慵嬾，相逢定喜歡。", "還攜小蠻去，試覓老劉看。"]'),
('cc2e3197-9444-4690-bf6b-bddc6f31df4f','感事','白居易','唐','唐诗','tang','','[]','服氣崔常侍，燒丹鄭舍人。',72,'全唐诗/poet.tang.24000.json','["服氣崔常侍，燒丹鄭舍人。", "常期生羽翼，那忽化灰塵。", "每遇淒涼事，還思潦倒身。", "唯知趂杯酒，不解鍊金銀。", "睡適三尸性，慵安五藏神。", "無憂亦無喜，六十六年春。"]'),
('e8b940a9-ec1a-4f14-a317-1feeb82ba04b','和裴令公南莊絕句','白居易','唐','唐诗','tang','','[]','陶廬僻陋那堪比，謝墅幽微不足攀。',32,'全唐诗/poet.tang.24000.json','["陶廬僻陋那堪比，謝墅幽微不足攀。", "何似嵩峰三十六，長隨申甫作家山。"]'),
('82043ca1-e3da-45c3-93b1-82f8207a1ce8','宅西有流水牆下構小樓臨玩之時頗有幽趣因命歌酒聊以自娛獨醉獨吟偶題五絕句 一','白居易','唐','唐诗','tang','','[]','伊水分來不自由，無人解愛爲誰流。',32,'全唐诗/poet.tang.24000.json','["伊水分來不自由，無人解愛爲誰流。", "家家拋向牆根底，唯我栽蓮越小樓。"]'),
('c61a5c72-1cea-4aaf-85bd-15e7d9f61b55','宅西有流水牆下構小樓臨玩之時頗有幽趣因命歌酒聊以自娛獨醉獨吟偶題五絕句 二','白居易','唐','唐诗','tang','','[]','水色波文何所似，麴塵羅帶一條斜。',32,'全唐诗/poet.tang.24000.json','["水色波文何所似，麴塵羅帶一條斜。", "莫言羅帶春無主，自置樓來屬白家。"]'),
('5bd8f33b-6f97-4093-b7ad-9a2ec0ee4d36','宅西有流水牆下構小樓臨玩之時頗有幽趣因命歌酒聊以自娛獨醉獨吟偶題五絕句 三','白居易','唐','唐诗','tang','','[]','日灩水光搖素壁，風飄樹影拂朱欄。',32,'全唐诗/poet.tang.24000.json','["日灩水光搖素壁，風飄樹影拂朱欄。", "皆言此處宜弦管，試奏霓裳一曲看。"]'),
('5bf6eec2-9e9b-4c5c-902e-28f3e1c1e043','宅西有流水牆下構小樓臨玩之時頗有幽趣因命歌酒聊以自娛獨醉獨吟偶題五絕句 四','白居易','唐','唐诗','tang','','[]','霓裳奏罷唱梁州，紅袖斜翻翠黛愁。',32,'全唐诗/poet.tang.24000.json','["霓裳奏罷唱梁州，紅袖斜翻翠黛愁。", "應是遙聞勝近聽，行人欲過盡迴頭。"]'),
('047cc6b5-d1d3-495f-8618-0d5422df595a','宅西有流水牆下構小樓臨玩之時頗有幽趣因命歌酒聊以自娛獨醉獨吟偶題五絕句 五','白居易','唐','唐诗','tang','','[]','獨醉還須得歌舞，自娛何必要親賓。',32,'全唐诗/poet.tang.24000.json','["獨醉還須得歌舞，自娛何必要親賓。", "當時一部清商樂，亦不長將樂外人。"]'),
('bb7ba540-75dd-4717-9d0b-e4f88931d53e','偶作','白居易','唐','唐诗','tang','','[]','籃舁出即忘歸舍，柴戶昏猶未掩關。',64,'全唐诗/poet.tang.24000.json','["籃舁出即忘歸舍，柴戶昏猶未掩關。", "聞客病時慙體健，見人忙處覺心閑。", "清涼秋寺行香去，和暖春城拜表還。", "木雁一篇須記取，致身才與不才間。"]'),
('cec4e78b-c91b-4bee-8b27-9a12fe6d6b43','因夢得酬牛相公初到洛中小飲見贈','白居易','唐','唐诗','tang','','[]','淮南揮手拋紅斾，洛下迴頭向白雲。',64,'全唐诗/poet.tang.24000.json','["淮南揮手拋紅斾，洛下迴頭向白雲。", "政事堂中老丞相，制科場裏舊將軍。", "宮城煙月饒全占，關塞風光請半分。", "詩酒放狂猶得在，莫欺白叟與劉君。"]'),
('eebcb493-b76b-4ccf-b258-0b704a24cd4c','幽居早秋閑詠','白居易','唐','唐诗','tang','','[]','幽僻囂塵外，清涼水木間。',72,'全唐诗/poet.tang.24000.json','["幽僻囂塵外，清涼水木間。", "臥風秋拂簟，步月夜開關。", "且得身安泰，從他世險艱。", "但休爭要路，不必入深山。", "軒鶴留何用，泉魚放不還。", "誰人知此味，臨老十年閑。"]'),
('8ae31a9a-1271-4bd1-8d56-b7be57aa5c5e','和令狐僕射小飲聽阮咸','白居易','唐','唐诗','tang','','[]','掩抑復淒清，非琴不是箏。',72,'全唐诗/poet.tang.24000.json','["掩抑復淒清，非琴不是箏。", "還彈樂府曲，別占阮家名。", "古調何人識，初聞滿座驚。", "落盤珠歷歷，搖珮玉琤琤。", "似勸杯中物，如含林下情。", "時移音律改，豈是昔時聲。"]'),
('228b1330-b470-4493-9dcb-77d4345e7a5d','燒藥不成命酒獨醉','白居易','唐','唐诗','tang','','[]','白髮逢秋王，丹砂見火空。',48,'全唐诗/poet.tang.24000.json','["白髮逢秋王，丹砂見火空。", "不能留姹女，爭免作衰翁。", "賴有杯中綠，能爲面上紅。", "少年心不遠，只在半酣中。"]'),
('4dbfde36-7fc1-4940-af75-cb372c122a11','送盧郎中赴河東裴令公幕','白居易','唐','唐诗','tang','','[]','別時暮雨洛橋岸，到日涼風汾水波。',32,'全唐诗/poet.tang.24000.json','["別時暮雨洛橋岸，到日涼風汾水波。", "荀令見君應問我，爲言秋草閉門多。"]'),
('4eff91f7-73ae-479e-8358-eefc83eb8b44','送李滁州','白居易','唐','唐诗','tang','','[]','君於覺路深留意，我亦禪門薄致功。',64,'全唐诗/poet.tang.24000.json','["君於覺路深留意，我亦禪門薄致功。", "未悟病時須去病，已知空後莫依空。", "白衣臥病嵩山下，皁蓋行春楚水東。", "誰道三年千里別，兩心同在道場中。"]'),
('e70c1682-d50e-4e24-8369-ed952f93ecd8','長齋月滿寄思黯','白居易','唐','唐诗','tang','','[]','一日不見如三月，一月相思如七年。',48,'全唐诗/poet.tang.24000.json','["一日不見如三月，一月相思如七年。", "似隔山河千里地，仍當風雨九秋天。", "明朝齋滿相尋去，挈榼抱衾同醉眠。"]'),
('b900332c-ebca-4e16-a556-9c7618b87a2c','冬夜對酒寄皇甫十','白居易','唐','唐诗','tang','','[]','霜殺中庭草，冰生後院池。',48,'全唐诗/poet.tang.24000.json','["霜殺中庭草，冰生後院池。", "有風空動樹，無葉可辭枝。", "十月苦長夜，百年強半時。", "新開一瓶酒，那得不相思。"]'),
('45715f0e-5271-42b5-bc67-69604b1ff5ce','歲除夜對酒','白居易','唐','唐诗','tang','','[]','衰翁歲除夜，對酒思悠然。',48,'全唐诗/poet.tang.24000.json','["衰翁歲除夜，對酒思悠然。", "草白經霜地，雲黃欲雪天。", "醉依香枕坐，慵傍煖爐眠。", "洛下閑來久，明朝是十年。"]'),
('269e39c7-8e54-43de-bad4-86909285f911','寄獻北都留守裴令公','白居易','唐','唐诗','tang','','[]','天上中台正，人間一品高。',288,'全唐诗/poet.tang.24000.json','["天上中台正，人間一品高。", "休明值堯舜，勳業過蕭曹。", "始擅文三捷，終兼武六韜。", "動人名赫赫，憂國意忉忉。", "盪蔡擒封豕，平齊斬巨鼇。", "兩河收土宇，四海定波濤。", "寵重移宮籥，恩新換閫旄。", "保釐東宅靜，守護北門牢。", "晉國封疆闊，幷州士馬豪。", "胡兵驚赤幟，邊雁避烏號。", "令下流如水，仁霑澤似膏。", "路喧歌五袴，軍醉感單醪。", "將校森貔武，賓僚儼雋髦。", "客無煩夜柝，吏不犯秋毫。", "神在臺駘助，魂亡獫狁逃。", "德星銷彗孛，霖雨滅腥臊。", "烽戍高臨代，關河遠控洮。", "汾雲晴漠漠，朔吹冷颾颾。", "豹尾交牙戟，蚪鬚捧佩刀。", "通天白犀帶，照地紫麟袍。", "羌管吹楊柳，燕姬酌蒲萄。", "銀含鑿落醆，金屑琵琶槽。", "遙想從軍樂，應忘報國勞。", "紫微留北闕，綠野寄東臯。"]'),
('6555677c-1bfc-4c14-bd1a-97464811f003','和東川楊慕巢尚書府中獨坐感戚在懷見寄十四韻','白居易','唐','唐诗','tang','','[]','我是知君者，君今意若何。',168,'全唐诗/poet.tang.24000.json','["我是知君者，君今意若何。", "窮通時不定，苦樂事相和。", "東蜀歡殊渥，西江歎逝波。", "只緣榮貴極，翻使感傷多。", "行斷風驚雁，年侵日下坡。", "片心休慘戚，雙鬢已蹉跎。", "紫綬黃金印，青幢白玉珂。", "老將榮補貼，愁用道銷磨。", "外府饒杯酒，中堂有綺羅。", "應須引滿飲，何不放狂歌？", "錦水通巴峽，香山對洛河。", "將軍馳鐵馬，少傅步銅駝。", "深契憐松竹，高情憶薜蘿。", "懸車年甚遠，未敢故相過。"]'),
('7911d0ba-5c2c-4e76-9c99-c884396c093c','分司洛中多暇數與諸客宴遊醉後狂吟偶成十韻因招夢得賓客兼呈思黯奇章公','白居易','唐','唐诗','tang','','[]','性與時相遠，身將世兩忘。',120,'全唐诗/poet.tang.24000.json','["性與時相遠，身將世兩忘。", "寄名朝士籍，寓興少年場。", "老豈無談笑，貧猶有酒漿。", "隨時來伴侶，逐日用風光。", "數數遊何爽，些些病未妨。", "天教榮啓樂，人恕接輿狂。", "改業爲逋客，移家住醉鄉。", "不論招夢得，兼擬誘奇章。", "要路風波險，權門市井忙。", "世間無可戀，不是不思量。"]'),
('61a52053-8753-4961-917f-f95ed1c3bea8','小歲日喜談氏外孫女孩滿月','白居易','唐','唐诗','tang','','[]','今旦夫妻喜，他人豈得知。',72,'全唐诗/poet.tang.24000.json','["今旦夫妻喜，他人豈得知。", "自嗟生女晚，敢訝見孫遲。", "物以稀爲貴，情因老更慈。", "新年逢吉日，滿月乞名時。", "桂燎熏花果，蘭湯洗玉肌。", "懷中有可抱，何必是男兒。"]'),
('f32d7165-5a28-43c4-8559-5de69bd00c7f','閑吟贈皇甫郎中親家翁','白居易','唐','唐诗','tang','','[]','誰能嗟歎光陰暮，豈復憂愁活計貧。',64,'全唐诗/poet.tang.24000.json','["誰能嗟歎光陰暮，豈復憂愁活計貧。", "忽忽不知頭上事，時時猶憶眼中人。", "早爲良友非交勢，晚接嘉姻不失親。", "最喜兩家婚嫁畢，一時抽得尚平身。"]'),
('32277eaf-e49a-4772-97f7-157aa485f592','夢得臥病攜酒相尋先以此寄','白居易','唐','唐诗','tang','','[]','病來知少客，誰可以爲娛。',48,'全唐诗/poet.tang.24000.json','["病來知少客，誰可以爲娛。", "日晏開門未，秋寒有酒無。", "自宜相慰問，何必待招呼。", "小疾無妨飲，還須挈一壺。"]'),
('416db338-76c7-40c3-b52a-b4543a4df824','酬思黯戲贈同用狂字','白居易','唐','唐诗','tang','','[]','鍾乳三千兩，金釵十二行。',48,'全唐诗/poet.tang.24000.json','["鍾乳三千兩，金釵十二行。", "妬他心似火，欺我鬢如霜。", "慰老資歌笑，銷愁仰酒漿。", "眼看狂不得，狂得且須狂。"]'),
('42cd174f-9d4a-4b03-90f9-ce1018fc0519','又戲荅絕句','白居易','唐','唐诗','tang','','[]','狂夫與我兩相忘，故態些些亦不妨。',32,'全唐诗/poet.tang.24000.json','["狂夫與我兩相忘，故態些些亦不妨。", "縱酒放歌聊自樂，接輿爭解教人狂。"]'),
('f85622f9-3067-4311-bd3c-12e69a6649e8','令狐相公與夢得交情素深眷予分亦不淺一聞薨逝相顧泫然旋有使來得前月未歿之前數日書及詩寄贈夢得哀吟悲歎寄情于詩詩成示予感而繼和','白居易','唐','唐诗','tang','','[]','緘題重疊語殷勤，存沒交親自此分。',64,'全唐诗/poet.tang.24000.json','["緘題重疊語殷勤，存沒交親自此分。", "前月使來猶理命，今朝詩到是遺文。", "銀鉤見晚書無報，玉樹埋深哭不聞。", "最感一行絕筆字，尚言千萬樂天君。"]'),
('2edea3aa-144f-4168-b760-2517740699b0','洛下雪中頻與劉李二賓客宴集因寄汴州李尚書','白居易','唐','唐诗','tang','','[]','水南水北雪紛紛，雪裏歡遊莫厭頻。',64,'全唐诗/poet.tang.24000.json','["水南水北雪紛紛，雪裏歡遊莫厭頻。", "日日暗來唯老病，年年少去是交親。", "碧氈帳暖梅花濕，紅燎爐香竹葉春。", "今日鄒枚俱在洛，梁園置酒召何人。"]'),
('ce7edb41-4bd3-4bc1-98e6-943f7c0ac145','看夢得題荅李侍郎詩詩中有文星之句因戲和之','白居易','唐','唐诗','tang','','[]','看題錦繡報瓊瓌，俱是人天第一才。',32,'全唐诗/poet.tang.24000.json','["看題錦繡報瓊瓌，俱是人天第一才。", "好遣文星守躔次，亦須防有客星來。"]'),
('ed7c5788-2d19-4cce-8b33-161f3db13e3d','閑適','白居易','唐','唐诗','tang','','[]','祿俸優饒官不卑，就中閑適是分司。',64,'全唐诗/poet.tang.24000.json','["祿俸優饒官不卑，就中閑適是分司。", "風光暖助遊行處，雨雪寒供飲宴時。", "肥馬輕裘還且有，麤歌薄酒亦相隨。", "微躬所要今皆得，只是蹉跎得校遲。"]'),
('55109dea-a8a7-4de0-9e14-ab4d7c4f1a50','戲荅思黯','白居易','唐','唐诗','tang','','[]','何時得見十三弦，待取無雲有月天。',32,'全唐诗/poet.tang.24000.json','["何時得見十三弦，待取無雲有月天。", "願得金波明似鏡，鏡中照出月中仙。"]'),
('ea0eef3c-8815-49b5-aafa-96bc981679e2','酬裴令公贈馬相戲','白居易','唐','唐诗','tang','','[]','安石風流無奈何，欲將赤驥換青娥。',32,'全唐诗/poet.tang.24000.json','["安石風流無奈何，欲將赤驥換青娥。", "不辭便送東山去，臨老何人與唱歌。"]'),
('c06ae7be-028e-4861-b29c-e081eb3fa8bd','新歲贈夢得','白居易','唐','唐诗','tang','','[]','暮齒忽將及，同心私自憐。',48,'全唐诗/poet.tang.24000.json','["暮齒忽將及，同心私自憐。", "漸衰宜減食，已喜更加年。", "紫綬行聯袂，籃轝出比肩。", "與君同甲子，歲酒合誰先。"]'),
('d5492348-63aa-4354-b6a0-b0940e15a419','早春持齋荅皇甫十見贈','白居易','唐','唐诗','tang','','[]','正月晴和風氣新，紛紛已有醉遊人。',32,'全唐诗/poet.tang.24000.json','["正月晴和風氣新，紛紛已有醉遊人。", "帝城花笑長齋客，三十年來負早春。"]'),
('53b02afe-b045-4c34-a0d5-f9db04e489dc','戲贈夢得兼呈思黯','白居易','唐','唐诗','tang','','[]','霜鬢莫欺今老矣，一杯莫笑便陶然。',64,'全唐诗/poet.tang.24000.json','["霜鬢莫欺今老矣，一杯莫笑便陶然。", "陳郎中處爲高戶，裴使君前作少年。", "顧我獨狂多自哂，與君同病最相憐。", "月終齋滿誰開素，須擬奇章置一筵。"]'),
('3c71472b-cd6e-4f4e-a90d-2f8a83136b39','早春憶遊思黯南莊因寄長句','白居易','唐','唐诗','tang','','[]','南莊勝處心常憶，借問軒車早晚遊。',64,'全唐诗/poet.tang.24000.json','["南莊勝處心常憶，借問軒車早晚遊。", "美景難忘竹廊下，好風爭奈柳橋頭。", "冰消見水多於地，雪霽看山盡入樓。", "若待春深始同賞，鶯殘花落却堪愁。"]'),
('08bee2c4-6577-460e-8223-ca08334ce6c0','酬皇甫十早春對雪見贈','白居易','唐','唐诗','tang','','[]','漠漠復雰雰，東風散玉塵。',48,'全唐诗/poet.tang.24000.json','["漠漠復雰雰，東風散玉塵。", "明催竹窗曉，寒退柳園春。", "綠醞香堪憶，紅爐暖可親。", "忍心三兩日，莫作破齋人。"]'),
('625ab649-4839-418f-a65b-4c64feb00f5e','奉和思黯自題南莊見示兼呈夢得','白居易','唐','唐诗','tang','','[]','謝家別墅最新奇，山展屏風花夾籬。',64,'全唐诗/poet.tang.24000.json','["謝家別墅最新奇，山展屏風花夾籬。", "曉月漸沈橋脚底，晨光初照屋梁時。", "臺頭有酒鶯呼客，水面無塵風洗池。", "除却吟詩兩閑客，此中情狀更誰知。"]'),
('45fdc966-f43d-4336-b41c-bcc3b52f5273','送蘄春李十九使君赴郡','白居易','唐','唐诗','tang','','[]','可憐官職好文詞，五十專城未是遲。',64,'全唐诗/poet.tang.24000.json','["可憐官職好文詞，五十專城未是遲。", "曉日鏡前無白髮，春風門外有紅旗。", "郡中何處堪攜酒，席上誰人解和詩。", "唯共交親開口笑，知君不及洛陽時。"]'),
('cc4f12d4-0e21-46e5-a83b-38544402c509','自題酒庫','白居易','唐','唐诗','tang','','[]','野鶴一辭籠，虛舟長任風。',48,'全唐诗/poet.tang.24000.json','["野鶴一辭籠，虛舟長任風。", "送愁還鬧處，移老入閑中。", "身更求何事，天將富此翁。", "此翁何處富，酒庫不曾空。"]'),
('877bdb1e-9884-4059-9cc0-bff7e9364f72','寒食日寄楊東川','白居易','唐','唐诗','tang','','[]','不知楊六逢寒食，作底歡娛過此辰。',64,'全唐诗/poet.tang.24000.json','["不知楊六逢寒食，作底歡娛過此辰。", "兜率寺高宜望月，嘉陵江近好遊春。", "蠻旗似火行隨馬，蜀妓如花坐遶身。", "不使黔婁夫婦看，誇張富貴向何人。"]'),
('2af83135-180d-4983-938d-f195dc4451fc','醉後聽唱桂華曲','白居易','唐','唐诗','tang','','[]','桂華詞意苦丁寧，唱到常娥醉便醒。',32,'全唐诗/poet.tang.24000.json','["桂華詞意苦丁寧，唱到常娥醉便醒。", "此是人間腸斷曲，莫教不得意人聽。"]'),
('3e87f8bd-3832-4845-916e-6247ec4ff784','酬夢得以予五月長齋延僧徒絕賓友見戲十韻','白居易','唐','唐诗','tang','','[]','賓客懶逢迎，翛然池館清。',120,'全唐诗/poet.tang.24000.json','["賓客懶逢迎，翛然池館清。", "簷閑空燕語，林靜未蟬鳴。", "葷血還休食，杯觴亦罷傾。", "三春多放逸，五月暫修行。", "香印朝煙細，紗燈夕焰明。", "交遊諸長老，師事古先生。", "禪後心彌寂，齋來體更輕。", "不唯忘肉味，兼擬滅風情。", "蒙以聲聞待，難將戲論爭。", "虛空若有佛，靈運恐先成。"]'),
('fe2d8cab-b2da-4652-8bcf-98c58e85a4f7','奉和裴令公三月上巳日遊太原龍泉憶去歲禊洛見示之作','白居易','唐','唐诗','tang','','[]','去歲暮春上巳，共泛洛水中流。',70,'全唐诗/poet.tang.24000.json','["去歲暮春上巳，共泛洛水中流。", "今歲暮春上巳，獨立香山下頭。", "風光閑寂寂，旌斾遠悠悠。", "丞相府歸晉國，太行山礙幷州。", "鵬背負天龜曳尾，雲泥不可得同遊。"]'),
('e53ca024-bac4-44c1-9fb9-ef5f8caa5c8f','又和令公新開龍泉晉水二池','白居易','唐','唐诗','tang','','[]','舊有潢汚泊，今爲白水塘。',48,'全唐诗/poet.tang.24000.json','["舊有潢汚泊，今爲白水塘。", "笙歌聞四面，樓閣在中央。", "春變煙波色，晴添樹木光。", "龍泉信爲美，莫忘午橋莊。"]'),
('8d6b3c0d-50b9-4a5d-9260-f9793744a54e','早夏曉興贈夢得','白居易','唐','唐诗','tang','','[]','窗明簾薄透朝光，臥整巾簪起下牀。',64,'全唐诗/poet.tang.24000.json','["窗明簾薄透朝光，臥整巾簪起下牀。", "背壁燈殘經宿焰，開箱衣帶隔年香。", "無情亦任他春去，不醉爭銷得晝長。", "一部清商一壺酒，與君明日暖新堂。"]'),
('2b6db47a-31ac-454f-abb0-4d42d89f4cf5','春日題乾元寺上方最高峰亭','白居易','唐','唐诗','tang','','[]','危亭絕頂四無鄰，見盡三千世界春。',80,'全唐诗/poet.tang.24000.json','["危亭絕頂四無鄰，見盡三千世界春。", "但覺虛空無障礙，不知高下幾由旬。", "迴看官路三條線，却望都城一片塵。", "賓客暫遊無半日，王侯不到便終身。", "始知天造空閑境，不爲忙人富貴人。"]'),
('5a23f935-734e-424b-b878-94c7abb31547','奉和思黯相公以李蘇州所寄太湖石奇狀絕倫因題二十韻見示兼呈夢得','白居易','唐','唐诗','tang','','["\u592a\u6e56"]','錯落復崔嵬，蒼然玉一堆。',240,'全唐诗/poet.tang.24000.json','["錯落復崔嵬，蒼然玉一堆。", "峰駢仙掌出，罅坼劒門開。", "峭頂高危矣，盤根下壯哉。", "精神欺竹樹，氣色壓亭臺。", "隱起磷磷狀，凝成瑟瑟胚。", "廉稜露鋒刃，清越扣瓊瑰。", "岌嶪形將動，巍峩勢欲摧。", "奇應潛鬼怪，靈合蓄雲雷。", "黛潤霑新雨，斑明點古苔。", "未曾栖鳥雀，不肯染塵埃。", "尖削琅玕筍，窪剜瑪瑙罍。", "海神移碣石，畫障簇天台。", "在世爲尤物，如人負逸才。", "渡江一葦載，入洛五丁推。", "出處雖無意，升沈亦有媒。", "拔從水府底，置向相庭隈。", "對稱吟詩句，看宜把酒杯。", "終隨金礪用，不學玉山頹。", "疎傅心偏愛，園公眼屢迴。", "共嗟無此分，虛管太湖來。"]'),
('4adabd9f-fbac-40c4-ae32-3cb2f338d127','奉和思黯相公雨後林園四韻見示','白居易','唐','唐诗','tang','','[]','新晴夏景好，復此池邊地。',48,'全唐诗/poet.tang.24000.json','["新晴夏景好，復此池邊地。", "煙樹綠含滋，水風清有味。", "便成林下隱，都忘門前事。", "騎吏引歸軒，始知身富貴。"]'),
('bd69db74-268c-466f-94df-26277d4c9afe','晚夏閑居絕無賓客欲尋夢得先寄此詩','白居易','唐','唐诗','tang','','[]','魚筍朝餐飽，蕉紗暑服輕。',72,'全唐诗/poet.tang.24000.json','["魚筍朝餐飽，蕉紗暑服輕。", "欲爲窗下寢，先傍水邊行。", "晴引鶴雙舞，秋生蟬一聲。", "無人解相訪，有酒共誰傾。", "老更諳時事，閑多見物情。", "只應劉與白，二叟自相迎。"]'),
('27b3c724-d5ec-4504-97a4-a9df022770e7','寄李蘄州','白居易','唐','唐诗','tang','','[]','下車書奏龔黃課，動筆詩傳鮑謝風。',64,'全唐诗/poet.tang.24000.json','["下車書奏龔黃課，動筆詩傳鮑謝風。", "江郡謳謠誇杜母，洛城歡會憶車公。", "笛愁春盡梅花裏，簟冷秋生薤葉中。", "不道蘄州歌酒少，使君難稱與誰同。"]'),
('04c605e1-caf5-4d03-958b-e1938a1ae10d','酬思黯相公晚夏雨後感秋見贈','白居易','唐','唐诗','tang','','[]','暮去朝來無歇期，炎涼闇向雨中移。',64,'全唐诗/poet.tang.24000.json','["暮去朝來無歇期，炎涼闇向雨中移。", "夜長祗合愁人覺，秋冷先應瘦客知。", "兩幅彩箋揮逸翰，一聲寒玉振清辭。", "無憂無病身榮貴，何故沈吟亦感時。"]'),
('a9721830-09b6-4f5c-9953-b5d260b54977','久雨閑悶對酒偶吟','白居易','唐','唐诗','tang','','[]','淒淒苦雨暗銅駞，嫋嫋涼風起漕河。',64,'全唐诗/poet.tang.24000.json','["淒淒苦雨暗銅駞，嫋嫋涼風起漕河。", "自夏及秋晴日少，從朝至暮悶時多。", "鷺臨池立窺魚笱，隼傍林飛拂雀羅。", "賴有杯中神聖物，百憂無奈十分何。"]'),
('8776313d-c1bd-4c33-9bfe-4b5c393189a2','雨後秋涼','白居易','唐','唐诗','tang','','[]','夜來秋雨後，秋氣颯然新。',48,'全唐诗/poet.tang.24000.json','["夜來秋雨後，秋氣颯然新。", "團扇先辭手，生衣不著身。", "更添砧引思，難與簟相親。", "此境誰偏覺，貧閑老瘦人。"]'),
('1b76a756-3d2f-457f-a63c-b2d3ffd09c55','酬夢得早秋夜對月見寄','白居易','唐','唐诗','tang','','[]','吾衰寡情趣，君病懶經過。',48,'全唐诗/poet.tang.24000.json','["吾衰寡情趣，君病懶經過。", "其奈西樓上，新秋明月何。", "庭蕪淒白露，池色澹金波。", "況是初長夜，東城砧杵多。"]'),
('fe9ae8b7-09f0-4ad6-8ee4-e49ee238809c','題謝公東山障子','白居易','唐','唐诗','tang','','[]','賢愚共在浮生內，貴賤同趨羣動間。',64,'全唐诗/poet.tang.24000.json','["賢愚共在浮生內，貴賤同趨羣動間。", "多見忙時已衰病，少聞健日肯休閑。", "鷹飢受緤從難退，鶴老乘軒亦不還。", "唯有風流謝安石，拂衣攜妓入東山。"]'),
('1399a743-11cd-4b38-8e1d-efdcf9dafc5a','謝楊東川寄衣服','白居易','唐','唐诗','tang','','[]','年年衰老交遊少，處處蕭條書信稀。',32,'全唐诗/poet.tang.24000.json','["年年衰老交遊少，處處蕭條書信稀。", "唯有巢兄不相忘，春茶未斷寄秋衣。"]'),
('03faced2-dc9b-47e2-a8f5-4841245a8b7a','詠懷寄皇甫朗之','白居易','唐','唐诗','tang','','[]','老大多情足往還，招僧待客夜開關。',64,'全唐诗/poet.tang.24000.json','["老大多情足往還，招僧待客夜開關。", "學調氣後衰中健，不用心來鬧處閑。", "養病未能辭薄俸，忘名何必入深山。", "與君別有相知分，同置身於木雁間。"]'),
('56442323-a7db-4c8c-8654-82e08f81daa9','東城晚歸','白居易','唐','唐诗','tang','','[]','一條邛杖懸龜榼，雙角吳童控馬銜。',32,'全唐诗/poet.tang.24000.json','["一條邛杖懸龜榼，雙角吳童控馬銜。", "晚入東城誰識我，短靴低帽白蕉衫。"]'),
('22074ea5-f85d-4525-8aef-48f6bcf9b733','與夢得沽酒閑飲且約後期','白居易','唐','唐诗','tang','','["\u53cb\u60c5", "\u6101\u82e6"]','少時猶不憂生計，老後誰能惜酒錢。',64,'全唐诗/poet.tang.24000.json','["少時猶不憂生計，老後誰能惜酒錢。", "共把十千沽一斗，相看七十欠三年。", "閑徵雅令窮經史，醉聽清吟勝管弦。", "更待菊黃家醞熟，共君一醉一陶然。"]'),
('87a10927-f96a-4ae2-b70d-7b41699a860a','與牛家妓樂雨後合宴','白居易','唐','唐诗','tang','','[]','玉管清弦聲旖旎，翠釵紅袖坐參差。',64,'全唐诗/poet.tang.24000.json','["玉管清弦聲旖旎，翠釵紅袖坐參差。", "兩家合奏洞房夜，八月連陰秋雨時。", "歌臉有情凝睇久，舞腰無力轉帬遲。", "人間歡樂無過此，上界西方即不知。"]'),
('6b33c0f3-e255-439b-8199-f8ed1993cec8','和楊六尚書喜兩弟漢公轉吳興魯士賜章服命賓開宴用慶恩榮賦長句見示','白居易','唐','唐诗','tang','','[]','華筵賀客日紛紛，劒外歡娛洛下聞。',66,'全唐诗/poet.tang.24000.json','["華筵賀客日紛紛，劒外歡娛洛下聞。", "朱紱寵光新照地，彤襜喜氣遠凌雲。", "榮聯花萼詩難和，樂助塤箎酒易[醺]。", "感羨料應知我意，今生此事不如君。"]'),
('285171a0-cd41-498b-82dc-ded9ec1c22e2','自詠','白居易','唐','唐诗','tang','','[]','鬚白面微紅，醺醺半醉中。',48,'全唐诗/poet.tang.24000.json','["鬚白面微紅，醺醺半醉中。", "百年隨手過，萬事轉頭空。", "臥疾瘦居士，行歌狂老翁。", "仍聞好事者，將我畫屏風。"]'),
('0a77c6de-1e8a-4530-ab13-9e58a269724d','夢得相過援琴命酒因彈秋思偶詠所懷兼寄繼之待價二相府','白居易','唐','唐诗','tang','','[]','閑居靜侶偶相招，小飲初酣琴欲調。',64,'全唐诗/poet.tang.24000.json','["閑居靜侶偶相招，小飲初酣琴欲調。", "我正風前弄秋思，君應天上聽雲韶。", "時和始見陶鈞力，物遂方知盛聖朝。", "雙鳳栖梧魚在藻，飛沈隨分各逍遙。"]'),
('f7965882-61f3-48d2-9906-55bbc354c5d7','九月八日酬皇甫十見贈','白居易','唐','唐诗','tang','','[]','君方對酒綴詩章，我正持齋坐道場。',64,'全唐诗/poet.tang.24000.json','["君方對酒綴詩章，我正持齋坐道場。", "處處追遊雖不去，時時吟詠亦無妨。", "霜蓬舊鬢三分白，露菊新花一半黃。", "惆悵東籬不同醉，陶家明日是重陽。"]'),
('c90e147d-c139-49dd-9f93-c4da0348e9d3','慕巢尚書書云室人欲爲置一歌者非所安也以詩相報因而和之','白居易','唐','唐诗','tang','','[]','東川已過二三春，南國須求一兩人。',64,'全唐诗/poet.tang.24000.json','["東川已過二三春，南國須求一兩人。", "富貴大都多老大，歡娛太半爲親賓。", "如愁翠黛應堪重，買笑黃金莫訴貧。", "他日相逢一杯酒，尊前還要落梁塵。"]'),
('a58e6a3f-27fc-4ccc-8985-d1ad2c49daa5','杪秋獨夜','白居易','唐','唐诗','tang','','[]','無限少年非我伴，可憐清夜與誰同。',64,'全唐诗/poet.tang.24000.json','["無限少年非我伴，可憐清夜與誰同。", "歡娛牢落中心少，親故凋零四面空。", "紅葉樹飄風起後，白鬚人立月明中。", "前頭更有蕭條物，老菊衰蘭三兩叢。"]'),
('04eb1ac2-3eca-4e96-8f3a-a37dbb02f274','憑李睦州訪徐凝山人','白居易','唐','唐诗','tang','','[]','郡守輕詩客，鄉人薄釣翁。',24,'全唐诗/poet.tang.24000.json','["郡守輕詩客，鄉人薄釣翁。", "解憐徐處士，唯有李郎中。"]'),
('80cbc4ae-f7cc-418c-8588-e0230f2d4c99','蘇州故吏','白居易','唐','唐诗','tang','','[]','江南故吏別來久，今日池邊識我無。',32,'全唐诗/poet.tang.24000.json','["江南故吏別來久，今日池邊識我無。", "不獨使君頭似雪，華亭鶴死白蓮枯。"]'),
('8f8b4c6e-95ab-43d3-b9a1-9d8f8c1d701d','得楊湖州書頗誇撫民接賓縱酒題詩因以絕句戲之','白居易','唐','唐诗','tang','','[]','豈獨愛民兼愛客，不唯能飲又能文。',32,'全唐诗/poet.tang.24000.json','["豈獨愛民兼愛客，不唯能飲又能文。", "白蘋洲上春傳語，柳使君輸楊使君。"]'),
('90858650-e9d6-47a3-83ed-72408ed80c74','天宮閣秋晴晚望','白居易','唐','唐诗','tang','','[]','洛城秋霽後，梵閣暮登時。',48,'全唐诗/poet.tang.24000.json','["洛城秋霽後，梵閣暮登時。", "此日風煙好，今秋節候遲。", "霞光紅泛豔，樹影碧參差。", "莫慮言歸晚，牛家有宿期。"]'),
('b9a8f048-0419-426a-890b-bbd634251130','酬夢得暮秋晴夜對月相憶','白居易','唐','唐诗','tang','','[]','霽月光如練，盈庭復滿池。',48,'全唐诗/poet.tang.24000.json','["霽月光如練，盈庭復滿池。", "秋深無熱後，夜淺未寒時。", "露葉團荒菊，風枝落病棃。", "相思懶相訪，應是各年衰。"]'),
('ae885dc7-7a55-4801-9405-38211ef4e6ee','同夢得和思黯見贈來詩中先敘三人同讌之歡次有歎鬢髮漸衰嫌孫子催老之意因酬妍唱兼吟鄙懷','白居易','唐','唐诗','tang','','[]','醉伴騰騰白與劉，何朝何夕不同遊。',64,'全唐诗/poet.tang.24000.json','["醉伴騰騰白與劉，何朝何夕不同遊。", "留連燈下明猶飲，斷送尊前倒即休。", "催老莫嫌孫稚長，加年須喜鬢毛秋。", "教他伯道爭存活，無子無孫亦白頭。"]'),
('3873d0bb-b3ae-4e80-bfb1-b11621b84feb','聽歌','白居易','唐','唐诗','tang','','[]','管妙弦清歌入雲，老人合眼醉醺醺。',32,'全唐诗/poet.tang.24000.json','["管妙弦清歌入雲，老人合眼醉醺醺。", "誠知不及當年聽，猶覺聞時勝不聞。"]'),
('6ee98955-3021-49da-823c-a5f12aa59d35','三年冬隨事鋪設小堂寢處稍似穩暖因念衰病偶吟所懷','白居易','唐','唐诗','tang','','[]','小宅非全陋，中堂不甚卑。',96,'全唐诗/poet.tang.24000.json','["小宅非全陋，中堂不甚卑。", "聊堪會親族，足以貯妻兒。", "暖帳迎冬設，溫爐向夜施。", "裘新青兔褐，褥軟白猨皮。", "似鹿眠深草，如雞宿穩枝。", "逐身安枕席，隨事有屏帷。", "病致衰殘早，貧營活計遲。", "由來蠶老後，方是繭成時。"]'),
('e200b631-9601-4e81-8da2-f4d863946124','初冬即事呈夢得','白居易','唐','唐诗','tang','','[]','青氈帳暖喜微雪，紅地爐深宜早寒。',64,'全唐诗/poet.tang.24000.json','["青氈帳暖喜微雪，紅地爐深宜早寒。", "走筆小詩能和否，潑醅新酒試嘗看。", "僧來乞食因留宿，客到開尊便共歡。", "臨老交親零落盡，希君恕我取人寬。"]'),
('04cd5186-589b-47df-8d3c-9a1706cf7fd0','自罷河南已換七尹每一入府悵然舊遊因宿內廳偶題西壁兼呈韋尹常侍','白居易','唐','唐诗','tang','','[]','每入河南府，依然似到家。',72,'全唐诗/poet.tang.24000.json','["每入河南府，依然似到家。", "杯嘗七尹酒，樹看十年花。", "且健須歡喜，雖衰莫歎嗟。", "迎門無故吏，侍坐有新娃。", "暖閣謀宵宴，寒庭放晚衙。", "主人留宿定，一任夕陽斜。"]'),
('00f7e2be-e515-412d-8e4e-aeb6e4923fb5','天寒晚起引酌詠懷寄許州王尚書汝州李常侍','白居易','唐','唐诗','tang','','[]','葉覆冰池雪滿山，日高慵起未開關。',64,'全唐诗/poet.tang.24000.json','["葉覆冰池雪滿山，日高慵起未開關。", "寒來更亦無過醉，老後何由可得閑。", "四海故交唯許汝，十年貧健是樊蠻。", "相思莫忘櫻桃會，一放狂歌一破顏。"]'),
('b64f9672-3afb-44e4-a3e8-e6f516d86f10','四年春','白居易','唐','唐诗','tang','','[]','柳梢黃嫩草芽新，又入開成第四春。',64,'全唐诗/poet.tang.24000.json','["柳梢黃嫩草芽新，又入開成第四春。", "近日放慵多不出，少年嫌老可相親。", "分司吉傅頻過舍，致仕崔卿擬卜鄰。", "時輩推遷年事到，往還多是白頭人。"]'),
('c3f8f836-1304-4efc-8d0d-fbe54cee54af','白髮','白居易','唐','唐诗','tang','','[]','白髮生來三十年，而今鬚鬢盡皤然。',64,'全唐诗/poet.tang.24000.json','["白髮生來三十年，而今鬚鬢盡皤然。", "歌吟終日如狂叟，衰疾多時似瘦仙。", "八戒夜持香火印，三光朝念蘂珠篇。", "其餘便被春收拾，不作閑遊即醉眠。"]'),
('49a18eb8-0e61-41f1-a5c8-fe4af24c4891','追歡偶作','白居易','唐','唐诗','tang','','[]','追歡逐樂少閑時，補貼平生得事遲。',80,'全唐诗/poet.tang.24000.json','["追歡逐樂少閑時，補貼平生得事遲。", "何處花開曾後看，誰家酒熟不先知。", "石樓月下吹蘆管，金谷風前舞柳枝。", "十聽春啼變鶯舌，三嫌老醜換蛾眉。", "樂天一過難知分，猶自咨嗟兩鬢絲。"]'),
('8a78dbdf-7647-4db0-90b8-04ea7003a64a','公垂尚書以白馬見寄光潔穩善以詩謝之','白居易','唐','唐诗','tang','','[]','翩翩白馬稱金羈，領綴銀花尾曳絲。',64,'全唐诗/poet.tang.24000.json','["翩翩白馬稱金羈，領綴銀花尾曳絲。", "毛色鮮明人盡愛，性靈馴善主偏知。", "免將妾換慙來處，試使奴牽欲上時。", "不蹶不驚行步穩，最宜山簡醉中騎。"]'),
('bb96ce01-700a-4fb5-9557-8848041d43fe','西樓獨立','白居易','唐','唐诗','tang','','[]','身著白衣頭似雪，時時醉立小樓中。',32,'全唐诗/poet.tang.24000.json','["身著白衣頭似雪，時時醉立小樓中。", "路人迴顧應相怪，十一年來見此翁。"]'),
('94be7709-b798-4de7-bb59-673b3b770a34','書事詠懷','白居易','唐','唐诗','tang','','[]','官俸將生計，雖貧豈敢嫌。',72,'全唐诗/poet.tang.24000.json','["官俸將生計，雖貧豈敢嫌。", "金多輸陸賈，酒足勝陶潛。", "牀煖僧敷坐，樓晴妓卷簾。", "日遭齋破用，春賴閏加添。", "老向歡彌切，狂於飲不廉。", "十年閑未足，亦恐涉無厭。"]'),
('4c383d54-c121-4eac-815c-1dbd21ca38f2','酬夢得比萱草見贈','白居易','唐','唐诗','tang','','[]','杜康能散悶，萱草解忘憂。',48,'全唐诗/poet.tang.24000.json','["杜康能散悶，萱草解忘憂。", "借問萱逢杜，何如白見劉。", "老衰勝少夭，閑樂笑忙愁。", "試問同年內，何人得白頭。"]'),
('6cec7855-9481-4adf-b384-aa4e7594efab','問皇甫十','白居易','唐','唐诗','tang','','[]','苦樂心由我，窮通命任他。',48,'全唐诗/poet.tang.24000.json','["苦樂心由我，窮通命任他。", "坐傾張翰酒，行唱接輿歌。", "榮盛傍看好，優閑自適多。", "知君能斷事，勝負兩如何。"]'),
('3ad3a839-62f3-4cb3-9bd0-962dded62589','早春獨登天宮閣','白居易','唐','唐诗','tang','','[]','天宮日暖閣門開，獨上迎春飲一杯。',32,'全唐诗/poet.tang.24000.json','["天宮日暖閣門開，獨上迎春飲一杯。", "無限遊人遙怪我，緣何最老最先來。"]'),
('bd397d21-27fd-4d22-854e-584a0074454e','送蘇州李使君赴郡二絕句 一','白居易','唐','唐诗','tang','','[]','憶拋印綬辭吳郡，衰病當時已有餘。',32,'全唐诗/poet.tang.24000.json','["憶拋印綬辭吳郡，衰病當時已有餘。", "今日賀君兼自喜，八迴看換舊銅魚。"]'),
('2b13fb95-626c-4f35-a24f-161dc523a0b0','送蘇州李使君赴郡二絕句 二','白居易','唐','唐诗','tang','','[]','館娃宮深春日長，烏鵲橋高秋夜涼。',32,'全唐诗/poet.tang.24000.json','["館娃宮深春日長，烏鵲橋高秋夜涼。", "風月不知人世變，奉君直似奉吳王。"]'),
('203dd367-29fc-418a-9488-dca20941240f','長洲曲新詞','白居易','唐','唐诗','tang','','[]','茂苑綺羅佳麗地，女湖桃李豔陽時。',32,'全唐诗/poet.tang.24000.json','["茂苑綺羅佳麗地，女湖桃李豔陽時。", "心奴已死胡容老，後輩風流是阿誰。"]'),
('e0b89b88-13fa-4f91-9db8-eb46ed6f2930','憶江南詞三首 一','白居易','唐','唐诗','tang','','[]','江南好，風景舊曾諳。',10,'全唐诗/poet.tang.24000.json','["江南好，風景舊曾諳。"]'),
('e58ff68f-386c-4a12-b97a-965eb7958ca0','憶江南詞三首 二','白居易','唐','唐诗','tang','','[]','江南憶，最憶是杭州。',10,'全唐诗/poet.tang.24000.json','["江南憶，最憶是杭州。"]'),
('a80c92aa-57ea-4786-a155-4b6b3d484e64','憶江南詞三首 三','白居易','唐','唐诗','tang','','[]','江南憶，其次憶吳宮。',10,'全唐诗/poet.tang.24000.json','["江南憶，其次憶吳宮。"]'),
('429667fc-08e7-490a-a87b-14a7323ca688','病中詩十五首 初病風','白居易','唐','唐诗','tang','','[]','六十八衰翁，乘衰百疾攻。',48,'全唐诗/poet.tang.24000.json','["六十八衰翁，乘衰百疾攻。", "朽株難免蠹，空穴易來風。", "肘痹宜生柳，頭旋劇轉蓬。", "恬然不動處，虛白在胷中。"]'),
('95e07da8-bbb2-441c-b208-dec16a5bd882','病中詩十五首 枕上作','白居易','唐','唐诗','tang','','[]','風疾侵凌臨老頭，血凝筋滯不調柔。',96,'全唐诗/poet.tang.24000.json','["風疾侵凌臨老頭，血凝筋滯不調柔。", "甘從此後支離臥，賴是從前爛漫遊。", "迴思往事紛如夢，轉覺餘生杳若浮。", "浩氣自能充靜室，驚飆何必蕩虛舟。", "腹空先進松花酒，膝冷重裝桂布裘。", "若問樂天憂病否，樂天知命了無憂。"]'),
('ea01d3d1-0257-4a25-89d4-599fe310addf','病中詩十五首 荅閑上人來問因何風疾','白居易','唐','唐诗','tang','','[]','一牀方丈向陽開，勞動文殊問疾來。',32,'全唐诗/poet.tang.24000.json','["一牀方丈向陽開，勞動文殊問疾來。", "欲界凡夫何足道，四禪天始免風災。"]'),
('2afa4a2b-d947-4575-a895-ddf92c1e4d31','病中詩十五首 病中五絕句 一','白居易','唐','唐诗','tang','','[]','世間生老病相隨，此事心中久自知。',32,'全唐诗/poet.tang.24000.json','["世間生老病相隨，此事心中久自知。", "今日行年將七十，猶須慙愧病來遲。"]'),
('55eb9051-846c-4295-94f5-4ffee3214054','病中詩十五首 病中五絕句 二','白居易','唐','唐诗','tang','','[]','方寸成灰鬢作絲，假如強健亦何爲。',32,'全唐诗/poet.tang.24000.json','["方寸成灰鬢作絲，假如強健亦何爲。", "家無憂累身無事，正是安閑好病時。"]'),
('4cf51eb9-76d4-4d88-bf7d-46505a3e19d1','病中詩十五首 病中五絕句 三','白居易','唐','唐诗','tang','','[]','李君墓上松應拱，元相池頭竹盡枯。',32,'全唐诗/poet.tang.24000.json','["李君墓上松應拱，元相池頭竹盡枯。", "多幸樂天今始病，不知合要苦治無。"]'),
('6848d03f-3d0e-4dae-b0ed-6645899f729b','病中詩十五首 病中五絕句 四','白居易','唐','唐诗','tang','','[]','目昏思寢即安眠，足軟妨行便坐禪。',32,'全唐诗/poet.tang.24000.json','["目昏思寢即安眠，足軟妨行便坐禪。", "身作醫王心是藥，不勞和扁到門前。"]'),
('831f46ab-a452-4de3-a264-6271026425e1','病中詩十五首 病中五絕句 五','白居易','唐','唐诗','tang','','[]','交親不要苦相憂，亦擬時時強出遊。',32,'全唐诗/poet.tang.24000.json','["交親不要苦相憂，亦擬時時強出遊。", "但有心情何用脚，陸乘肩轝水乘舟。"]'),
('01efda21-3c54-4fbf-a222-e79de3e5716a','病中詩十五首 送嵩客','白居易','唐','唐诗','tang','','[]','登山臨水分無期，泉石煙霞今屬誰。',32,'全唐诗/poet.tang.24000.json','["登山臨水分無期，泉石煙霞今屬誰。", "君到嵩陽吟此句，與教二十六峰知。"]'),
('1938a424-341f-4a2c-9fe5-786be01d323e','病中詩十五首 罷[灸]','白居易','唐','唐诗','tang','','[]','病身佛說將何喻，變滅須臾豈不聞。',34,'全唐诗/poet.tang.24000.json','["病身佛說將何喻，變滅須臾豈不聞。", "莫遣淨名知我笑，休將火艾[灸]浮雲。"]'),
('45e0b372-c3f1-4c6d-8537-75dbca4ed069','病中詩十五首 賣駱馬','白居易','唐','唐诗','tang','','[]','五年花下醉騎行，臨賣回頭嘶一聲。',32,'全唐诗/poet.tang.24000.json','["五年花下醉騎行，臨賣回頭嘶一聲。", "項籍顧騅猶解歎，樂天別駱豈無情。"]'),
('042f6a90-e4de-4b94-85ad-451b8d7a0325','病中詩十五首 別柳枝','白居易','唐','唐诗','tang','','[]','兩枝楊柳小樓中，嫋嫋多年伴醉翁。',32,'全唐诗/poet.tang.24000.json','["兩枝楊柳小樓中，嫋嫋多年伴醉翁。", "明日放歸歸去後，世間應不要春風。"]'),
('18b34c44-3006-438d-95ce-f6d5e8c33006','病中詩十五首 就暖偶酌戲諸詩酒舊侶','白居易','唐','唐诗','tang','','[]','低屏軟褥臥藤牀，舁向前軒就日陽。',64,'全唐诗/poet.tang.24000.json','["低屏軟褥臥藤牀，舁向前軒就日陽。", "一足任他爲外物，三杯自要沃中腸。", "頭風若見詩應愈，齒折仍誇笑不妨。", "細酌徐吟猶得在，舊遊未必便相忘。"]'),
('34abad4b-3030-45ff-be95-4a95bfb26f04','病中詩十五首 歲暮呈思黯相公皇甫朗之及夢得尚書','白居易','唐','唐诗','tang','','[]','歲暮皤然一老夫，十分流輩九分無。',32,'全唐诗/poet.tang.24000.json','["歲暮皤然一老夫，十分流輩九分無。", "莫嫌身病人扶侍，猶勝無身可遣扶。"]'),
('e673845c-b604-4175-99c7-9a98bc685ff4','病中詩十五首 自解','白居易','唐','唐诗','tang','','[]','房傳往世爲禪客王道前生應畫師。',47,'全唐诗/poet.tang.24000.json','["房傳往世爲禪客王道前生應畫師。", "我亦定中觀宿命，多生債負是歌詩。", "不然何故狂吟詠，病後多於未病時。"]'),
('6d581d39-7c63-4109-84aa-7ab12472e229','歲暮病懷贈夢得','白居易','唐','唐诗','tang','','[]','十年四海故交親，零落唯殘兩病身。',64,'全唐诗/poet.tang.24000.json','["十年四海故交親，零落唯殘兩病身。", "共遣數奇從是命，同教步蹇有何因。", "眼隨老減嫌長夜，體待陽舒望早春。", "新樂堂前舊池上，相過亦不要他人。"]'),
('a3e14106-ad33-4839-8d56-331791812875','雪後過集賢裴令公舊宅有感','白居易','唐','唐诗','tang','','[]','梁王捐館後，枚叟過門時。',48,'全唐诗/poet.tang.24000.json','["梁王捐館後，枚叟過門時。", "有淚人還泣，無情雪不知。", "臺亭留盡在，賓客散何之。", "唯有蕭條雁，時來下故池。"]'),
('132fc035-aaff-4582-8856-be885c18ca8f','酬夢得貧居詠懷見贈','白居易','唐','唐诗','tang','','[]','歲陰生計兩蹉跎，相顧悠悠醉且歌。',64,'全唐诗/poet.tang.24000.json','["歲陰生計兩蹉跎，相顧悠悠醉且歌。", "廚冷難留烏止屋，門閑可與雀張羅。", "病添莊舃吟聲苦，貧欠韓康藥債多。", "日望揮金賀新命，俸錢依舊又如何。"]'),
('b06152cd-7dda-4c46-a96a-6dd15b3850c9','酬夢得見喜疾瘳','白居易','唐','唐诗','tang','','[]','暖臥摩綿褥，晨傾藥酒螺。',48,'全唐诗/poet.tang.24000.json','["暖臥摩綿褥，晨傾藥酒螺。", "昏昏布裘底，病醉睡相和。", "末疾徒云爾，餘年有幾何。", "須知差與否，相去校無多。"]'),
('c55ceced-7b4b-4b02-a17c-47778a2f7ca4','夜聞箏中彈瀟湘送神曲感舊','白居易','唐','唐诗','tang','','[]','縹緲巫山女，歸來七八年。',48,'全唐诗/poet.tang.24000.json','["縹緲巫山女，歸來七八年。", "殷勤湘水曲，留在十三弦。", "苦調吟還出，深情咽不傳。", "萬重雲水思，今夜月明前。"]'),
('d5426eda-9f02-4725-9b03-697baf405fd6','感蘇州舊舫','白居易','唐','唐诗','tang','','[]','畫梁朽折紅窗破，獨立池邊盡日看。',32,'全唐诗/poet.tang.24000.json','["畫梁朽折紅窗破，獨立池邊盡日看。", "守得蘇州船舫爛，此身爭合不衰殘。"]'),
('4c0cc768-ace4-4077-a313-5f68f8a32331','感舊石上字','白居易','唐','唐诗','tang','','["\u592a\u6e56"]','閑撥船行尋舊池，幽情往事復誰知。',32,'全唐诗/poet.tang.24000.json','["閑撥船行尋舊池，幽情往事復誰知。", "太湖石上鐫三字，十五年前陳結之。"]'),
('b1fc129e-ebed-4b85-bf8e-1bf428b47127','見敏中初到邠寧秋日登城樓詩詩中頗多鄉思因以寄和','白居易','唐','唐诗','tang','','[]','想爾到邊頭，蕭條正值秋。',48,'全唐诗/poet.tang.24000.json','["想爾到邊頭，蕭條正值秋。", "二年貧御史，八月古邠州。", "絲管聞雖樂，風沙見亦愁。", "望鄉心若苦，不用數登樓。"]'),
('5bab6fbc-36f1-49cf-821d-aa86fa2d31a3','齋戒','白居易','唐','唐诗','tang','','[]','每因齋戒斷葷腥，漸覺塵勞染愛輕。',64,'全唐诗/poet.tang.24000.json','["每因齋戒斷葷腥，漸覺塵勞染愛輕。", "六賊定知無氣色，三尸應恨少恩情。", "酒魔降伏終須盡，詩債填還亦欲平。", "從此始堪爲弟子，竺乾師是古先生。"]'),
('41289609-342e-494a-8046-30428f857644','戲禮經老僧','白居易','唐','唐诗','tang','','[]','香火一爐燈一醆，白頭夜禮佛名經。',32,'全唐诗/poet.tang.24000.json','["香火一爐燈一醆，白頭夜禮佛名經。", "何年飲著聲聞酒，直到如今醉未醒。"]'),
('c4bd890f-f11b-4f5c-8ea0-a616c9188dd3','近見慕巢尚書詩中屢有歎老思退之意又於洛下新置郊居然寵寄方深歸心大速因以長句戲而諭之','白居易','唐','唐诗','tang','','[]','近見詩中歎白髮，遙知閫外憶東都。',64,'全唐诗/poet.tang.24000.json','["近見詩中歎白髮，遙知閫外憶東都。", "煙霞偷眼窺來久，富貴黏身擺得無。", "新置林園猶濩落，未終婚嫁且踟躕。", "應須待到懸車歲，然後東歸伴老夫。"]'),
('9612102c-31cf-4e06-a6bd-f8eb606474b5','對鏡偶吟贈張道士抱元','白居易','唐','唐诗','tang','','[]','閑來對鏡自思量，年貌衰殘分所當。',64,'全唐诗/poet.tang.24000.json','["閑來對鏡自思量，年貌衰殘分所當。", "白髮萬莖何所怪，丹砂一粒不曾嘗。", "眼昏久被書料理，肺渴多因酒損傷。", "今日逢師雖已晚，枕中治老有何方。"]'),
('801050d8-45bb-40b6-a8cf-fc80a6317019','病入新正','白居易','唐','唐诗','tang','','[]','枕上驚新歲，花前念舊歡。',48,'全唐诗/poet.tang.24000.json','["枕上驚新歲，花前念舊歡。", "是身老所逼，非意病相干。", "風月情猶在，杯觴興漸闌。", "便休心未伏，更試一春看。"]'),
('c2361fb2-9708-421e-a294-cd02f3fb140a','臥疾來早晚','白居易','唐','唐诗','tang','','[]','臥疾來早晚，懸懸將十旬。',48,'全唐诗/poet.tang.24000.json','["臥疾來早晚，懸懸將十旬。", "婢能尋本草，犬不吠醫人。", "酒甕全生醭，歌筵半委塵。", "風光還欲好，爭向枕前春。"]'),
('8a618145-31df-4c59-b047-f0c481e57962','強起迎春戲寄思黯','白居易','唐','唐诗','tang','','[]','杖策人扶廢病身，晴和強起一迎春。',32,'全唐诗/poet.tang.24000.json','["杖策人扶廢病身，晴和強起一迎春。", "他時蹇跛縱行得，笑殺平原樓上人。"]'),
('5ef65e05-065a-42b6-b4fc-c89361444b5a','夢得前所酬篇有鍊盡美少年之句因思往事兼詠今懷重以長句荅之','白居易','唐','唐诗','tang','','[]','鍊盡少年成白首，憶初相識到今朝。',64,'全唐诗/poet.tang.24000.json','["鍊盡少年成白首，憶初相識到今朝。", "昔饒春桂長先折，今伴寒松取後凋。", "生事縱貧猶可過，風情雖老未全銷。", "聲華寵命人皆得，若箇如君歷七朝。"]'),
('b27218c9-b467-43e7-b625-9513fc7c6044','病後寒食','白居易','唐','唐诗','tang','','[]','故紗絳帳舊青氈，藥酒醺醺引醉眠。',64,'全唐诗/poet.tang.24000.json','["故紗絳帳舊青氈，藥酒醺醺引醉眠。", "斗擻弊袍春晚後，摩挲病脚日陽前。", "行無筋力尋山水，坐少精神聽管弦。", "拋擲風光負寒食，曾來未省似今年。"]'),
('0c85a623-4112-4e32-8339-7b25e189760a','老病相仍以詩自解','白居易','唐','唐诗','tang','','[]','榮枯憂喜與彭殤，都是人間戲一場。',64,'全唐诗/poet.tang.24000.json','["榮枯憂喜與彭殤，都是人間戲一場。", "蟲臂鼠肝猶不怪，雞膚鶴髮復何傷。", "昨因風發甘長往，今遇陽和又小康。", "還似遠行裝束了，遲迴且住亦何妨。"]'),
('c9026eb8-1a77-4496-acb7-88df04bf8825','皇甫郎中親家翁赴任絳州宴送出城贈別','白居易','唐','唐诗','tang','','[]','慕賢入室交先定，結援通家好復成。',64,'全唐诗/poet.tang.24000.json','["慕賢入室交先定，結援通家好復成。", "新婦不嫌貧活計，嬌孫同慰老心情。", "洛橋歌酒今朝散，絳路風煙幾日行。", "欲識離羣相戀意，爲君扶病出都城。"]'),
('c05a88ab-d4a5-47f3-9c30-47e9ac53e23c','春暖','白居易','唐','唐诗','tang','','[]','風痹宜和暖，春來脚較輕。',48,'全唐诗/poet.tang.24000.json','["風痹宜和暖，春來脚較輕。", "鶯留花下立，鶴引水邊行。", "髮少嫌巾重，顏衰訝鏡明。", "不論親與故，自亦昧平生。"]'),
('84bbd8e3-6c52-4f4f-90ec-3483fb8d1fb8','殘春晚起伴客笑談','白居易','唐','唐诗','tang','','[]','掩戶下簾朝睡足，一聲黃鳥報殘春。',64,'全唐诗/poet.tang.24000.json','["掩戶下簾朝睡足，一聲黃鳥報殘春。", "披衣岸幘日高起，兩角青衣扶老身。", "策杖強行過里巷，引杯閑酌伴親賓。", "莫言病後妨談笑，猶恐多於不病人。"]'),
('af649eb6-0717-4fc0-95c6-4f09eb17202b','送唐州崔使君侍親赴任','白居易','唐','唐诗','tang','','[]','連持使節歷專城，獨賀崔侯最慶榮。',64,'全唐诗/poet.tang.24000.json','["連持使節歷專城，獨賀崔侯最慶榮。", "烏府一拋霜簡去，朱輪四從板輿行。", "發時止許沙鷗送，到日方乘竹馬迎。", "唯慮郡齋賓友少，數杯春酒共誰傾。"]'),
('c905d9e5-0ce4-40d7-b779-a8a35fa3e21c','春晚詠懷贈皇甫朗之','白居易','唐','唐诗','tang','','[]','豔陽時節又蹉跎，遲暮光陰復若何。',64,'全唐诗/poet.tang.24000.json','["豔陽時節又蹉跎，遲暮光陰復若何。", "一歲平分春日少，百年通計老時多。", "多中更被愁牽引，少處兼遭病折磨。", "賴有銷憂治悶藥，君家濃酎我狂歌。"]'),
('c768b264-bc65-4cb5-9057-971d376a1fe1','春盡日宴罷感事獨吟','白居易','唐','唐诗','tang','','[]','五年三月今朝盡，客散筵空獨掩扉。',64,'全唐诗/poet.tang.24000.json','["五年三月今朝盡，客散筵空獨掩扉。", "病共樂天相伴住，春隨樊子一時歸。", "閑聽鶯語移時立，思逐楊花觸處飛。", "金帶縋腰衫委地，年年衰瘦不勝衣。"]'),
('768287b6-de28-4e1a-90b7-b1446f1dca99','病中辱崔宣城長句見寄兼有觥綺之贈因以四韻總而酬之','白居易','唐','唐诗','tang','','[]','劉[楨]病發經春臥，謝朓詩來盡日吟。',66,'全唐诗/poet.tang.24000.json','["劉[楨]病發經春臥，謝朓詩來盡日吟。", "三道舊誇收片玉，一章新喜獲雙金。", "信題霞綺緘情重，酒試銀觥表分深。", "科第門生滿霄漢，歲寒少得似君心。"]'),
('4b210956-7ecb-4dc9-921c-8d13afe96856','前有別楊柳枝絕句夢得繼和云春盡絮飛留不得隨風好去落誰家又復戲答','白居易','唐','唐诗','tang','','[]','柳老春深日又斜，任他飛向別人家。',32,'全唐诗/poet.tang.24000.json','["柳老春深日又斜，任他飛向別人家。", "誰能更學孩童戲，尋逐春風捉柳花。"]'),
('dca6b012-2f1d-45ea-bb0b-3ae116f50ee2','池上早夏','白居易','唐','唐诗','tang','','["\u590f\u5929"]','水積春塘晚，陰交夏木繁。',48,'全唐诗/poet.tang.24000.json','["水積春塘晚，陰交夏木繁。", "舟船如野渡，籬落似江村。", "靜拂琴牀席，香開酒庫門。", "慵閑無一事，時弄小嬌孫。"]'),
('5b774ae7-0663-4e01-a218-08b63efa9e47','談氏外孫生三日喜是男偶吟成篇兼戲呈夢得','白居易','唐','唐诗','tang','','[]','玉芽珠顆小男兒，羅薦蘭湯欲罷時。',64,'全唐诗/poet.tang.24000.json','["玉芽珠顆小男兒，羅薦蘭湯欲罷時。", "芣苢春來盈女手，梧桐老去長孫枝。", "慶傳媒氏燕先賀，喜報談家烏預知。", "明日貧翁具雞黍，應須酬賽引雛詩。"]'),
('71220610-5c41-494c-a80c-10e133f9c7ae','開成大行皇帝挽歌詞四首奉敕撰進 一','白居易','唐','唐诗','tang','','[]','御宇恢皇化，傳家叶至公。',48,'全唐诗/poet.tang.24000.json','["御宇恢皇化，傳家叶至公。", "華夷臣妾內，堯舜弟兄中。", "制度移民俗，文章變國風。", "開成與貞觀，實錄事多同。"]'),
('cfafe1b8-afa3-4363-bc05-c1fd37399b4d','開成大行皇帝挽歌詞四首奉敕撰進 二','白居易','唐','唐诗','tang','','[]','晏駕辭雙闕，靈儀出九衢。',48,'全唐诗/poet.tang.24000.json','["晏駕辭雙闕，靈儀出九衢。", "上雲歸碧落，下席葬蒼梧。", "蓂晚餘堯曆，龜新啓夏圖。", "三朝聯棣萼，從古帝王無。"]'),
('3ff0267f-d5cf-4399-baba-16d2516b337b','開成大行皇帝挽歌詞四首奉敕撰進 三','白居易','唐','唐诗','tang','','[]','嚴恭七月禮，哀慟萬人心。',48,'全唐诗/poet.tang.24000.json','["嚴恭七月禮，哀慟萬人心。", "地感勝秋氣，天愁結夕陰。", "鼎湖龍漸遠，濛汜日初沈。", "唯有雲韶樂，長留治世音。"]'),
('de8d604f-875d-404c-8f8a-adcfb804dfd8','開成大行皇帝挽歌詞四首奉敕撰進 四','白居易','唐','唐诗','tang','','[]','化成同軌表清平，恩結連枝感聖明。',64,'全唐诗/poet.tang.24000.json','["化成同軌表清平，恩結連枝感聖明。", "帝與九齡雖吉夢，山呼萬歲是虛聲。", "月低儀仗辭蘭路，風引笳簫入柏城。", "老病龍髯攀不及，東周退傅最傷情。"]'),
('6283f898-8e2c-45c7-967d-4290286f4115','時熱少客因詠所懷','白居易','唐','唐诗','tang','','[]','冠櫛心多懶，逢迎興漸微。',72,'全唐诗/poet.tang.24000.json','["冠櫛心多懶，逢迎興漸微。", "況當時熱甚，幸遇客來稀。", "濕灑池邊地，涼開竹下扉。", "露牀青篾簟，風架白蕉衣。", "院靜留僧宿，樓空放妓歸。", "衰殘強歡宴，此事久知非。"]'),
('6c2aec3b-3a61-4625-9671-adc1df710075','宣州崔大夫閤老忽以近詩數十首見示吟諷之下竊有所喜因成長句寄題郡齋','白居易','唐','唐诗','tang','','[]','謝玄暉歿吟聲寢，郡閣寥寥筆硯閑。',64,'全唐诗/poet.tang.24000.json','["謝玄暉歿吟聲寢，郡閣寥寥筆硯閑。", "無復新詩題壁上，虛教遠岫列窗間。", "忽驚歌雪今朝至，必恐文星昨夜還。", "再喜宣城章句動，飛觴遙賀敬亭山。"]'),
('53a349ea-e298-4684-a604-c09ad7942195','足疾','白居易','唐','唐诗','tang','','[]','足疾無加亦不瘳，綿春歷夏復經秋。',64,'全唐诗/poet.tang.24000.json','["足疾無加亦不瘳，綿春歷夏復經秋。", "開顏且酌尊中酒，代步多乘池上舟。", "幸有眼前衣食在，兼無身後子孫憂。", "應須學取陶彭澤，但委心形任去留。"]'),
('81955419-6668-4531-a8d1-e624f2020c80','晚池汎舟遇景成詠贈呂處士','白居易','唐','唐诗','tang','','[]','岸淺橋平池面寬，飄然輕櫂汎澄瀾。',64,'全唐诗/poet.tang.24000.json','["岸淺橋平池面寬，飄然輕櫂汎澄瀾。", "風宜扇引開懷入，樹愛舟行仰臥看。", "別境客稀知不易，能詩人少詠應難。", "唯憐呂叟時相伴，同把磻溪舊釣竿。"]'),
('a3b11d99-9994-4ff0-a8db-d85d1b7ed065','夢微之','白居易','唐','唐诗','tang','','["\u60bc\u4ea1", "\u6000\u5ff5"]','夜來攜手夢同遊，晨起盈巾淚莫收。',64,'全唐诗/poet.tang.24000.json','["夜來攜手夢同遊，晨起盈巾淚莫收。", "漳浦老身三度病，咸陽草樹八迴秋。", "君埋泉下泥銷骨，我寄人間雪滿頭。", "阿衛韓郎相次去，夜臺茫昧得知不。"]'),
('1c6f35e8-6d5e-4204-8966-2d6731db7242','感秋詠意','白居易','唐','唐诗','tang','','[]','炎涼遷次速如飛，又脫生衣著熟衣。',64,'全唐诗/poet.tang.24000.json','["炎涼遷次速如飛，又脫生衣著熟衣。", "遶壁闇蛩無限思，戀巢寒燕未能歸。", "須知流輩年年失，莫歎衰容日日非。", "舊語相傳聊自慰，世間七十老人稀。"]'),
('cf1cfc21-3d0f-4d3c-b078-4b12314de8ea','老病幽獨偶吟所懷','白居易','唐','唐诗','tang','','[]','眼漸昏昏耳漸聾，滿頭霜雪半身風。',64,'全唐诗/poet.tang.24000.json','["眼漸昏昏耳漸聾，滿頭霜雪半身風。", "已將身出浮雲外，猶寄形於逆旅中。", "觴詠罷來賓閣閉，笙歌散後妓房空。", "世緣俗念消除盡，別是人間清淨翁。"]'),
('4006dcb1-2ecf-4a2c-a415-a4f437e6e489','和楊尚書罷相後夏日遊永安水亭兼招本曹楊侍郎同行','白居易','唐','唐诗','tang','','[]','道行無喜退無憂，舒卷如雲得自由。',64,'全唐诗/poet.tang.24000.json','["道行無喜退無憂，舒卷如雲得自由。", "良冶動時爲哲匠，巨川濟了作虛舟。", "竹亭陰合偏宜夏，水檻風涼不待秋。", "遙愛翩翩雙紫鳳，入同官署出同遊。"]'),
('bddb3ee4-eb64-4104-8e48-d22e53bd6c11','在家出家','白居易','唐','唐诗','tang','','[]','衣食支吾婚嫁畢，從今家事不相仍。',64,'全唐诗/poet.tang.24000.json','["衣食支吾婚嫁畢，從今家事不相仍。", "夜眠身是投林鳥，朝飯心同乞食僧。", "清唳數聲松下鶴，寒光一點竹間燈。", "中宵入定跏趺坐，女喚妻呼多不應。"]'),
('03372351-cdb4-4cc7-ab64-399e0c87ebba','夜涼','白居易','唐','唐诗','tang','','[]','露白風清庭戶涼，老人先著夾衣裳。',32,'全唐诗/poet.tang.24000.json','["露白風清庭戶涼，老人先著夾衣裳。", "舞腰歌袖拋何處，唯對無弦琴一張。"]'),
('88a31154-38ba-4fe8-81a9-9e24b6f5f23c','繼之尚書自余病來寄遺非一又蒙覽醉吟先生傳題詩以美之今以此篇用伸酬謝','白居易','唐','唐诗','tang','','[]','衰殘與世日相疎，惠好唯君分有餘。',64,'全唐诗/poet.tang.24000.json','["衰殘與世日相疎，惠好唯君分有餘。", "茶藥贈多因病久，衣裳寄早及寒初。", "交情鄭重金相似，詩韻清鏘玉不如。", "醉傅狂言人盡笑，獨知我者是尚書。"]'),
('b0653223-b1fb-4104-ae2d-70545d323985','五年秋病後獨宿香山寺三絕句 一','白居易','唐','唐诗','tang','','[]','經年不到龍門寺，今夜何人知我情。',32,'全唐诗/poet.tang.24000.json','["經年不到龍門寺，今夜何人知我情。", "還向暢師房裏宿，新秋月色舊灘聲。"]'),
('984c61cc-704d-43f8-aed1-67c08511127d','五年秋病後獨宿香山寺三絕句 二','白居易','唐','唐诗','tang','','[]','飲徒歌伴今何在，雨散雲飛盡不迴。',32,'全唐诗/poet.tang.24000.json','["飲徒歌伴今何在，雨散雲飛盡不迴。", "從此香山風月夜，祗應長是一身來。"]'),
('2c9e5322-b071-484e-bb3e-42e4d8f5347b','五年秋病後獨宿香山寺三絕句 三','白居易','唐','唐诗','tang','','[]','石盆泉畔石樓頭，十二年來晝夜遊。',32,'全唐诗/poet.tang.24000.json','["石盆泉畔石樓頭，十二年來晝夜遊。", "更過今年年七十，假如無病亦宜休。"]'),
('e57c3520-1757-4943-adea-0f05e4b0caf0','題香山新經堂招僧','白居易','唐','唐诗','tang','','[]','煙滿秋堂月滿庭，香花漠漠磬泠泠。',32,'全唐诗/poet.tang.24000.json','["煙滿秋堂月滿庭，香花漠漠磬泠泠。", "誰能來此尋真諦，白老新開一藏經。"]'),
('4f8b1fd9-1e0d-4736-a90d-5aa587ce1b13','偶題鄧公','白居易','唐','唐诗','tang','','[]','偶因攜酒尋村客，聊復迴車訪薜蘿。',64,'全唐诗/poet.tang.24000.json','["偶因攜酒尋村客，聊復迴車訪薜蘿。", "且值雪寒相慰問，不妨春暖更經過。", "翁居山下年空老，我得人間事校多。", "一種共翁頭似雪，翁無衣食自如何。"]'),
('2117e226-371a-4a3c-aa42-696c6bf035cf','早入皇城贈王留守僕射','白居易','唐','唐诗','tang','','[]','津橋殘月曉沈沈，風露淒清禁署深。',32,'全唐诗/poet.tang.24000.json','["津橋殘月曉沈沈，風露淒清禁署深。", "城柳宮槐謾搖落，悲愁不到貴人心。"]'),
('eb9a37d1-b354-4aa8-b4ce-d9da6b817cd7','寄題廬山舊草堂兼呈二林寺道侶','白居易','唐','唐诗','tang','','["\u5e90\u5c71"]','三十年前草堂主，而今雖在鬢如絲。',64,'全唐诗/poet.tang.24000.json','["三十年前草堂主，而今雖在鬢如絲。", "登山尋水應無力，不似江州司馬時。", "漸伏酒魔休放醉，猶殘口業未拋詩。", "君行過到鑪峰下，爲報東林長老知。"]'),
('c8654133-e05f-4b4c-baf1-8bc7966b9105','改業','白居易','唐','唐诗','tang','','[]','先生老去飲無興，居士病來閑有餘。',64,'全唐诗/poet.tang.24000.json','["先生老去飲無興，居士病來閑有餘。", "猶覺醉吟多放逸，不如禪定更清虛。", "柘枝紫袖教丸藥，羯鼓蒼頭遣種蔬。", "却被山僧戲相問，一時改業意何如。"]'),
('9735a2df-9045-42e0-ade6-475619a761b7','山下留別佛光和尚','白居易','唐','唐诗','tang','','[]','勞師送我下山行，此別何人識此情。',32,'全唐诗/poet.tang.24000.json','["勞師送我下山行，此別何人識此情。", "我已七旬師九十，當知後會在他生。"]'),
('76311dbf-41e9-48b4-a738-4022d541cba7','山中五絕句 嶺上雲','白居易','唐','唐诗','tang','','[]','嶺上白雲朝未散，田中青麥旱將枯。',32,'全唐诗/poet.tang.24000.json','["嶺上白雲朝未散，田中青麥旱將枯。", "自生自滅成何事，能逐東風作雨無。"]'),
('d34db24d-053b-4a0b-b861-bbedf317216d','山中五絕句 石上苔','白居易','唐','唐诗','tang','','[]','漠漠斑斑石上苔，幽芳靜綠絕纖埃。',32,'全唐诗/poet.tang.24000.json','["漠漠斑斑石上苔，幽芳靜綠絕纖埃。", "路傍凡草榮遭遇，曾得七香車輾來。"]'),
('00fad44c-5847-4ff0-92b3-3ec81105050b','山中五絕句 林下樗','白居易','唐','唐诗','tang','','[]','香檀文桂苦雕鐫，生理何曾得自全。',32,'全唐诗/poet.tang.24000.json','["香檀文桂苦雕鐫，生理何曾得自全。", "知我無材老樗否，一枝不損盡天年。"]'),
('17434cae-0b68-4b7c-8f62-05ed4428ac19','山中五絕句 澗中魚','白居易','唐','唐诗','tang','','[]','海水桑田欲變時，風濤翻覆沸天池。',32,'全唐诗/poet.tang.24000.json','["海水桑田欲變時，風濤翻覆沸天池。", "鯨吞蛟鬬波成血，深澗遊魚樂不知。"]'),
('e09cee2a-8dbe-4303-ba9f-ac0279b1f0a1','山中五絕句 洞中蝙蝠','白居易','唐','唐诗','tang','','[]','千年鼠化白蝙蝠，黑洞深藏避網羅。',32,'全唐诗/poet.tang.24000.json','["千年鼠化白蝙蝠，黑洞深藏避網羅。", "遠害全身誠得計，一生幽暗又如何。"]'),
('18766ea9-e1df-444c-a56d-b0a4843ff534','自戲三絕句 心問身','白居易','唐','唐诗','tang','','[]','心問身云何泰然，嚴冬暖被日高眠。',32,'全唐诗/poet.tang.24000.json','["心問身云何泰然，嚴冬暖被日高眠。", "放君快活知恩否，不早朝來十一年。"]'),
('8b7d52d0-b7b9-41f4-9254-106b8de0f247','自戲三絕句 身報心','白居易','唐','唐诗','tang','','[]','心是身王身是宮，君今居在我宮中。',32,'全唐诗/poet.tang.24000.json','["心是身王身是宮，君今居在我宮中。", "是君家舍君須愛，何事論恩自說功。"]'),
('3b16d4ce-f736-432f-827b-9edb2be3c5d6','自戲三絕句 心重荅身','白居易','唐','唐诗','tang','','[]','因我疎慵休罷早，遣君安樂歲時多。',32,'全唐诗/poet.tang.24000.json','["因我疎慵休罷早，遣君安樂歲時多。", "世間老苦人何限，不放君閑奈我何。"]'),
('865c8b7f-47aa-42d6-910d-aba4b40661f7','會昌元年春五絕句 病後喜過劉家','白居易','唐','唐诗','tang','','[]','忽憶前年初病後，此生甘分不銜杯。',32,'全唐诗/poet.tang.24000.json','["忽憶前年初病後，此生甘分不銜杯。", "誰能料得今春事，又向劉家飲酒來。"]'),
('8877da7f-b340-444b-a6c3-097bc064d5c0','會昌元年春五絕句 贈舉之僕射','白居易','唐','唐诗','tang','','[]','雞毬餳粥屢開筵，談笑謳吟間管弦。',32,'全唐诗/poet.tang.24000.json','["雞毬餳粥屢開筵，談笑謳吟間管弦。", "一月三迴寒食會，春光應不負今年。"]'),
('1e40f33c-0c2c-4e21-81d5-61913fae3475','會昌元年春五絕句 盧尹賀夢得會中作','白居易','唐','唐诗','tang','','[]','病聞川守賀筵開，起伴尚書飲一杯。',32,'全唐诗/poet.tang.24000.json','["病聞川守賀筵開，起伴尚書飲一杯。", "任意少年長笑我，老人自覓老人來。"]'),
('1fdd3f37-29db-4c8a-893b-93dd3a972f59','會昌元年春五絕句 題朗之槐亭','白居易','唐','唐诗','tang','','[]','春風可惜無多日，家醞唯殘軟半瓶。',32,'全唐诗/poet.tang.24000.json','["春風可惜無多日，家醞唯殘軟半瓶。", "猶望君歸同一醉，籃舁早晚入槐亭。"]'),
('302a138d-357b-42dc-819e-b27baf841844','會昌元年春五絕句 勸夢得酒','白居易','唐','唐诗','tang','','[]','誰人功畫麒麟閣，何客新投魑魅鄉。',32,'全唐诗/poet.tang.24000.json','["誰人功畫麒麟閣，何客新投魑魅鄉。", "兩處榮枯君莫問，殘春更醉兩三場。"]'),
('ccf240c0-5d5f-4eeb-95d7-c0abfa924ddd','過裴令公宅二絕句 一','白居易','唐','唐诗','tang','','[]','風吹楊柳出牆枝，憶得同歡共醉時。',32,'全唐诗/poet.tang.24000.json','["風吹楊柳出牆枝，憶得同歡共醉時。", "每到集賢坊地過，不曾一度不低眉。"]'),
('0c250379-fbcc-47d8-9b91-ee9a9c6f401c','過裴令公宅二絕句 二','白居易','唐','唐诗','tang','','[]','梁王舊館雪濛濛，愁殺鄒枚二老翁。',32,'全唐诗/poet.tang.24000.json','["梁王舊館雪濛濛，愁殺鄒枚二老翁。", "假使明朝深一尺，亦無人到兔園中。"]'),
('7977cdb8-5956-4380-ba7a-6c9f4098e8c0','百日假滿少傅官停自喜言懷','白居易','唐','唐诗','tang','','[]','長告今朝滿十旬，從茲蕭灑便終身。',64,'全唐诗/poet.tang.24000.json','["長告今朝滿十旬，從茲蕭灑便終身。", "老嫌手重拋牙笏，病喜頭輕換角巾。", "疎傅不朝懸組綬，尚平無累畢婚姻。", "人言世事何時了，我是人間事了人。"]'),
('ea321309-c893-472c-866b-83a66dc7e5bf','早熱','白居易','唐','唐诗','tang','','[]','畏景又加旱，火雲殊未收。',48,'全唐诗/poet.tang.24000.json','["畏景又加旱，火雲殊未收。", "籬暄飢有雀，池涸渴無鷗。", "岸幘頭仍痛，褰裳汗亦流。", "若爲當此日，遷客向炎州。"]'),
('28933305-6ab0-4b29-b8ad-48b25fad93d7','題崔少尹上林坊新居','白居易','唐','唐诗','tang','','[]','坊靜居新深且幽，忽疑縮地到滄洲。',64,'全唐诗/poet.tang.24000.json','["坊靜居新深且幽，忽疑縮地到滄洲。", "宅東籬缺嵩峰出，堂後池開洛水流。", "高下三層盤野徑，沿洄十里汎漁舟。", "若能爲客烹雞黍，願伴田蘇日日遊。"]'),
('443e6b24-9d07-42cd-bd89-757bbd0b4e3b','新澗亭','白居易','唐','唐诗','tang','','[]','煙蘿初合澗新開，閑上西亭日幾迴。',32,'全唐诗/poet.tang.24000.json','["煙蘿初合澗新開，閑上西亭日幾迴。", "老病歸山應未得，且移泉石就身來。"]'),
('5c6c689c-cdec-40db-a4e5-84f57be9ff80','對酒有懷寄李十九郎中','白居易','唐','唐诗','tang','','[]','往年江外拋桃葉，去歲樓中別柳枝。',32,'全唐诗/poet.tang.24000.json','["往年江外拋桃葉，去歲樓中別柳枝。", "寂寞春來一杯酒，此情唯有李君知。"]'),
('de18a792-527a-42c5-836f-41c7aad429c7','楊六尚書頻寄新詩詩中多有思閑相就之志因書鄙意報而諭之','白居易','唐','唐诗','tang','','[]','君年殊未及懸車，未合將閑逐老夫。',64,'全唐诗/poet.tang.24000.json','["君年殊未及懸車，未合將閑逐老夫。", "身健正宜金印綬，位高方稱白髭鬚。", "若論塵事何由了，但問雲心自在無。", "進退是非俱是夢，丘中闕下亦何殊。"]'),
('12177bfb-8386-43af-852e-34c9bcf91d28','偶吟自慰兼呈夢得','白居易','唐','唐诗','tang','','[]','且喜同年滿七旬，莫嫌衰病莫嫌貧。',64,'全唐诗/poet.tang.24000.json','["且喜同年滿七旬，莫嫌衰病莫嫌貧。", "已爲海內有名客，又占世間長命人。", "耳裏聲聞新將相，眼前失盡故交親。", "尊榮富壽難兼得，閑坐思量最要身。"]'),
('b12716a9-f259-4051-8ae9-68af2ed88fe5','寄潮州楊繼之','白居易','唐','唐诗','tang','','[]','相府潮陽俱夢中，夢中何者是窮通。',32,'全唐诗/poet.tang.24000.json','["相府潮陽俱夢中，夢中何者是窮通。", "他時事過方應悟，不獨榮空辱亦空。"]'),
('33bebb08-6d90-4e4a-861e-ca4a4be1c986','雪暮偶與夢得同致仕裴賓客王尚書飲','白居易','唐','唐诗','tang','','[]','黃昏慘慘雪霏霏，白首相歡醉不歸。',31,'全唐诗/poet.tang.24000.json','["黃昏慘慘雪霏霏，白首相歡醉不歸。", "四箇老人三百歲人間此會亦應稀。"]'),
('dae3384d-bc09-486e-bc2f-1e44997fb773','雪朝乘興欲詣李司徒留守先以五韻戲之','白居易','唐','唐诗','tang','','[]','夜寒生酒思，曉雪引詩情。',48,'全唐诗/poet.tang.24000.json','["夜寒生酒思，曉雪引詩情。", "熱飲一兩醆，冷吟三五聲。", "鋪花憐地凍，銷玉畏天晴。", "好拂烏巾出，宜披鶴氅行。"]'),
('df56a349-6b98-41b5-9d47-c60776ff18da','贈思黯','白居易','唐','唐诗','tang','','[]','爲憐清淺愛潺湲，一日三迴到水邊。',32,'全唐诗/poet.tang.24000.json','["爲憐清淺愛潺湲，一日三迴到水邊。", "若道歸仁灘更好，主人何故別三年。"]'),
('735b9974-1bab-4357-8f2d-a9f44df03d23','聽歌六絕句 聽都子歌','白居易','唐','唐诗','tang','','[]','都子新歌有性靈，一聲格轉已堪聽。',32,'全唐诗/poet.tang.24000.json','["都子新歌有性靈，一聲格轉已堪聽。", "更聽唱到嫦娥字，猶有樊家舊典刑。"]'),
('54177233-5b0d-48eb-a485-9a680046ee82','聽歌六絕句 樂世','白居易','唐','唐诗','tang','','[]','管急弦繁拍漸稠，綠腰宛轉曲終頭。',32,'全唐诗/poet.tang.24000.json','["管急弦繁拍漸稠，綠腰宛轉曲終頭。", "誠知樂世聲聲樂，老病人聽未免愁。"]'),
('0e27f703-5220-4393-b2ae-876c4ec0e4a4','聽歌六絕句 水調','白居易','唐','唐诗','tang','','[]','五言一徧最殷勤，調少情多似有因。',32,'全唐诗/poet.tang.24000.json','["五言一徧最殷勤，調少情多似有因。", "不會當時翻曲意，此聲腸斷爲何人。"]'),
('e3b81ef3-019d-47db-ac40-544f6fdcfe1c','聽歌六絕句 想夫憐','白居易','唐','唐诗','tang','','[]','玉管朱弦莫急催，容聽歌送十分杯。',32,'全唐诗/poet.tang.24000.json','["玉管朱弦莫急催，容聽歌送十分杯。", "長愛夫憐第二句，請君重唱夕陽開。"]'),
('0a64345f-9b5d-4b44-b8f8-5a388db3c175','聽歌六絕句 何滿子','白居易','唐','唐诗','tang','','[]','世傳滿子是人名，臨就刑時曲始成。',32,'全唐诗/poet.tang.24000.json','["世傳滿子是人名，臨就刑時曲始成。", "一曲四調歌八疊，從頭便是斷腸聲。"]'),
('a994a3c7-5cdf-4115-b293-c2c6a91aa4db','聽歌六絕句 離別難','白居易','唐','唐诗','tang','','[]','綠楊陌上送行人，馬去車迴一望塵。',32,'全唐诗/poet.tang.24000.json','["綠楊陌上送行人，馬去車迴一望塵。", "不覺別時紅淚盡，歸來無淚可霑巾。"]'),
('1320e4b6-9ba5-4ac5-9d57-1195a90e96b7','閑樂','白居易','唐','唐诗','tang','','[]','坐安臥穩輿平肩，倚杖披衫遶四邊。',48,'全唐诗/poet.tang.24000.json','["坐安臥穩輿平肩，倚杖披衫遶四邊。", "空腹三杯卯後酒，曲肱一覺醉中眠。", "更無忙苦吟閑樂，恐是人間自在天。"]'),
('08abce08-f0a4-47e9-b5e6-944b4ec778b9','立秋夕涼風忽至炎暑稍消即事詠懷寄汴州節度使李二十尚書','白居易','唐','唐诗','tang','','[]','嫋嫋簷樹動，好風西南來。',132,'全唐诗/poet.tang.24000.json','["嫋嫋簷樹動，好風西南來。", "紅缸霏微滅，碧幌飄颻開。", "披襟有餘涼，拂簟無纖埃。", "但喜煩暑退，不惜光陰催。", "河秋稍清淺，月午方裴回。", "或行或坐臥，體適心悠哉。", "美人在浚都，旌旗繞樓臺。", "雖非滄溟阻，難見如蓬萊。", "蟬迎節又換，雁送書未迴。", "君位日寵重，我年日摧頹。", "無因風月下，一舉平生杯。"]'),
('1c643deb-e874-4235-bf81-fc419dee5bd6','開成二年夏聞新蟬贈夢得','白居易','唐','唐诗','tang','','[]','十載與君別，常感新蟬鳴。',84,'全唐诗/poet.tang.24000.json','["十載與君別，常感新蟬鳴。", "今年共君聽，同在洛陽城。", "噪處知林靜，聞時覺景清。", "涼風忽嫋嫋，秋思先秋生。", "殘槿花邊立，老槐陰下行。", "雖無索居恨，還動長年情。", "且喜未聾耳，年年聞此聲。"]'),
('ca155661-0860-40b8-832e-9586a9506164','題牛相公歸仁里宅新成小灘','白居易','唐','唐诗','tang','','[]','平生見流水，見此轉留連。',144,'全唐诗/poet.tang.24000.json','["平生見流水，見此轉留連。", "況此朱門內，君家新引泉。", "伊流決一帶，洛石砌千拳。", "與君三伏月，滿耳作潺湲。", "深處碧磷磷，淺處清濺濺。", "碕岸束嗚咽，沙汀散淪漣。", "翻浪雪不盡，澄波空共鮮。", "兩岸灩澦口，一泊瀟湘天。", "曾作天南客，漂流六七年。", "何山不倚杖，何水不停船。", "巴峽聲心裏，松江色眼前。", "今朝小灘上，能不思悠然。"]'),
('918ab730-fa0e-4685-b721-132962a8ceb6','春日閑居三首 一','白居易','唐','唐诗','tang','','[]','陶云愛吾廬，吾亦愛吾屋。',120,'全唐诗/poet.tang.24000.json','["陶云愛吾廬，吾亦愛吾屋。", "屋中有琴書，聊以慰幽獨。", "是時三月半，花落庭蕪綠。", "舍上晨鳩鳴，窗間春睡足。", "睡足起閑坐，景晏方櫛沐。", "今日非十齋，庖童饋魚肉。", "飢來恣餐歠，冷熱隨所欲。", "飽竟快搔爬，筋骸無檢束。", "豈徒暢肢體，兼欲遺耳目。", "便可傲松喬，何假杯中淥。"]'),
('447cc32b-af24-4cc5-ab72-6ea0b448f8d4','春日閑居三首 二','白居易','唐','唐诗','tang','','[]','廣池春水平，羣魚恣遊泳。',96,'全唐诗/poet.tang.24000.json','["廣池春水平，羣魚恣遊泳。", "新林綠陰成，衆鳥欣相鳴。", "時我亦瀟灑，適無累與病。", "魚鳥人則殊，同歸於遂性。", "緬思山梁雉，時哉感孔聖。", "聖人不得所，慨然歎時命。", "我今對鱗羽，取樂成謠詠。", "得所仍得時，吾生一何幸。"]'),
('2790dba2-3032-49dc-bba2-03667283e210','春日閑居三首 三','白居易','唐','唐诗','tang','','[]','勞者不覺歌，歌其勞苦事。',120,'全唐诗/poet.tang.24000.json','["勞者不覺歌，歌其勞苦事。", "逸者不覺歌，歌其逸樂意。", "問我逸如何，閑居多興味。", "問我樂如何，閑官少憂累。", "又問俸厚薄，百千隨月至。", "又問年幾何，七十行欠二。", "所得皆過望，省躬良可媿。", "馬閑無羈絆，鶴老有祿位。", "設自爲化工，優饒只如是。", "安得不歌詠，默默受天賜。"]'),
('11870117-0aed-4c28-95ec-cb1e149fdbbb','小閣閑坐','白居易','唐','唐诗','tang','','[]','閣前竹蕭蕭，閣下水潺潺。',72,'全唐诗/poet.tang.24000.json','["閣前竹蕭蕭，閣下水潺潺。", "拂簟卷簾坐，清風生其間。", "靜聞新蟬鳴，遠見飛鳥還。", "但有巾挂壁，而無客叩關。", "二疎返故里，四老歸舊山。", "吾亦適所願，求閑而得閑。"]'),
('bd40d75d-42c3-41bd-8681-4aa255146eee','遊平泉宴浥澗宿香山石樓贈座客','白居易','唐','唐诗','tang','','[]','逸少集蘭亭，季倫宴金谷。',120,'全唐诗/poet.tang.24000.json','["逸少集蘭亭，季倫宴金谷。", "金谷太繁華，蘭亭闕絲竹。", "何如今日會，浥澗平泉曲。", "杯酒與管弦，貧中隨分足。", "紫鮮林筍嫩，紅潤園桃熟。", "採摘助盤筵，芳滋盈口腹。", "閑吟暮雲碧，醉藉春草綠。", "舞妙豔流風，歌清叩寒玉。", "古詩惜晝短，勸我令秉燭。", "是夜勿言歸，相攜石樓宿。"]'),
('6c051c79-9237-4762-bb8b-f890a42989b5','池上幽境','白居易','唐','唐诗','tang','','[]','褭褭過水橋，微微入林路。',72,'全唐诗/poet.tang.24000.json','["褭褭過水橋，微微入林路。", "幽境深誰知，老身閑獨步。", "行行何所愛，遇物自成趣。", "平滑青盤石，低密綠陰樹。", "石上一素琴，樹下雙草屨。", "此是榮先生，坐禪三樂處。"]'),
('70d83fdb-34d8-439a-b4e5-e4f37d12cc71','夏日閑放','白居易','唐','唐诗','tang','','[]','時暑不出門，亦無賓客至。',96,'全唐诗/poet.tang.24000.json','["時暑不出門，亦無賓客至。", "靜室深下簾，小庭新掃地。", "褰裳復岸幘，閑傲得自恣。", "朝景枕簟清，乘涼一覺睡。", "午餐何所有，魚肉一兩味。", "夏服亦無多，蕉紗三五事。", "資身既給足，長物徒煩費。", "若比簞瓢人，吾今太富貴。"]'),
('20ce3eb7-49dc-4d66-8e3d-0d9e29da8287','和思黯居守獨飲偶醉見示六韻時夢得和篇先成頗爲麗絕時添兩韻繼而美之','白居易','唐','唐诗','tang','','[]','宮漏滴漸闌，城烏啼復歇。',96,'全唐诗/poet.tang.24000.json','["宮漏滴漸闌，城烏啼復歇。", "此時若不醉，爭奈千門月。", "主人中夜起，妓燭前羅列。", "歌袂默收聲，舞鬟低赴節。", "弦吟玉柱品，酒透金杯熱。", "朱顏忽已酡，清奏猶未闋。", "妍詞黯先唱，逸韻劉繼發。", "鏗然雙雅音，金石相磨戛。"]'),
('d85e874f-0079-43d5-8677-b07b86f3bf68','和夢得洛中早春見贈七韻','白居易','唐','唐诗','tang','','[]','衆皆賞春色，君獨憐春意。',84,'全唐诗/poet.tang.24000.json','["衆皆賞春色，君獨憐春意。", "春意竟如何，老夫知此味。", "燭餘減夜漏，衾暖添朝睡。", "恬和臺上風，虛潤池邊地。", "開遲花養豔，語懶鶯含思。", "似訝隔年齋，如勸迎春醉。", "何日同宴遊，心期二月二。"]'),
('53084e93-55af-42ff-98d7-6b3c05f7b2d5','櫻桃花下有感而作','白居易','唐','唐诗','tang','','[]','藹藹美周宅，櫻繁春日斜。',72,'全唐诗/poet.tang.24000.json','["藹藹美周宅，櫻繁春日斜。", "一爲洛下客，十見池上花。", "爛熳豈無意，爲君占年華。", "風光饒此樹，歌舞勝諸家。", "失盡白頭伴，長成紅粉娃。", "停杯兩相顧，堪喜亦堪嗟。"]'),
('b9952183-9f8b-47a5-97db-ca095c95eb28','洗竹','白居易','唐','唐诗','tang','','[]','布衾寒擁頸，氈履溫承足。',96,'全唐诗/poet.tang.24000.json','["布衾寒擁頸，氈履溫承足。", "獨立冰池前，久看洗霜竹。", "先除老且病，次去纖而曲。", "剪棄猶可憐，琅玕十餘束。", "青青復籊籊，頗異凡草木。", "依然若有情，回頭語僮僕。", "小者截魚竿，大者編茅屋。", "勿作篲與箕，而令糞土辱。"]'),
('aec71e4f-1e6f-4f25-8fc6-40b2622e372b','新沐浴','白居易','唐','唐诗','tang','','["\u9ec4\u6cb3"]','形適外無恙，心恬內無憂。',144,'全唐诗/poet.tang.24000.json','["形適外無恙，心恬內無憂。", "夜來新沐浴，肌髮舒且柔。", "寬裁夾烏帽，厚絮長白裘。", "裘溫裹我足，帽暖覆我頭。", "先進酒一杯，次舉粥一甌。", "半酣半飽時，四體春悠悠。", "是月歲陰暮，慘冽天地愁。", "白日冷無光，黃河凍不流。", "何處征戍行，何人羈旅遊。", "窮途絕糧客，寒獄無燈囚。", "勞生彼何苦，遂性我何優。", "撫心但自媿，孰知其所由。"]'),
('dbe1bf48-ea99-43d1-af81-2bf42aa8ea0e','三年除夜','白居易','唐','唐诗','tang','','[]','晰晰燎火光，氳氳臘酒香。',96,'全唐诗/poet.tang.24000.json','["晰晰燎火光，氳氳臘酒香。", "嗤嗤童稚戲，迢迢歲夜長。", "堂上書帳前，長幼合成行。", "以我年最長，次第來稱觴。", "七十期漸近，萬綠心已忘。", "不唯少歡樂，兼亦無悲傷。", "素屏應居士，青衣侍孟光。", "夫妻老相對，各坐一繩牀。"]'),
('cc0d6427-7125-4b0c-bdb2-399004d33a0d','自題小園','白居易','唐','唐诗','tang','','[]','不鬬門館華，不鬬林園大。',108,'全唐诗/poet.tang.24000.json','["不鬬門館華，不鬬林園大。", "但鬬爲主人，一坐十餘載。", "迴看甲乙第，列在都城內。", "素垣夾朱門，藹藹遙相對。", "主人安在哉，富貴去不迴。", "池乃爲魚鑿，林乃爲禽栽。", "何如小園主，拄杖閑即來。", "親賓有時會，琴酒連夜開。", "以此聊自足，不羨大池臺。"]'),
('b806e551-5624-46fa-a51c-68ca730aacc5','病中宴坐','白居易','唐','唐诗','tang','','[]','有酒病不飲，有詩慵不吟。',72,'全唐诗/poet.tang.24000.json','["有酒病不飲，有詩慵不吟。", "頭眩罷垂鉤，手痹休援琴。", "竟日悄無事，所居閑且深。", "外安支離體，中養希夷心。", "窗戶納秋景，竹木澄夕陰。", "宴坐小池畔，清風時動襟。"]'),
('efaf5330-dc43-4226-817d-642472e4ba0a','戒藥','白居易','唐','唐诗','tang','','[]','促促急景中，蠢蠢微塵裏。',120,'全唐诗/poet.tang.24000.json','["促促急景中，蠢蠢微塵裏。", "生涯有分限，愛戀無終已。", "早夭羨中年，中年羨暮齒。", "暮齒又貪生，服食求不死。", "朝吞太陽精，夕吸秋石髓。", "徼福反成災，藥誤者多矣。", "以之資嗜慾，又望延甲子。", "天人陰隲間，亦恐無此理。", "域中有真道，所說不如此。", "後身始身存，吾聞諸老氏。"]'),
('1bf8e156-c142-4307-9c60-04daadbb556a','贈夢得','白居易','唐','唐诗','tang','','[]','前日君家飲，昨日王家宴。',72,'全唐诗/poet.tang.24000.json','["前日君家飲，昨日王家宴。", "今日過我廬，三日三會面。", "當歌聊自放，對酒交相勸。", "爲我盡一杯，與君發三願。", "一願世清平，二願身強健。", "三願臨老頭，數與君相見。"]'),
('1d9a4c9d-7551-4045-a59d-5afb4c7b7167','逸老','白居易','唐','唐诗','tang','','[]','白日下駸駸，青天高浩浩。',204,'全唐诗/poet.tang.24000.json','["白日下駸駸，青天高浩浩。", "人生在其中，適時即爲好。", "勞我以少壯，息我以衰老。", "順之多吉壽，違之或凶夭。", "我初五十八，息老雖非早。", "一閑十三年，所得亦不少。", "況加祿仕後，衣食常溫飽。", "又從風疾來，女嫁男婚了。", "胷中一無事，浩氣凝襟抱。", "飄若雲信風，樂於魚在藻。", "桑榆坐已暮，鐘漏行將曉。", "皤然七十翁，亦足稱壽考。", "筋骸本非實，一束芭蕉草。", "眷屬偶相依，一夕同栖鳥。", "去何有顧戀，住亦無憂惱。", "生死尚復然，其餘安足道。", "是故臨老心，冥然合玄造。"]'),
('7ffe4f6a-3d2f-4e03-b5e4-21786d9b910d','遇物感興因示子弟','白居易','唐','唐诗','tang','','[]','聖擇狂夫言，俗信老人語。',144,'全唐诗/poet.tang.24000.json','["聖擇狂夫言，俗信老人語。", "我有老狂詞，聽之吾語汝。", "吾觀器用中，劒銳鋒多傷。", "吾觀形骸內，骨勁齒先亡。", "寄言處世者，不可苦剛強。", "龜性愚且善，鳩心鈍無惡。", "人賤拾支牀，鶻欺擒暖脚。", "寄言立身者，不得全柔弱。", "彼固罹禍難，此未免憂患。", "于何保終吉，強弱剛柔間。", "上遵周孔訓，旁鑒老莊言。", "不唯鞭其後，亦要軛其先。"]'),
('b9f4656c-bec2-4a71-bed3-fcc816f81f4d','首夏南池獨酌','白居易','唐','唐诗','tang','','[]','春盡雜英歇，夏初芳草深。',84,'全唐诗/poet.tang.24000.json','["春盡雜英歇，夏初芳草深。", "薰風自南至，吹我池上林。", "綠蘋散還合，頳鯉跳復沈。", "新葉有佳色，殘鶯猶好音。", "依然謝家物，池酌對風琴。", "慙無康樂作，秉筆思沈吟。", "境勝才思劣，詩成不稱心。"]'),
('5989bfc0-3786-47fc-bc30-d58bb638955a','官俸初罷親故見憂以詩諭之','白居易','唐','唐诗','tang','','[]','七年爲少傅，品高俸不薄。',144,'全唐诗/poet.tang.24000.json','["七年爲少傅，品高俸不薄。", "乘軒已多慙，況是一病鶴。", "又及懸車歲，筋力轉衰弱。", "豈以貧是憂，尚爲名所縛。", "今春始病免，纓組初擺落。", "蜩甲有何知，雲心無所著。", "囷中殘舊穀，可備歲饑惡。", "園中多新蔬，未至食藜藿。", "不求安師卜，不問陳生藥。", "但對丘中琴，時開池上酌。", "信風舟不繫，掉尾魚方樂。", "親友不我知，而憂我寂寞。"]'),
('028660ea-cc99-48a5-8662-41c1a62f603f','閑居偶吟招鄭庶子皇甫郎中','白居易','唐','唐诗','tang','','[]','自哂此迂叟，少迂老更迂。',132,'全唐诗/poet.tang.24000.json','["自哂此迂叟，少迂老更迂。", "家計不一問，園林聊自娛。", "竹間琴一張，池上酒一壺。", "更無俗物到，但與秋光俱。", "古石蒼錯落，新泉碧縈紆。", "焉用車馬客，即此是吾徒。", "猶有所思人，各在城一隅。", "杳然愛不見，搔首方踟躕。", "玄晏風韻遠，子真雲貌孤。", "誠知厭朝市，何必憶江湖。", "能來小澗上，一聽潺湲無。"]'),
('d8d94679-b8fc-4a95-a1c6-9b75a1ff66cb','亭西牆下伊渠水中置石激流潺湲成韻頗有幽趣以詩記之','白居易','唐','唐诗','tang','','[]','嵌巉嵩石峭，皎潔伊流清。',96,'全唐诗/poet.tang.24000.json','["嵌巉嵩石峭，皎潔伊流清。", "立爲遠峰勢，激作寒玉聲。", "夾岸羅密樹，面灘開小亭。", "忽疑嚴子瀨，流入洛陽城。", "是時羣動息，風靜微月明。", "高枕夜悄悄，滿耳秋泠泠。", "終日臨大道，何人知此情。", "此情苟自愜，亦不要人聽。"]'),
('efd44663-298f-4575-b367-7ac7788f67f2','閑題家池寄王屋張道士','白居易','唐','唐诗','tang','','[]','有石白磷磷，有水清潺潺。',120,'全唐诗/poet.tang.24000.json','["有石白磷磷，有水清潺潺。", "有叟頭似雪，婆娑乎其間。", "進不趨要路，退不入深山。", "深山太濩落，要路多險艱。", "不如家池上，樂逸無憂患。", "有食適吾口，有酒酡吾顏。", "恍惚遊醉鄉，希夷造玄關。", "五千言下悟，十二年來閑。", "富者我不顧，貴者我不攀。", "唯有天壇子，時來一往還。"]'),
('ef64b452-6a83-4cb4-8362-656f1a5e8c5e','李盧二中丞各創山居俱誇勝絕然去城稍遠來往頗勞弊居新泉實在宇下偶題十五韻聊戲二君','白居易','唐','唐诗','tang','','[]','龍門蒼石壁，浥澗碧潭水。',180,'全唐诗/poet.tang.24000.json','["龍門蒼石壁，浥澗碧潭水。", "各在一山隅，迢遙幾十里。", "清鏡碧屏風，惜哉信爲美。", "愛而不得見，亦與無相似。", "聞君每來去，矻矻事行李。", "脂轄復裹糧，心力頗勞止。", "未如吾舍下，石與泉甚邇。", "鑿鑿復濺濺，晝夜流不已。", "洛石千萬拳，襯波鋪錦綺。", "海珉一兩片，激瀨含宮徵。", "綠宜春濯足，淨可朝漱齒。", "遶砌紫鱗遊，拂簾白鳥起。", "何言履道叟，便是滄浪子。", "君若趁歸程，請君先到此。", "願以潺湲聲，洗君塵土耳。"]'),
('0851be33-fa47-4177-ab32-960f99438fb7','北窗竹石','白居易','唐','唐诗','tang','','[]','一片瑟瑟石，數竿青青竹。',72,'全唐诗/poet.tang.24000.json','["一片瑟瑟石，數竿青青竹。", "向我如有情，依然看不足。", "況臨北窗下，復近西塘曲。", "筠風散餘清，苔雨含微綠。", "有妻亦衰老，無子方煢獨。", "莫掩夜窗扉，共渠相伴宿。"]'),
('33789ba7-a44a-4989-9da1-f1379968bb8a','飲後戲示弟子','白居易','唐','唐诗','tang','','[]','吾爲爾先生，爾爲吾弟子。',132,'全唐诗/poet.tang.24000.json','["吾爲爾先生，爾爲吾弟子。", "孔門有遺訓，復坐吾告爾。", "先生饌酒食，弟子服勞止。", "孝敬不在他，在茲而已矣。", "欲我少憂愁，欲我多歡喜。", "無如醞好酒，酒須多且旨。", "旨即賓可留，多即罍不恥。", "吾更有一言，爾宜聽入耳。", "人老多憂貧，人病多憂死。", "我今雖老病，所憂不在此。", "憂在半酣時，尊空座客起。"]'),
('79595710-c31b-4b1d-bb36-7977c563bf5b','閑坐看書貽諸少年','白居易','唐','唐诗','tang','','[]','雨砌長寒蕪，風庭落秋果。',96,'全唐诗/poet.tang.24000.json','["雨砌長寒蕪，風庭落秋果。", "窗間有閑叟，盡日看書坐。", "書中見往事，歷歷知福禍。", "多取終厚亡，疾驅必先墮。", "勸君少干名，名爲錮身鏁。", "勸君少求利，利是焚身火。", "我心知已久，吾道無不可。", "所以雀羅門，不能寂寞我。"]'),
('650c3277-30c8-4f12-807e-df47dfdc441e','夢上山','白居易','唐','唐诗','tang','','[]','夜夢上嵩山，獨攜藜杖出。',96,'全唐诗/poet.tang.24000.json','["夜夢上嵩山，獨攜藜杖出。", "千巖與萬壑，遊覽皆周畢。", "夢中足不病，健似少年日。", "既悟神返初，依然舊形質。", "始知形神內，形病神無疾。", "形神兩是幻，夢寐俱非實。", "晝行雖蹇澀，夜步頗安逸。", "晝夜既平分，其間何得失。"]'),
('29a75999-e769-4fa2-8406-1245036bee8c','對酒閑吟贈同老者','白居易','唐','唐诗','tang','','[]','人生七十稀，我年幸過之。',168,'全唐诗/poet.tang.24000.json','["人生七十稀，我年幸過之。", "遠行將盡路，春夢欲覺時。", "家事口不問，世名心不思。", "老既不足歎，病亦不能治。", "扶持仰婢僕，將養信妻兒。", "飢飽進退食，寒暄加減衣。", "聲妓放鄭衛，裘馬脫輕肥。", "百事盡除去，尚餘酒與詩。", "興來吟一篇，吟罷酒一巵。", "不獨適情性，兼用扶衰羸。", "雲液灑六腑，陽和生四肢。", "於中我自樂，此外吾不知。", "寄問同老者，捨此將安歸。", "莫學蓬心叟，胷中殘是非。"]'),
('ea109bd2-c2ee-41ce-aa8b-4031768a1f89','晚起閑行','白居易','唐','唐诗','tang','','[]','皤然一老子，擁裘仍隱几。',72,'全唐诗/poet.tang.24000.json','["皤然一老子，擁裘仍隱几。", "坐穩夜忘眠，臥安朝不起。", "起來無可作，閉目時叩齒。", "靜對銅爐香，暖漱銀瓶水。", "午齋何儉潔，餅與蔬而已。", "西寺講楞伽，閑行一隨喜。"]'),
('cd41c21f-37df-49ab-94cc-977f21bccc34','香山居士寫真詩','白居易','唐','唐诗','tang','','[]','昔作少學士，圖形入集賢。',72,'全唐诗/poet.tang.24000.json','["昔作少學士，圖形入集賢。", "今爲老居士，寫貌寄香山。", "鶴毳變玄髮，雞膚換朱顏。", "前形與後貌，相去三十年。", "勿歎韶華子，俄成皤叟仙。", "請看東海水，亦變作桑田。"]'),
('cd5b5dee-6348-46b1-bd96-e3241e4b958f','二年三月五日齋畢開素當食偶吟贈妻弘農郡君','白居易','唐','唐诗','tang','','[]','睡足肢體暢，晨起開中堂。',228,'全唐诗/poet.tang.24000.json','["睡足肢體暢，晨起開中堂。", "初旭泛簾幕，微風拂衣裳。", "二婢扶盥櫛，雙童舁簟牀。", "庭東有茂樹，其下多陰涼。", "前月事齋戒，昨日散道塲。", "以我久蔬素，加籩仍異糧。", "魴鱗白如雪，蒸炙加桂薑。", "稻飯紅似花，調沃新酪漿。", "佐以脯醢味，間之椒薤芳。", "老憐口尚美，病喜鼻聞香。", "嬌騃三四孫，索哺遶我傍。", "山妻未舉案，饞叟已先嘗。", "憶同牢巹初，家貧共糟糠。", "今食且如此，何必烹猪羊。", "況觀姻族間，夫妻半存亡。", "偕老不易得，白頭何足傷。", "食罷酒一杯，醉飽吟又狂。", "緬想梁高士，樂道喜文章。", "徒誇五噫作，不解贈孟光。"]'),
('1fc043b1-d392-44da-89db-0d0508963b98','不出門','白居易','唐','唐诗','tang','','[]','彌月不出門，永日無來賓。',96,'全唐诗/poet.tang.24000.json','["彌月不出門，永日無來賓。", "食飽更拂牀，睡覺一嚬伸。", "輕箑白鳥羽，新簟青箭筠。", "方寸方丈室，空然兩無塵。", "披衣腰不帶，散髮頭不巾。", "袒跣北窗下，葛天之遺民。", "一日亦自足，況得以終身。", "不知天壤內，目我爲何人。"]'),
('42055eb8-47f9-4e96-b7a2-3a8d589ab55e','感舊','白居易','唐','唐诗','tang','','[]','晦叔墳荒草已陳，夢得墓濕土猶新。',128,'全唐诗/poet.tang.24000.json','["晦叔墳荒草已陳，夢得墓濕土猶新。", "微之捐館將一紀，杓直歸丘二十春。", "城中雖有故第宅，庭蕪園廢生荆榛。", "篋中亦有舊書札，紙穿字蠹成灰塵。", "平生定交取人窄，屈指相知唯五人。", "四人先去我在後，一枝蒲柳衰殘身。", "豈無晚歲新相識，相識面親心不親。", "人生莫羨苦長命，命長感舊多悲辛。"]');
